import React from 'react';
import { Product, ProductType } from '../types';
import { ShoppingCart, Zap, Key, UserCheck } from 'lucide-react';
import { Link } from 'react-router-dom';

interface ProductCardProps {
  product: Product;
}

const ProductCard: React.FC<ProductCardProps> = ({ product }) => {
  const getIcon = () => {
    switch (product.type) {
      case ProductType.ID_LOAD: return <Zap className="w-4 h-4 text-yellow-400" />;
      case ProductType.LICENSE_KEY: return <Key className="w-4 h-4 text-blue-400" />;
      case ProductType.ACCOUNT: return <UserCheck className="w-4 h-4 text-green-400" />;
      default: return <ShoppingCart className="w-4 h-4" />;
    }
  };

  const hasStock = product.type === ProductType.ID_LOAD || product.stock.some(s => !s.isSold);

  return (
    <div className="bg-gaming-card rounded-xl overflow-hidden border border-gray-800 shadow-lg hover:shadow-gaming-neon/20 hover:border-gaming-neon/50 transition-all duration-300 group">
      <div className="relative h-48 overflow-hidden">
        <img 
          src={product.image} 
          alt={product.title} 
          className="w-full h-full object-cover transform group-hover:scale-110 transition-transform duration-500"
        />
        <div className="absolute top-2 right-2 bg-black/60 backdrop-blur-sm px-2 py-1 rounded text-xs font-bold text-white border border-white/10 flex items-center gap-1">
          {getIcon()}
          {product.type === ProductType.ID_LOAD ? 'ID LOAD' : product.type === ProductType.LICENSE_KEY ? 'KEY' : 'ACCOUNT'}
        </div>
        {!hasStock && (
           <div className="absolute inset-0 bg-black/80 flex items-center justify-center">
             <span className="text-red-500 font-bold border-2 border-red-500 px-4 py-1 -rotate-12">OUT OF STOCK</span>
           </div>
        )}
      </div>

      <div className="p-5">
        <div className="text-xs text-gaming-neon mb-1 font-semibold uppercase tracking-wider">{product.category}</div>
        <h3 className="text-lg font-bold text-white mb-2 line-clamp-1">{product.title}</h3>
        <p className="text-gray-400 text-sm mb-4 line-clamp-2 min-h-[40px]">{product.description}</p>

        <div className="flex items-center justify-between mt-auto">
          <span className="text-xl font-bold text-white">{product.price.toFixed(2)} ₼</span>
          <Link 
            to={`/product/${product.id}`}
            className={`px-4 py-2 rounded-lg text-sm font-semibold transition-colors flex items-center gap-2
              ${hasStock 
                ? 'bg-gaming-accent hover:bg-gaming-accent/80 text-white' 
                : 'bg-gray-700 text-gray-500 cursor-not-allowed pointer-events-none'}`}
          >
            {hasStock ? 'Buy Now' : 'Sold Out'}
          </Link>
        </div>
      </div>
    </div>
  );
};

export default ProductCard;

import React, { useState } from 'react';
