              type="text" 
              placeholder="Search for PUBG, Steam, Netflix..."
              value={search}
              onChange={(e) => setSearch(e.target.value)}
              className="w-full bg-slate-900/50 border border-gray-700 text-white pl-12 pr-4 py-3 rounded-full focus:outline-none focus:ring-2 focus:ring-gaming-neon transition-all shadow-lg backdrop-blur-sm"
