                {product.requiresInput && (
                  <div className="mb-8">
                    <label className="block text-sm font-medium text-gray-300 mb-2">
                      {product.inputLabel || "Account ID / Link"} <span className="text-red-500">*</span>
                    </label>
                    <input
                      type="text"
                      value={userInput}
                      onChange={(e) => setUserInput(e.target.value)}
                      className="w-full bg-slate-900 border border-gray-700 rounded-lg p-3 text-white focus:ring-2 focus:ring-gaming-neon outline-none transition-all"
                      placeholder="Enter required info here..."
                    />
                  </div>
                )}

                <button
                  onClick={() => {
                    if (product.requiresInput && !userInput) {
                      alert("Please fill in the required field");
                      return;
                    }
                    setStep(2);
                  }}
                  className="w-full bg-gaming-neon hover:bg-cyan-600 text-black font-bold py-4 rounded-lg transition-colors"
                >
                  Proceed to Payment
                </button>
              </div>
            )}

            {/* STEP 2: Payment & Receipt */}
            {step === 2 && (
              <div className="animate-fade-in">
                <h2 className="text-xl font-bold text-white mb-6">Select Payment Method</h2>

                <div className="grid grid-cols-1 sm:grid-cols-2 gap-4 mb-8">
                  {paymentMethods.filter(pm => pm.isActive).map(pm => (
                    <button
                      key={pm.id}
                      onClick={() => setSelectedMethod(pm.id)}
                      className={`p-4 rounded-xl border flex flex-col items-start gap-2 transition-all
                        ${selectedMethod === pm.id 
                          ? 'border-gaming-neon bg-gaming-neon/10' 
                          : 'border-gray-700 bg-slate-900 hover:border-gray-500'}`}
                    >
                      <div className="flex items-center gap-2 w-full">
                        <CreditCard className="w-5 h-5 text-gray-400" />
                        <span className="font-bold text-white">{pm.name}</span>
                      </div>
                    </button>
                  ))}
                </div>

                {selectedMethod && (
                  <div className="bg-slate-900/80 p-6 rounded-xl border border-dashed border-gray-600 mb-8">
                    <div className="mb-4">
                      <p className="text-gray-400 text-sm mb-1">Send <span className="text-white font-bold">{product.price.toFixed(2)} ₼</span> to:</p>
                      <p className="text-xl font-mono text-gaming-neon tracking-wider">{getSelectedPaymentDetails()?.details}</p>
                      <p className="text-xs text-gray-500 mt-2">{getSelectedPaymentDetails()?.instructions}</p>
                    </div>

                    <div className="mt-6">
                      <label className="block text-sm font-medium text-gray-300 mb-2">Upload Payment Receipt</label>
                      <div className="relative border-2 border-dashed border-gray-600 rounded-lg p-6 hover:bg-slate-800/50 transition-colors text-center group">
                        <input
                          type="file"
                          accept="image/*"
                          onChange={handleFileChange}
                          className="absolute inset-0 w-full h-full opacity-0 cursor-pointer"
                        />
                        <div className="flex flex-col items-center">
                          <Upload className="w-8 h-8 text-gray-400 mb-2 group-hover:text-gaming-neon transition-colors" />
                          <p className="text-sm text-gray-300">
                            {receiptFile ? <span className="text-green-400 font-bold">{receiptFile.name}</span> : "Click to upload screenshot"}
                          </p>
                        </div>
                      </div>
                    </div>
                  </div>
                )}

                <div className="flex gap-4">
                  <button onClick={() => setStep(1)} className="px-6 py-3 rounded-lg border border-gray-600 hover:bg-gray-800 text-gray-300">Back</button>
                  <button 
                    onClick={handleSubmit}
                    disabled={!selectedMethod || !receiptFile || isSubmitting}
                    className={`flex-1 py-3 rounded-lg font-bold flex items-center justify-center gap-2
                      ${(!selectedMethod || !receiptFile || isSubmitting) 
                        ? 'bg-gray-700 text-gray-500 cursor-not-allowed' 
                        : 'bg-green-600 hover:bg-green-700 text-white'}`}
                  >
                    {isSubmitting ? 'Verifying...' : 'Confirm Payment'}
                  </button>
                </div>
              </div>
            )}

            {/* STEP 3: Success */}
            {step === 3 && (
              <div className="text-center py-10 animate-fade-in">
                <div className="w-20 h-20 bg-green-500/20 rounded-full flex items-center justify-center mx-auto mb-6">
                  <CheckCircle className="w-10 h-10 text-green-500" />
                </div>
                <h2 className="text-3xl font-bold text-white mb-4">Order Placed!</h2>
                <p className="text-gray-400 mb-8 max-w-md mx-auto">
                  Your order has been submitted for manual verification. 
                  Once our admin approves your receipt, you will receive your product instantly in your profile.
                </p>
                <button
                  onClick={() => navigate('/profile')}
                  className="bg-gaming-accent hover:bg-purple-700 text-white font-bold py-3 px-8 rounded-full transition-all"
                >
                  View My Order
                </button>
              </div>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

export default ProductView;

import React from 'react';
import { useApp } from '../store';
import { Order, OrderStatus } from '../types';
import { Clock, CheckCircle, XCircle, Copy } from 'lucide-react';

const Profile = () => {
  const { user, orders } = useApp();

  const myOrders = orders.filter(o => o.userId === user.id);

  const getStatusColor = (status: OrderStatus) => {
    switch (status) {
      case OrderStatus.PENDING: return 'text-yellow-400 bg-yellow-400/10';
      case OrderStatus.PROCESSING: return 'text-blue-400 bg-blue-400/10';
      case OrderStatus.COMPLETED: return 'text-green-400 bg-green-400/10';
      case OrderStatus.CANCELLED: return 'text-red-400 bg-red-400/10';
    }
  };

  const copyToClipboard = (text: string) => {
    navigator.clipboard.writeText(text);
    alert("Copied!");
  };

  return (
    <div className="max-w-7xl mx-auto px-4 py-8">
      <div className="flex items-center gap-6 mb-10 bg-gaming-card p-6 rounded-2xl border border-gray-800">
        <img src={user.avatar} alt={user.name} className="w-20 h-20 rounded-full border-2 border-gaming-neon" />
        <div>
          <h1 className="text-2xl font-bold text-white">{user.name}</h1>
          <p className="text-gray-400">{user.email}</p>
          <div className="mt-2 inline-flex px-3 py-1 rounded bg-slate-800 text-xs text-gray-400 border border-gray-700">
            Member since 2024
          </div>
        </div>
      </div>

      <h2 className="text-xl font-bold text-white mb-6 pl-2 border-l-4 border-gaming-neon">Order History</h2>

      <div className="space-y-4">
        {myOrders.length === 0 ? (
          <p className="text-gray-500">No orders yet.</p>
        ) : (
          myOrders.map(order => (
            <div key={order.id} className="bg-gaming-card rounded-xl p-6 border border-gray-800 hover:border-gray-700 transition-all">
              <div className="flex flex-col md:flex-row justify-between md:items-center gap-4">

                <div className="flex-1">
                  <div className="flex items-center gap-3 mb-1">
                    <h3 className="text-lg font-bold text-white">{order.productTitle}</h3>
                    <span className={`px-2 py-0.5 rounded text-xs font-bold ${getStatusColor(order.status)}`}>
                      {order.status}
                    </span>
                  </div>
                  <div className="text-sm text-gray-400">
                    ID: {order.id} • {new Date(order.date).toLocaleDateString()}
