import React, { useState } from 'react';
import { useApp } from '../store';
import { Order, OrderStatus, ProductType } from '../types';
import { Check, X, Eye, Package, CreditCard, ShoppingBag, Search } from 'lucide-react';

const Admin = () => {
  const { user, orders, updateOrderStatus, products, addProductStock, paymentMethods, updatePaymentMethod } = useApp();
  const [activeTab, setActiveTab] = useState<'orders' | 'inventory' | 'finance'>('orders');
  const [viewReceipt, setViewReceipt] = useState<string | null>(null);

  if (user.role !== 'admin') {
    return <div className="p-10 text-center text-red-500">Access Denied</div>;
  }

  // ORDERS LOGIC
  const pendingOrders = orders.filter(o => o.status === OrderStatus.PENDING || o.status === OrderStatus.PROCESSING);
  const completedOrders = orders.filter(o => o.status === OrderStatus.COMPLETED || o.status === OrderStatus.CANCELLED);

  const handleApprove = (order: Order) => {
    // If it's a manual ID load, we might move to PROCESSING first, but for demo let's assume admin did it instantly
    updateOrderStatus(order.id, OrderStatus.COMPLETED);
    alert(`Order ${order.id} Approved! Item delivered.`);
  };

  const handleReject = (orderId: string) => {
    updateOrderStatus(orderId, OrderStatus.CANCELLED);
  };

  // INVENTORY LOGIC
  const [stockInput, setStockInput] = useState<{pid: string, content: string}>({pid: '', content: ''});
  const handleAddStock = () => {
    if(!stockInput.pid || !stockInput.content) return;
    // Simple parsing by new line
    const items = stockInput.content.split('\n').filter(s => s.trim().length > 0);
    addProductStock(stockInput.pid, items);
    setStockInput({pid: '', content: ''});
    alert(`Added ${items.length} items to stock.`);
  }

  return (
    <div className="min-h-screen bg-slate-900 text-white flex">
      {/* Sidebar */}
      <div className="w-64 bg-slate-950 border-r border-gray-800 hidden md:flex flex-col p-4">
        <h2 className="text-2xl font-bold text-gaming-neon mb-8 px-2">Admin Panel</h2>
        <nav className="space-y-2">
          <button 
            onClick={() => setActiveTab('orders')}
            className={`w-full text-left px-4 py-3 rounded-lg flex items-center gap-3 ${activeTab === 'orders' ? 'bg-gaming-accent text-white' : 'text-gray-400 hover:bg-slate-900'}`}
          >
            <ShoppingBag className="w-5 h-5" /> Orders
            {pendingOrders.length > 0 && <span className="ml-auto bg-red-500 text-white text-xs px-2 py-0.5 rounded-full">{pendingOrders.length}</span>}
          </button>
          <button 
             onClick={() => setActiveTab('inventory')}
             className={`w-full text-left px-4 py-3 rounded-lg flex items-center gap-3 ${activeTab === 'inventory' ? 'bg-gaming-accent text-white' : 'text-gray-400 hover:bg-slate-900'}`}
          >
            <Package className="w-5 h-5" /> Inventory
          </button>
          <button 
             onClick={() => setActiveTab('finance')}
             className={`w-full text-left px-4 py-3 rounded-lg flex items-center gap-3 ${activeTab === 'finance' ? 'bg-gaming-accent text-white' : 'text-gray-400 hover:bg-slate-900'}`}
          >
            <CreditCard className="w-5 h-5" /> Payments
          </button>
        </nav>
      </div>

      {/* Content */}
      <div className="flex-1 p-6 md:p-10 overflow-y-auto">

        {/* Mobile Tab Switcher */}
        <div className="md:hidden flex gap-2 mb-6 overflow-x-auto">
           {['orders', 'inventory', 'finance'].map((t) => (
             <button key={t} onClick={() => setActiveTab(t as any)} className={`px-4 py-2 rounded capitalize ${activeTab === t ? 'bg-gaming-accent' : 'bg-slate-800'}`}>{t}</button>
           ))}
        </div>

        {activeTab === 'orders' && (
          <div className="space-y-8 animate-fade-in">
            <div>
              <h3 className="text-xl font-bold mb-4 flex items-center gap-2">
                <span className="w-3 h-3 bg-yellow-400 rounded-full animate-pulse"></span>
                Pending Requests
              </h3>
              <div className="grid gap-4">
                {pendingOrders.length === 0 && <p className="text-gray-500 italic">No pending orders. Good job!</p>}
                {pendingOrders.map(order => (
                  <div key={order.id} className="bg-slate-800 rounded-xl p-4 border border-gray-700 shadow-lg flex flex-col lg:flex-row gap-4">
                     {/* Receipt Preview */}
                     <div className="w-full lg:w-48 h-32 bg-black rounded-lg overflow-hidden relative group cursor-pointer" onClick={() => setViewReceipt(order.receiptImage || '')}>
                        <img src={order.receiptImage} className="w-full h-full object-cover opacity-70 group-hover:opacity-100 transition-opacity" alt="Receipt" />
                        <div className="absolute inset-0 flex items-center justify-center opacity-0 group-hover:opacity-100 bg-black/40">
                          <Eye className="text-white" />
                        </div>
                     </div>

                     <div className="flex-1">
                        <div className="flex justify-between items-start">
                          <div>
                            <h4 className="font-bold text-lg text-white">{order.productTitle}</h4>
                            <p className="text-sm text-gray-400">User: {order.userId} | Method: {order.paymentMethodName}</p>
                            {order.userInput && <p className="text-yellow-400 font-mono text-sm mt-1 bg-yellow-400/10 inline-block px-2 rounded">Target ID: {order.userInput}</p>}
                          </div>
                          <div className="text-right">
                            <div className="text-2xl font-bold text-green-400">{order.price.toFixed(2)} ₼</div>
                            <div className="text-xs text-gray-500">{new Date(order.date).toLocaleTimeString()}</div>
                          </div>
                        </div>

                        <div className="mt-4 flex gap-3">
                          <button onClick={() => handleApprove(order)} className="flex-1 bg-green-600 hover:bg-green-700 text-white py-2 rounded-lg font-medium flex items-center justify-center gap-2">
                            <Check className="w-4 h-4" /> Approve & Deliver
                          </button>
                          <button onClick={() => handleReject(order.id)} className="px-4 bg-red-600 hover:bg-red-700 text-white rounded-lg flex items-center">
                            <X className="w-4 h-4" />
                          </button>
                        </div>
                     </div>
                  </div>
                ))}
              </div>
            </div>

            <div className="pt-8 border-t border-gray-800">
               <h3 className="text-lg font-semibold text-gray-400 mb-4">Past Transactions</h3>
               <div className="overflow-x-auto">
                 <table className="w-full text-sm text-left text-gray-400">
                   <thead className="bg-slate-800 text-gray-200 uppercase">
                     <tr>
                       <th className="px-4 py-3">ID</th>
                       <th className="px-4 py-3">Product</th>
                       <th className="px-4 py-3">Status</th>
                       <th className="px-4 py-3">Amount</th>
                     </tr>
                   </thead>
                   <tbody>
                     {completedOrders.slice(0, 10).map(order => (
                       <tr key={order.id} className="border-b border-gray-800 hover:bg-slate-800/50">
                         <td className="px-4 py-3 font-mono">{order.id.slice(-6)}</td>
                         <td className="px-4 py-3">{order.productTitle}</td>
                         <td className="px-4 py-3">
                           <span className={`px-2 py-1 rounded text-xs ${order.status === OrderStatus.COMPLETED ? 'bg-green-900 text-green-300' : 'bg-red-900 text-red-300'}`}>
                             {order.status}
                           </span>
                         </td>
                         <td className="px-4 py-3">{order.price.toFixed(2)} ₼</td>
                       </tr>
                     ))}
                   </tbody>
                 </table>
               </div>
            </div>
          </div>
        )}

        {activeTab === 'inventory' && (
          <div className="animate-fade-in">
             <div className="bg-slate-800 p-6 rounded-xl border border-gray-700 mb-8">
                <h3 className="text-lg font-bold mb-4">Add Stock (Bulk)</h3>
                <div className="grid gap-4">
                  <select 
                    className="w-full bg-slate-900 border border-gray-600 rounded p-2 text-white"
                    value={stockInput.pid}
                    onChange={(e) => setStockInput({...stockInput, pid: e.target.value})}
                  >
                    <option value="">Select Product...</option>
                    {products.filter(p => p.type !== ProductType.ID_LOAD).map(p => (
                      <option key={p.id} value={p.id}>{p.title} ({p.stock.filter(s => !s.isSold).length} left)</option>
                    ))}
                  </select>
                  <textarea 
                    className="w-full bg-slate-900 border border-gray-600 rounded p-2 text-white h-32 font-mono text-sm"
                    placeholder="Paste codes here (one per line)...&#10;CODE-1234&#10;CODE-5678"
                    value={stockInput.content}
                    onChange={(e) => setStockInput({...stockInput, content: e.target.value})}
                  />
                  <button onClick={handleAddStock} className="bg-gaming-accent hover:bg-purple-600 text-white py-2 rounded font-bold">
                    Upload Codes
                  </button>
                </div>
             </div>

             <div className="grid gap-4">
               {products.filter(p => p.type !== ProductType.ID_LOAD).map(p => (
                 <div key={p.id} className="bg-slate-800 p-4 rounded-lg flex justify-between items-center">
                   <div>
                     <h4 className="font-bold">{p.title}</h4>
                     <p className="text-sm text-gray-400">Type: {p.type}</p>
                   </div>
                   <div className="text-right">
                     <span className={`text-2xl font-bold ${p.stock.filter(s => !s.isSold).length < 2 ? 'text-red-500' : 'text-green-500'}`}>
                       {p.stock.filter(s => !s.isSold).length}
                     </span>
                     <p className="text-xs text-gray-500">Available</p>
                   </div>
                 </div>
               ))}
             </div>
          </div>
        )}

        {activeTab === 'finance' && (
          <div className="animate-fade-in">
             <h3 className="text-xl font-bold mb-6">Payment Gateways (Manual)</h3>
             <div className="grid gap-6">
               {paymentMethods.map(pm => (
                 <div key={pm.id} className="bg-slate-800 p-6 rounded-xl border border-gray-700">
                    <div className="flex justify-between items-start mb-4">
                      <div className="flex items-center gap-3">
                         <div className="bg-slate-700 p-2 rounded">
                            <CreditCard className="w-6 h-6 text-gaming-neon" />
                         </div>
                         <div>
                           <h4 className="font-bold text-lg">{pm.name}</h4>
                           <span className={`text-xs px-2 py-0.5 rounded ${pm.isActive ? 'bg-green-900 text-green-300' : 'bg-red-900 text-red-300'}`}>
                             {pm.isActive ? 'Active' : 'Disabled'}
                           </span>
                         </div>
                      </div>
                      <button 
                        onClick={() => updatePaymentMethod(pm.id, { isActive: !pm.isActive })}
                        className="text-sm text-blue-400 hover:text-white"
                      >
                        {pm.isActive ? 'Disable' : 'Enable'}
                      </button>
                    </div>

                    <div className="space-y-3">
                      <div>
                        <label className="block text-xs text-gray-500 mb-1">Account/Card Details</label>
                        <input 
                          type="text" 
                          value={pm.details} 
                          onChange={(e) => updatePaymentMethod(pm.id, { details: e.target.value })}
                          className="w-full bg-slate-900 border border-gray-600 rounded p-2 text-gaming-neon font-mono"
                        />
                      </div>
                      <div>
                        <label className="block text-xs text-gray-500 mb-1">Instructions</label>
                        <input 
                          type="text" 
                          value={pm.instructions} 
                          onChange={(e) => updatePaymentMethod(pm.id, { instructions: e.target.value })}
                          className="w-full bg-slate-900 border border-gray-600 rounded p-2 text-sm"
                        />
                      </div>
                    </div>
                 </div>
               ))}
             </div>
          </div>
        )}
      </div>

      {/* Image Modal */}
      {viewReceipt && (
        <div className="fixed inset-0 z-50 bg-black/90 flex items-center justify-center p-4" onClick={() => setViewReceipt(null)}>
           <img src={viewReceipt} className="max-w-full max-h-[90vh] rounded shadow-2xl border border-gray-700" alt="Receipt Full" />
           <button className="absolute top-4 right-4 text-white bg-red-600 p-2 rounded-full">
             <X />
           </button>
        </div>
      )}
    </div>
  );
};

export default Admin;

