          {categories.map(cat => (
            <button
              key={cat.id}
              onClick={() => setActiveCat(cat.id)}
              className={`px-6 py-2 rounded-full text-sm font-medium whitespace-nowrap transition-all
                ${activeCat === cat.id 
                  ? 'bg-gaming-neon text-black shadow-[0_0_15px_rgba(6,182,212,0.4)]' 
                  : 'bg-gaming-card text-gray-400 hover:text-white hover:bg-gray-700'}`}
