import React, { useState } from 'react';
import { useApp } from '../store';
import { Order, OrderStatus, ProductType, Product, Category } from '../types';
import { Check, X, Eye, Package, CreditCard, ShoppingBag, Settings, Plus, Trash2, LayoutGrid, BarChart3, Save } from 'lucide-react';

const Admin = () => {
  const { 
    user, orders, updateOrderStatus, products, addProductStock, 
    paymentMethods, updatePaymentMethod, siteSettings, updateSiteSettings,
    categories, addCategory, deleteCategory, addProduct, deleteProduct
  } = useApp();

  const [activeTab, setActiveTab] = useState<'orders' | 'inventory' | 'finance' | 'cms' | 'products'>('orders');
  const [viewReceipt, setViewReceipt] = useState<string | null>(null);

  // States for Forms
  const [newCatName, setNewCatName] = useState('');
  const [stockInput, setStockInput] = useState<{pid: string, content: string}>({pid: '', content: ''});
  const [newProduct, setNewProduct] = useState<Partial<Product>>({
    title: '', categoryId: '', price: 0, type: ProductType.LICENSE_KEY, image: '', description: '', requiresInput: false
  });

  if (user.role !== 'admin') {
    return <div className="p-10 text-center text-red-500 font-bold text-2xl">Access Denied</div>;
  }

  // LOGIC
  const pendingOrders = orders.filter(o => o.status === OrderStatus.PENDING || o.status === OrderStatus.PROCESSING);
  const completedOrders = orders.filter(o => o.status === OrderStatus.COMPLETED);
  const totalRevenue = completedOrders.reduce((sum, o) => sum + o.price, 0);
  const todayRevenue = completedOrders
    .filter(o => new Date(o.date).toDateString() === new Date().toDateString())
    .reduce((sum, o) => sum + o.price, 0);

  const handleApprove = (order: Order) => {
    updateOrderStatus(order.id, OrderStatus.COMPLETED);
    alert(`Order ${order.id} Approved!`);
  };

  const handleReject = (orderId: string) => {
    updateOrderStatus(orderId, OrderStatus.CANCELLED);
  };

  const handleAddStock = () => {
    if(!stockInput.pid || !stockInput.content) return;
    const items = stockInput.content.split('\n').filter(s => s.trim().length > 0);
    addProductStock(stockInput.pid, items);
    setStockInput({pid: '', content: ''});
    alert(`Added ${items.length} items to stock.`);
  }

  const handleCreateProduct = (e: React.FormEvent) => {
    e.preventDefault();
    if(!newProduct.title || !newProduct.price || !newProduct.categoryId) {
      alert("Please fill basic fields");
      return;
    }
    const product: Product = {
      id: `prod-${Date.now()}`,
      title: newProduct.title!,
      categoryId: newProduct.categoryId!,
      type: newProduct.type || ProductType.LICENSE_KEY,
      price: Number(newProduct.price),
      image: newProduct.image || 'https://via.placeholder.com/300',
      description: newProduct.description || '',
      requiresInput: newProduct.requiresInput,
      inputLabel: newProduct.inputLabel,
      stock: []
    };
    addProduct(product);
    setNewProduct({ title: '', categoryId: '', price: 0, type: ProductType.LICENSE_KEY, image: '', description: '', requiresInput: false });
    alert("Product created!");
  };

  return (
    <div className="min-h-screen bg-slate-950 text-white flex flex-col md:flex-row">
      {/* Sidebar */}
      <div className="w-full md:w-64 bg-slate-900 border-r border-gray-800 flex flex-col p-4 shrink-0">
        <h2 className="text-2xl font-black text-gaming-neon mb-8 px-2 tracking-tighter">ADMIN PANEL</h2>
        <nav className="space-y-2 overflow-x-auto md:overflow-visible flex md:block gap-2">
          {[
             {id: 'orders', icon: ShoppingBag, label: 'Sifarişlər', count: pendingOrders.length},
             {id: 'inventory', icon: Package, label: 'Stok (Bulk)'},
             {id: 'products', icon: Plus, label: 'Məhsullar'},
             {id: 'cms', icon: LayoutGrid, label: 'Sayt / CMS'},
             {id: 'finance', icon: CreditCard, label: 'Ödənişlər'},
          ].map(item => (
            <button 
              key={item.id}
              onClick={() => setActiveTab(item.id as any)}
              className={`w-full text-left px-4 py-3 rounded-lg flex items-center gap-3 transition-colors shrink-0 md:shrink 
                ${activeTab === item.id ? 'bg-gaming-accent text-white shadow-lg' : 'text-gray-400 hover:bg-slate-800'}`}
            >
              <item.icon className="w-5 h-5" /> 
              <span className="hidden md:inline">{item.label}</span>
              <span className="md:hidden inline">{item.label.slice(0,3)}</span>
              {item.count ? <span className="ml-auto bg-red-500 text-white text-xs px-2 py-0.5 rounded-full">{item.count}</span> : null}
            </button>
          ))}
        </nav>

        {/* Mini Stats in Sidebar */}
        <div className="mt-auto hidden md:block pt-6 border-t border-gray-800">
          <div className="bg-slate-800 p-4 rounded-xl mb-2">
            <p className="text-xs text-gray-400">Total Income</p>
            <p className="text-xl font-bold text-green-400">{totalRevenue.toFixed(2)} ₼</p>
          </div>
          <div className="bg-slate-800 p-4 rounded-xl">
             <p className="text-xs text-gray-400">Today's Income</p>
             <p className="text-xl font-bold text-yellow-400">{todayRevenue.toFixed(2)} ₼</p>
          </div>
        </div>
      </div>

      {/* Content */}
      <div className="flex-1 p-6 md:p-10 overflow-y-auto">

        {/* ORDERS TAB */}
        {activeTab === 'orders' && (
          <div className="space-y-8 animate-fade-in">
            <div>
              <h3 className="text-xl font-bold mb-4 flex items-center gap-2">
                <span className="w-3 h-3 bg-yellow-400 rounded-full animate-pulse"></span>
                Gözləyən Sifarişlər
              </h3>
              <div className="grid gap-4">
                {pendingOrders.length === 0 && <p className="text-gray-500 italic p-4 bg-slate-900 rounded">Hələlik yeni sifariş yoxdur.</p>}
                {pendingOrders.map(order => (
                  <div key={order.id} className="bg-slate-800 rounded-xl p-4 border border-gray-700 shadow-lg flex flex-col lg:flex-row gap-4">
                     {/* Receipt Preview */}
                     <div className="w-full lg:w-48 h-32 bg-black rounded-lg overflow-hidden relative group cursor-pointer border border-gray-600" onClick={() => setViewReceipt(order.receiptImage || '')}>
                        <img src={order.receiptImage} className="w-full h-full object-cover opacity-70 group-hover:opacity-100 transition-opacity" alt="Receipt" />
                        <div className="absolute inset-0 flex items-center justify-center opacity-0 group-hover:opacity-100 bg-black/40">
                          <Eye className="text-white" />
                        </div>
                     </div>

                     <div className="flex-1">
                        <div className="flex justify-between items-start">
                          <div>
                            <h4 className="font-bold text-lg text-white">{order.productTitle}</h4>
                            <p className="text-sm text-gray-400">User: {order.userId} | Method: {order.paymentMethodName}</p>
                            {order.userInput && <p className="text-yellow-400 font-mono text-sm mt-1 bg-yellow-400/10 inline-block px-2 rounded">Target: {order.userInput}</p>}
                          </div>
                          <div className="text-right">
                            <div className="text-2xl font-bold text-green-400">{order.price.toFixed(2)} ₼</div>
                            <div className="text-xs text-gray-500">{new Date(order.date).toLocaleTimeString()}</div>
                          </div>
                        </div>

                        <div className="mt-4 flex gap-3">
                          <button onClick={() => handleApprove(order)} className="flex-1 bg-green-600 hover:bg-green-700 text-white py-2 rounded-lg font-medium flex items-center justify-center gap-2 shadow-lg shadow-green-900/20">
                            <Check className="w-4 h-4" /> Təsdiqlə (Ver)
                          </button>
                          <button onClick={() => handleReject(order.id)} className="px-4 bg-red-600 hover:bg-red-700 text-white rounded-lg flex items-center shadow-lg shadow-red-900/20">
                            <X className="w-4 h-4" />
                          </button>
                        </div>
                     </div>
                  </div>
                ))}
              </div>
            </div>
          </div>
        )}

        {/* PRODUCTS TAB */}
        {activeTab === 'products' && (
          <div className="animate-fade-in grid grid-cols-1 lg:grid-cols-2 gap-8">
            <div className="bg-slate-800 p-6 rounded-xl border border-gray-700">
               <h3 className="text-xl font-bold mb-6 flex items-center gap-2"><Plus className="text-gaming-neon" /> Yeni Məhsul Yarat</h3>
               <form onSubmit={handleCreateProduct} className="space-y-4">
                  <div>
                    <label className="text-xs text-gray-400">Ad</label>
                    <input type="text" className="w-full bg-slate-900 p-2 rounded border border-gray-600" value={newProduct.title} onChange={e => setNewProduct({...newProduct, title: e.target.value})} placeholder="Məs: PUBG 60 UC" />
                  </div>
                  <div className="grid grid-cols-2 gap-4">
                     <div>
                        <label className="text-xs text-gray-400">Qiymət (AZN)</label>
                        <input type="number" step="0.01" className="w-full bg-slate-900 p-2 rounded border border-gray-600" value={newProduct.price} onChange={e => setNewProduct({...newProduct, price: parseFloat(e.target.value)})} />
                     </div>
                     <div>
                        <label className="text-xs text-gray-400">Kateqoriya</label>
                        <select className="w-full bg-slate-900 p-2 rounded border border-gray-600" value={newProduct.categoryId} onChange={e => setNewProduct({...newProduct, categoryId: e.target.value})}>
                           <option value="">Seçin...</option>
                           {categories.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
                        </select>
                     </div>
                  </div>
                  <div className="grid grid-cols-2 gap-4">
                     <div>
                        <label className="text-xs text-gray-400">Tip</label>
                        <select className="w-full bg-slate-900 p-2 rounded border border-gray-600" value={newProduct.type} onChange={e => setNewProduct({...newProduct, type: e.target.value as ProductType})}>
                           <option value={ProductType.LICENSE_KEY}>License Key (Auto)</option>
                           <option value={ProductType.ID_LOAD}>ID Yükləmə (Manual)</option>
                           <option value={ProductType.ACCOUNT}>Hesab (Email:Pass)</option>
                        </select>
                     </div>
                     <div>
                        <label className="text-xs text-gray-400">Şəkil URL</label>
                        <input type="text" className="w-full bg-slate-900 p-2 rounded border border-gray-600" value={newProduct.image} onChange={e => setNewProduct({...newProduct, image: e.target.value})} placeholder="https://..." />
                     </div>
                  </div>
                  {newProduct.type === ProductType.ID_LOAD && (
                    <div>
                       <label className="flex items-center gap-2 text-sm text-yellow-400">
                          <input type="checkbox" checked={newProduct.requiresInput} onChange={e => setNewProduct({...newProduct, requiresInput: e.target.checked})} />
                          İstifadəçidən ID tələb et?
                       </label>
                       {newProduct.requiresInput && (
                         <input type="text" className="w-full mt-2 bg-slate-900 p-2 rounded border border-gray-600" value={newProduct.inputLabel} onChange={e => setNewProduct({...newProduct, inputLabel: e.target.value})} placeholder="Label: Məs. Oyunçu ID" />
                       )}
                    </div>
                  )}
                  <div>
                    <label className="text-xs text-gray-400">Təsvir (SEO Description)</label>
                    <textarea className="w-full bg-slate-900 p-2 rounded border border-gray-600 h-24" value={newProduct.description} onChange={e => setNewProduct({...newProduct, description: e.target.value})}></textarea>
                  </div>
                  <button type="submit" className="w-full bg-gaming-neon text-black font-bold py-3 rounded hover:bg-cyan-400">Məhsulu Yarat</button>
               </form>
            </div>

            <div className="space-y-4">
              <h3 className="text-xl font-bold">Mövcud Məhsullar</h3>
              <div className="bg-slate-800 rounded-xl border border-gray-700 overflow-hidden max-h-[600px] overflow-y-auto">
                {products.map(p => (
                  <div key={p.id} className="p-4 border-b border-gray-700 flex justify-between items-center hover:bg-slate-700">
                     <div className="flex items-center gap-3">
                        <img src={p.image} className="w-10 h-10 rounded object-cover" alt="" />
                        <div>
                           <p className="font-bold">{p.title}</p>
                           <p className="text-xs text-gray-400">{p.price} ₼ | Stok: {p.type === ProductType.ID_LOAD ? 'Manual' : p.stock.filter(s=>!s.isSold).length}</p>
                        </div>
                     </div>
                     <button onClick={() => deleteProduct(p.id)} className="text-red-400 hover:text-red-300 p-2"><Trash2 className="w-5 h-5" /></button>
                  </div>
                ))}
              </div>
            </div>
          </div>
        )}

        {/* CMS / SETTINGS TAB */}
        {activeTab === 'cms' && (
           <div className="animate-fade-in grid grid-cols-1 lg:grid-cols-2 gap-8">
              {/* Site Config */}
              <div className="bg-slate-800 p-6 rounded-xl border border-gray-700">
                 <h3 className="text-xl font-bold mb-4 flex items-center gap-2"><Settings /> Sayt Ayarları</h3>
                 <div className="space-y-4">
                    <div>
                       <label className="text-xs text-gray-400">Sayt Adı</label>
                       <input type="text" className="w-full bg-slate-900 p-2 rounded border border-gray-600" value={siteSettings.siteName} onChange={(e) => updateSiteSettings({siteName: e.target.value})} />
                    </div>
                    <div>
                       <label className="text-xs text-gray-400">Logo URL</label>
                       <input type="text" className="w-full bg-slate-900 p-2 rounded border border-gray-600" value={siteSettings.logoUrl} onChange={(e) => updateSiteSettings({logoUrl: e.target.value})} />
                    </div>
                    <div>
                       <label className="text-xs text-gray-400">Hero Banner URL</label>
                       <input type="text" className="w-full bg-slate-900 p-2 rounded border border-gray-600" value={siteSettings.heroBannerUrl} onChange={(e) => updateSiteSettings({heroBannerUrl: e.target.value})} />
                    </div>
                    <div>
                       <label className="text-xs text-gray-400">Hero Başlıq</label>
                       <input type="text" className="w-full bg-slate-900 p-2 rounded border border-gray-600" value={siteSettings.heroTitle} onChange={(e) => updateSiteSettings({heroTitle: e.target.value})} />
                    </div>
                    <div>
                       <label className="text-xs text-gray-400">Footer Mətni</label>
                       <input type="text" className="w-full bg-slate-900 p-2 rounded border border-gray-600" value={siteSettings.footerText} onChange={(e) => updateSiteSettings({footerText: e.target.value})} />
                    </div>
                 </div>
              </div>

              {/* Category Management */}
              <div className="bg-slate-800 p-6 rounded-xl border border-gray-700">
                 <h3 className="text-xl font-bold mb-4 flex items-center gap-2"><LayoutGrid /> Kateqoriyalar</h3>
                 <div className="flex gap-2 mb-4">
                    <input 
                      type="text" 
                      className="flex-1 bg-slate-900 p-2 rounded border border-gray-600" 
                      placeholder="Yeni Kateqoriya adı..." 
                      value={newCatName}
                      onChange={(e) => setNewCatName(e.target.value)}
                    />
                    <button 
                      onClick={() => {
                        if(newCatName) {
                           addCategory({id: `cat-${Date.now()}`, name: newCatName});
                           setNewCatName('');
                        }
                      }}
                      className="bg-green-600 px-4 rounded font-bold"
                    >
                      Əlavə Et
                    </button>
                 </div>
                 <div className="space-y-2">
                    {categories.map(cat => (
                       <div key={cat.id} className="flex justify-between items-center bg-slate-700 p-3 rounded">
                          <span>{cat.name}</span>
                          <button onClick={() => deleteCategory(cat.id)} className="text-red-400 hover:text-white"><Trash2 className="w-4 h-4" /></button>
                       </div>
                    ))}
                 </div>
              </div>
           </div>
        )}

        {/* INVENTORY TAB */}
        {activeTab === 'inventory' && (
          <div className="animate-fade-in">
             <div className="bg-slate-800 p-6 rounded-xl border border-gray-700 mb-8">
                <h3 className="text-lg font-bold mb-4">Stok Artır (Bulk Import)</h3>
                <div className="grid gap-4">
                  <select 
                    className="w-full bg-slate-900 border border-gray-600 rounded p-2 text-white"
                    value={stockInput.pid}
                    onChange={(e) => setStockInput({...stockInput, pid: e.target.value})}
                  >
                    <option value="">Məhsul Seçin...</option>
                    {products.filter(p => p.type !== ProductType.ID_LOAD).map(p => (
                      <option key={p.id} value={p.id}>{p.title} ({p.stock.filter(s => !s.isSold).length} qalıb)</option>
                    ))}
                  </select>
                  <textarea 
                    className="w-full bg-slate-900 border border-gray-600 rounded p-2 text-white h-32 font-mono text-sm"
                    placeholder="Kodları bura yapışdırın (hər sətirdə biri)...&#10;CODE-1234&#10;CODE-5678"
                    value={stockInput.content}
                    onChange={(e) => setStockInput({...stockInput, content: e.target.value})}
                  />
                  <button onClick={handleAddStock} className="bg-gaming-accent hover:bg-purple-600 text-white py-2 rounded font-bold">
                    Stoka Yüklə
                  </button>
                </div>
             </div>
          </div>
        )}

        {/* FINANCE TAB */}
        {activeTab === 'finance' && (
          <div className="animate-fade-in">
             <h3 className="text-xl font-bold mb-6">Ödəniş Metodları (Manual)</h3>
             <p className="text-gray-400 mb-6">Burada dəyişdiyiniz məlumatlar istifadəçi ödəniş səhifəsində dərhal görünəcək.</p>
             <div className="grid gap-6">
               {paymentMethods.map(pm => (
                 <div key={pm.id} className="bg-slate-800 p-6 rounded-xl border border-gray-700">
                    <div className="flex justify-between items-start mb-4">
                      <div className="flex items-center gap-3">
                         <div className="bg-slate-700 p-2 rounded">
                            <CreditCard className="w-6 h-6 text-gaming-neon" />
                         </div>
                         <div>
                           <h4 className="font-bold text-lg">{pm.name}</h4>
                           <span className={`text-xs px-2 py-0.5 rounded ${pm.isActive ? 'bg-green-900 text-green-300' : 'bg-red-900 text-red-300'}`}>
                             {pm.isActive ? 'Aktiv' : 'Deaktiv'}
                           </span>
                         </div>
                      </div>
                      <button 
                        onClick={() => updatePaymentMethod(pm.id, { isActive: !pm.isActive })}
                        className="text-sm text-blue-400 hover:text-white"
                      >
                        {pm.isActive ? 'Deaktiv et' : 'Aktiv et'}
                      </button>
                    </div>

                    <div className="space-y-3">
                      <div>
                        <label className="block text-xs text-gray-500 mb-1">Hesab / Kart Məlumatları</label>
                        <input 
                          type="text" 
                          value={pm.details} 
                          onChange={(e) => updatePaymentMethod(pm.id, { details: e.target.value })}
                          className="w-full bg-slate-900 border border-gray-600 rounded p-2 text-gaming-neon font-mono"
                        />
                      </div>
                      <div>
                        <label className="block text-xs text-gray-500 mb-1">Təlimat (Müştəri nə etməlidir?)</label>
                        <textarea 
                          value={pm.instructions} 
                          onChange={(e) => updatePaymentMethod(pm.id, { instructions: e.target.value })}
                          className="w-full bg-slate-900 border border-gray-600 rounded p-2 text-sm h-20"
                        />
                      </div>
                    </div>
                 </div>
               ))}
             </div>
          </div>
        )}
      </div>

      {/* Image Modal */}
      {viewReceipt && (
        <div className="fixed inset-0 z-50 bg-black/90 flex items-center justify-center p-4 backdrop-blur-sm" onClick={() => setViewReceipt(null)}>
           <img src={viewReceipt} className="max-w-full max-h-[90vh] rounded shadow-2xl border border-gray-700" alt="Receipt Full" />
           <button className="absolute top-4 right-4 text-white bg-red-600 p-3 rounded-full hover:bg-red-700">
             <X />
           </button>
        </div>
      )}
    </div>
  );
};

