import React, { createContext, useContext, useState, ReactNode, useEffect } from 'react';
import { Product, Order, PaymentMethod, User, OrderStatus, ProductType, StockItem, Category, SiteSettings, Blog, Agreement, Comment } from './types';
import { INITIAL_PRODUCTS, INITIAL_PAYMENT_METHODS, CURRENT_USER, INITIAL_CATEGORIES, INITIAL_SETTINGS } from './constants';

interface AppContextType {
  user: User;
  products: Product[];
  categories: Category[];
  orders: Order[];
  paymentMethods: PaymentMethod[];
  siteSettings: SiteSettings;
  blogs: Blog[];
  agreements: Agreement[];
  comments: Comment[];

  // Actions
  placeOrder: (productId: string, paymentMethodId: string, receiptFile: File, userInput?: string) => Promise<boolean>;
  updateOrderStatus: (orderId: string, status: OrderStatus) => void;
  toggleUserRole: () => void;
  addPaymentMethod: (method: PaymentMethod) => void;
  updatePaymentMethod: (id: string, details: Partial<PaymentMethod>) => void;
  addProductStock: (productId: string, items: string[]) => void;
  deleteProductStock: (productId: string, stockId: string) => void;

  // Admin CMS Actions
  addProduct: (product: Product) => void;
  deleteProduct: (productId: string) => void;
  addCategory: (category: Category) => void;
  deleteCategory: (categoryId: string) => void;
  updateSiteSettings: (settings: Partial<SiteSettings>) => void;
  updateUserBalance: (amount: number) => void;

  // New CMS Actions
  addBlog: (blog: Blog) => void;
  deleteBlog: (id: string) => void;
  addAgreement: (agreement: Agreement) => void;
  deleteAgreement: (id: string) => void;
  toggleCommentApproval: (id: string) => void;
  deleteComment: (id: string) => void;
}

const AppContext = createContext<AppContextType | undefined>(undefined);

export const AppProvider = ({ children }: { children?: React.ReactNode }) => {
  const [user, setUser] = useState<User>(CURRENT_USER);
  const [products, setProducts] = useState<Product[]>(INITIAL_PRODUCTS);
  const [categories, setCategories] = useState<Category[]>(INITIAL_CATEGORIES);
  const [orders, setOrders] = useState<Order[]>([]);
  const [paymentMethods, setPaymentMethods] = useState<PaymentMethod[]>(INITIAL_PAYMENT_METHODS);
  const [siteSettings, setSiteSettings] = useState<SiteSettings>(INITIAL_SETTINGS);

  // New CMS State
  const [blogs, setBlogs] = useState<Blog[]>([
    { id: 'b1', title: 'PUBG Yeni Sezon Başladı!', content: 'Yeni sezonun gəlişi ilə birlikdə...', date: new Date().toISOString(), image: 'https://images.unsplash.com/photo-1542751371-adc38448a05e' }
  ]);
  const [agreements, setAgreements] = useState<Agreement[]>([
    { id: 'a1', title: 'İstifadəçi Razılaşması', content: 'Saytımızdan istifadə edərkən...' },
    { id: 'a2', title: 'Məxfilik Siyasəti', content: 'Məlumatlarınız qorunur...' }
  ]);
  const [comments, setComments] = useState<Comment[]>([
    { id: 'c1', author: 'Elvin M.', content: 'Çox sürətli gəldi, təşəkkürlər!', type: 'product', targetId: 'p1', isApproved: true, date: new Date().toISOString() },
    { id: 'c2', author: 'Anonim', content: 'Gözləyirəm hələ...', type: 'site', isApproved: false, date: new Date().toISOString() }
  ]);

  // Load some mock orders on init
  useEffect(() => {
    setOrders([
      {
        id: 'ord-hist-1',
        userId: user.id,
        productId: 'p2',
        productTitle: 'Steam Wallet $20',
        productType: ProductType.LICENSE_KEY,
        price: 35.00,
        status: OrderStatus.COMPLETED,
        date: new Date(Date.now() - 86400000).toISOString(), // Yesterday
        paymentMethodName: 'Birbank',
        deliveredContent: 'STEAM-HIST-ORY1-CODE'
      }
    ]);
  }, []);

  const toggleUserRole = () => {
    setUser(prev => ({ ...prev, role: prev.role === 'admin' ? 'user' : 'admin' }));
  };

  const updateUserBalance = (amount: number) => {
    setUser(prev => ({ ...prev, balance: prev.balance + amount }));
  };

  const placeOrder = async (productId: string, paymentMethodId: string, receiptFile: File, userInput?: string): Promise<boolean> => {
    const product = products.find(p => p.id === productId);
    const method = paymentMethods.find(p => p.id === paymentMethodId);

    if (!product || !method) return false;

    const receiptUrl = URL.createObjectURL(receiptFile);

    // Calculate final price based on discount
    const finalPrice = product.price - (product.price * (product.discountPercent / 100));

    const newOrder: Order = {
      id: `ord-${Date.now()}`,
      userId: user.id,
      productId: product.id,
      productTitle: product.title,
      productType: product.type,
      price: finalPrice,
      status: OrderStatus.PENDING,
      date: new Date().toISOString(),
      paymentMethodName: method.name,
      userInput: userInput,
      receiptImage: receiptUrl,
    };

    setOrders(prev => [newOrder, ...prev]);
    console.log(`[Telegram Bot] New Order Received! Amount: ${newOrder.price} AZN. Order ID: ${newOrder.id}`);
    return true;
  };

  const updateOrderStatus = (orderId: string, status: OrderStatus) => {
    setOrders(prev => prev.map(order => {
      if (order.id !== orderId) return order;

      let updatedOrder = { ...order, status };

      // AUTOMATIC DELIVERY LOGIC
      if (status === OrderStatus.COMPLETED && !updatedOrder.deliveredContent) {
        const product = products.find(p => p.id === order.productId);

        if (product && (product.type === ProductType.LICENSE_KEY || product.type === ProductType.ACCOUNT)) {
          const availableStockIndex = product.stock.findIndex(s => !s.isSold);

          if (availableStockIndex !== -1) {
            const stockItem = product.stock[availableStockIndex];
            updatedOrder.deliveredContent = stockItem.content;
            markStockAsSold(product.id, stockItem.id);
          } else {
             updatedOrder.deliveredContent = "STOCK_ERROR: Contact Support";
          }
        } else if (product?.type === ProductType.ID_LOAD) {
          updatedOrder.deliveredContent = "Yüklənmə tamamlandı. ID: " + order.userInput;
        }
      }

      return updatedOrder;
    }));
  };

  const markStockAsSold = (productId: string, stockId: string) => {
    setProducts(prev => prev.map(p => {
      if (p.id !== productId) return p;
      return {
        ...p,
        stock: p.stock.map(s => s.id === stockId ? { ...s, isSold: true } : s)
      };
    }));
  };

  const addProductStock = (productId: string, rawItems: string[]) => {
    setProducts(prev => prev.map(p => {
      if (p.id !== productId) return p;
      const newItems: StockItem[] = rawItems.map((content, idx) => ({
        id: `stock-${Date.now()}-${idx}`,
        content,
        isSold: false
      }));
      return { ...p, stock: [...p.stock, ...newItems] };
    }));
  };

  const deleteProductStock = (productId: string, stockId: string) => {
    setProducts(prev => prev.map(p => {
      if (p.id !== productId) return p;
      return { ...p, stock: p.stock.filter(s => s.id !== stockId) };
    }));
  };

  // --- CMS Actions ---

  const addProduct = (product: Product) => {
    setProducts(prev => [...prev, product]);
  };

  const deleteProduct = (productId: string) => {
    setProducts(prev => prev.filter(p => p.id !== productId));
  };

  const addCategory = (category: Category) => {
    setCategories(prev => [...prev, category]);
  };

  const deleteCategory = (categoryId: string) => {
    setCategories(prev => prev.filter(c => c.id !== categoryId));
  };

  const updateSiteSettings = (settings: Partial<SiteSettings>) => {
    setSiteSettings(prev => ({ ...prev, ...settings }));
  };

  const addPaymentMethod = (method: PaymentMethod) => {
    setPaymentMethods(prev => [...prev, method]);
  };

  const updatePaymentMethod = (id: string, details: Partial<PaymentMethod>) => {
    setPaymentMethods(prev => prev.map(pm => pm.id === id ? { ...pm, ...details } : pm));
  };

  // New CMS Actions Implementation
  const addBlog = (blog: Blog) => setBlogs(prev => [...prev, blog]);
  const deleteBlog = (id: string) => setBlogs(prev => prev.filter(b => b.id !== id));

  const addAgreement = (agreement: Agreement) => setAgreements(prev => [...prev, agreement]);
  const deleteAgreement = (id: string) => setAgreements(prev => prev.filter(a => a.id !== id));

  const toggleCommentApproval = (id: string) => setComments(prev => prev.map(c => c.id === id ? {...c, isApproved: !c.isApproved} : c));
  const deleteComment = (id: string) => setComments(prev => prev.filter(c => c.id !== id));

  return (
    <AppContext.Provider value={{ 
      user, products, categories, orders, paymentMethods, siteSettings,
      blogs, agreements, comments,
      placeOrder, updateOrderStatus, toggleUserRole, updateUserBalance,
      addPaymentMethod, updatePaymentMethod, addProductStock, deleteProductStock,
      addProduct, deleteProduct, addCategory, deleteCategory, updateSiteSettings,
      addBlog, deleteBlog, addAgreement, deleteAgreement, toggleCommentApproval, deleteComment
    }}>
      {children}
    </AppContext.Provider>
  );
};

export const useApp = () => {
  const context = useContext(AppContext);
  if (!context) throw new Error("useApp must be used within AppProvider");
  return context;
};

