import React, { useState } from 'react';
import { useApp } from '../store';
import { Trash2, CreditCard, Upload, CheckCircle, ArrowRight } from 'lucide-react';
import { useNavigate } from 'react-router-dom';

const Cart = () => {
  const { cart, removeFromCart, paymentMethods, placeOrder, user, isAuthenticated } = useApp();
  const navigate = useNavigate();

  const [selectedMethod, setSelectedMethod] = useState<string | null>(null);
  const [receiptFile, setReceiptFile] = useState<File | null>(null);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [orderComplete, setOrderComplete] = useState(false);

  const totalAmount = cart.reduce((sum, item) => sum + item.price, 0);

  const handleCheckout = async () => {
     if(!selectedMethod || !receiptFile) return;
     setIsSubmitting(true);
     await placeOrder(selectedMethod, receiptFile);
     setIsSubmitting(false);
     setOrderComplete(true);
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
