import React, { useState } from 'react';
import { useApp } from '../store';
import { Order, OrderStatus } from '../types';
import { Clock, CheckCircle, XCircle, Copy, Plus, CreditCard, Upload, Send } from 'lucide-react';

const Profile = () => {
  const { user, orders, placeBalanceOrder, paymentMethods } = useApp();
  const [showTopUp, setShowTopUp] = useState(false);
  const [topUpAmount, setTopUpAmount] = useState<number>(10);
  const [selectedMethod, setSelectedMethod] = useState<string | null>(null);
  const [receiptFile, setReceiptFile] = useState<File | null>(null);

  const myOrders = orders.filter(o => o.userId === user?.id);

  const getStatusColor = (status: OrderStatus) => {
    switch (status) {
      case OrderStatus.PENDING: return 'text-yellow-400 bg-yellow-400/10';
      case OrderStatus.PROCESSING: return 'text-blue-400 bg-blue-400/10';
      case OrderStatus.COMPLETED: return 'text-green-400 bg-green-400/10';
      case OrderStatus.CANCELLED: return 'text-red-400 bg-red-400/10';
    }
  };

  const copyToClipboard = (text: string) => {
    navigator.clipboard.writeText(text);
    alert("Kopyalandı!");
  };

  const handleTopUpSubmit = async () => {
    if(!selectedMethod || !receiptFile || topUpAmount <= 0) return;
    await placeBalanceOrder(topUpAmount, selectedMethod, receiptFile);
    setShowTopUp(false);
    setReceiptFile(null);
    alert("Balans artırma sorğusu göndərildi! Admin təsdiqindən sonra balansınıza əlavə olunacaq.");
  };

  if(!user) return null;

  return (
    <div className="max-w-7xl mx-auto px-4 py-8">
      <div className="flex flex-col md:flex-row items-center justify-between gap-6 mb-10 bg-gaming-card p-6 rounded-2xl border border-gray-800">
        <div className="flex items-center gap-6">
            <img src={user.avatar || 'https://via.placeholder.com/150'} alt={user.name} className="w-20 h-20 rounded-full border-2 border-gaming-neon object-cover" />
            <div>
            <h1 className="text-2xl font-bold text-white">{user.name}</h1>
            <p className="text-gray-400">{user.email}</p>
            <div className="mt-2 inline-flex px-3 py-1 rounded bg-slate-800 text-xs text-gray-400 border border-gray-700">
                Member since 2024
            </div>
            </div>
        </div>

        <div className="bg-slate-900 p-4 rounded-xl border border-gray-700 text-center min-w-[200px]">
            <p className="text-gray-400 text-sm mb-1">Mövcud Balans</p>
            <p className="text-3xl font-mono font-bold text-gaming-neon">{user.balance.toFixed(2)} ₼</p>
            <button onClick={() => setShowTopUp(true)} className="mt-3 w-full bg-gaming-neon text-black font-bold py-2 rounded text-sm hover:bg-cyan-400 flex items-center justify-center gap-2">
                <Plus className="w-4 h-4" /> Balans Artır
            </button>
        </div>
      </div>

      <h2 className="text-xl font-bold text-white mb-6 pl-2 border-l-4 border-gaming-neon">Sifariş Tarixçəsi</h2>

      <div className="space-y-4">
        {myOrders.length === 0 ? (
          <p className="text-gray-500">Hələ heç bir sifariş yoxdur.</p>
        ) : (
          myOrders.map(order => (
            <div key={order.id} className="bg-gaming-card rounded-xl p-6 border border-gray-800 hover:border-gray-700 transition-all">
              <div className="flex flex-col md:flex-row justify-between md:items-center gap-4">

                <div className="flex-1">
                  <div className="flex items-center gap-3 mb-1">
                    <h3 className="text-lg font-bold text-white">{order.productTitle || (order.items && order.items.length > 0 ? order.items[0].title : 'Order')} {order.items && order.items.length > 1 && `(+${order.items.length - 1} digər)`}</h3>
                    <span className={`px-2 py-0.5 rounded text-xs font-bold ${getStatusColor(order.status)}`}>
                      {order.status}
                    </span>
                  </div>
                  <div className="text-sm text-gray-400">
                    ID: {order.id} • {new Date(order.date).toLocaleDateString()}
                  </div>
                </div>

                <div className="text-right">
                  <div className="text-xl font-bold text-white">{order.totalPrice ? order.totalPrice.toFixed(2) : order.price.toFixed(2)} ₼</div>
                  <div className="text-sm text-gray-500">{order.paymentMethodName}</div>
                </div>

              </div>

              {/* Delivery Section */}
              {order.status === OrderStatus.COMPLETED && order.deliveredContent && (
                <div className="mt-4 pt-4 border-t border-gray-800 bg-slate-900/50 -mx-6 -mb-6 px-6 py-4 rounded-b-xl">
                  <p className="text-xs text-green-400 mb-1 uppercase font-bold tracking-wider flex items-center gap-1">
                    <CheckCircle className="w-3 h-3" /> Təslimat
                  </p>
                  <div className="flex items-center gap-2 bg-black/40 p-3 rounded border border-gray-700">
                    <code className="text-gaming-neon font-mono flex-1 break-all">{order.deliveredContent}</code>
                    <button 
                      onClick={() => copyToClipboard(order.deliveredContent!)}
                      className="p-2 hover:bg-gray-700 rounded text-gray-400 hover:text-white"
                    >
                      <Copy className="w-4 h-4" />
                    </button>
                  </div>
                </div>
              )}
            </div>
          ))
        )}
      </div>

      {/* Top Up Modal */}
      {showTopUp && (
          <div className="fixed inset-0 z-50 bg-black/80 flex items-center justify-center p-4 backdrop-blur-sm">
             <div className="bg-slate-900 p-6 rounded-2xl border border-gray-700 w-full max-w-md shadow-2xl animate-fade-in">
                <div className="flex justify-between items-center mb-4">
                    <h3 className="text-xl font-bold text-white">Balans Artır</h3>
                    <button onClick={() => setShowTopUp(false)} className="text-gray-400 hover:text-white"><XCircle /></button>
                </div>

                <div className="space-y-4">
                    <div>
                        <label className="text-gray-400 text-sm">Məbləğ (AZN)</label>
                        <input type="number" className="w-full bg-black border border-gray-600 rounded p-3 text-white" value={topUpAmount} onChange={e => setTopUpAmount(parseFloat(e.target.value))} />
                    </div>

                    <div>
                        <label className="text-gray-400 text-sm mb-2 block">Ödəniş Üsulu</label>
                        <div className="grid grid-cols-1 gap-2">
                            {paymentMethods.filter(pm => pm.isActive).map(pm => (
                                <button key={pm.id} onClick={() => setSelectedMethod(pm.id)} className={`p-3 rounded border text-sm text-left ${selectedMethod === pm.id ? 'border-gaming-neon bg-gaming-neon/10 text-white' : 'border-gray-700 text-gray-400'}`}>
                                    {pm.name}
                                </button>
                            ))}
                        </div>
                    </div>

                    {selectedMethod && (
                        <div className="bg-slate-800 p-3 rounded text-sm text-gray-300">
                            Hesab: <span className="text-white font-mono">{paymentMethods.find(p=>p.id===selectedMethod)?.details}</span>
                        </div>
                    )}

                    <div className="border-2 border-dashed border-gray-600 rounded p-4 text-center cursor-pointer hover:bg-slate-800" onClick={() => document.getElementById('topup-file')?.click()}>
                         <Upload className="w-6 h-6 mx-auto text-gray-400 mb-2"/>
                         <span className="text-xs text-gray-400">{receiptFile ? receiptFile.name : "Çeki Yüklə"}</span>
                         <input id="topup-file" type="file" hidden accept="image/*" onChange={(e) => e.target.files && setReceiptFile(e.target.files[0])} />
                    </div>

                    <button onClick={handleTopUpSubmit} className="w-full bg-green-600 text-white font-bold py-3 rounded flex items-center justify-center gap-2">
                        <Send className="w-4 h-4" /> Göndər
                    </button>
                </div>
             </div>
          </div>
      )}
    </div>
  );
};

