    paymentMethods, updatePaymentMethod, siteSettings, updateSiteSettings,
    categories, addCategory, deleteCategory, addProduct, deleteProduct,
    blogs, addBlog, deleteBlog, agreements, addAgreement, deleteAgreement,
    comments, toggleCommentApproval, deleteComment, logout
  } = useApp();

  const [activeTab, setActiveTab] = useState<'dashboard' | 'orders' | 'products' | 'categories' | 'cms' | 'settings'>('dashboard');
  const [cmsSubTab, setCmsSubTab] = useState<'blogs' | 'contracts' | 'comments'>('blogs');
  const [settingsSubTab, setSettingsSubTab] = useState<'general' | 'payment' | 'hero' | 'seo'>('general');

  // Modals
  const [viewReceipt, setViewReceipt] = useState<string | null>(null);
  const [deliveryModal, setDeliveryModal] = useState<{orderId: string, productTitle: string} | null>(null);
  const [deliveryContent, setDeliveryContent] = useState('');

  // States for Dashboard Date Filter
  const [statsPeriod, setStatsPeriod] = useState<number>(1); // 1 = Today

  // States for Forms
  const [newCatName, setNewCatName] = useState('');

  // Product Form
  const [productForm, setProductForm] = useState<Partial<Product> & { imageFile?: File | null }>({
    title: '', categoryId: '', price: 0, costPrice: 0, discountPercent: 0, type: ProductType.LICENSE_KEY, image: '', description: '', requiresInput: false
  });
  const fileInputRef = useRef<HTMLInputElement>(null);

  if (!user || user.role !== 'admin') {
    return <div className="p-10 text-center text-red-500 font-bold text-2xl">Access Denied</div>;
  }

  // --- STATS LOGIC ---
  const getFilteredOrders = () => {
    const now = new Date();
    const past = new Date();

    // If statsPeriod is 1 (Today), we need to check only today's date string
    if (statsPeriod === 1) {
       return orders.filter(o => {
         const orderDate = new Date(o.date);
         return orderDate.toDateString() === now.toDateString() && o.status === OrderStatus.COMPLETED;
       });
    }

    past.setDate(now.getDate() - statsPeriod);
    past.setHours(0,0,0,0);

    return orders.filter(o => {
      const orderDate = new Date(o.date);
      return orderDate >= past && o.status === OrderStatus.COMPLETED;
    });
  };

  const filteredOrders = getFilteredOrders();
  // Revenue calculation update for legacy/new order structure
  const totalRevenue = filteredOrders.reduce((sum, o) => sum + (o.totalPrice || o.price), 0);

  // Simplified Profit Calculation (ignoring bundle cost complexity for now)
  const totalProfit = totalRevenue * 0.2; // Rough estimate as cost calculation for bundles is complex in this scope

  // --- HANDLERS ---

  const handleLogout = () => {
    logout();
    navigate('/');
  };

  const openDeliveryModal = (order: Order) => {
    // Check if it is a balance order
    if (order.productType === ProductType.BALANCE || (order.items && order.items[0]?.type === ProductType.BALANCE)) {
        if(window.confirm("Bu balans artımıdır. Təsdiqləsəniz istifadəçi balansına avtomatik pul əlavə olunacaq.")) {
            completeOrder(order.id, "Balans Artırıldı");
        }
    } else {
        const title = order.productTitle || (order.items && order.items.length > 0 ? order.items.map(i => i.title).join(', ') : 'Order');
        setDeliveryModal({ orderId: order.id, productTitle: title });
        setDeliveryContent('');
    }
  };

  const confirmDelivery = () => {
    if(!deliveryModal || !deliveryContent) return;
    completeOrder(deliveryModal.orderId, deliveryContent);
    setDeliveryModal(null);
    setDeliveryContent('');
    alert("Sifariş tamamlandı və məlumat istifadəçiyə göndərildi!");
  };

  const handleProductImageSelect = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if(file) {
      setProductForm({...productForm, imageFile: file, image: URL.createObjectURL(file)});
    }
  };

  const handleCreateProduct = (e: React.FormEvent) => {
    e.preventDefault();
    if(!productForm.title || !productForm.price || !productForm.categoryId) {
      alert("Əsas xanaları doldurun!");
      return;
