    const product: Product = {
      id: `prod-${Date.now()}`,
      title: productForm.title!,
      categoryId: productForm.categoryId!,
      type: productForm.type || ProductType.LICENSE_KEY,
      price: Number(productForm.price),
      costPrice: Number(productForm.costPrice || 0),
      discountPercent: Number(productForm.discountPercent || 0),
      image: productForm.image || 'https://via.placeholder.com/300',
      description: productForm.description || '',
      requiresInput: productForm.requiresInput,
      inputLabel: productForm.inputLabel
    };
    addProduct(product);
