        )}

        {/* ORDERS TAB */}
        {activeTab === 'orders' && (
          <div className="space-y-6 animate-fade-in">
             <h3 className="text-xl font-bold mb-4">Sifariş İdarəetməsi</h3>
             <div className="grid gap-4">
                {orders.length === 0 && <p className="text-gray-500">Sifariş tapılmadı.</p>}
                {orders.map(order => (
                  <div key={order.id} className="bg-slate-800 rounded-xl p-4 border border-gray-700 flex flex-col lg:flex-row gap-4">
                     <div className="w-full lg:w-32 h-32 bg-black rounded-lg relative group cursor-pointer border border-gray-600 shrink-0" onClick={() => setViewReceipt(order.receiptImage || '')}>
                        <img src={order.receiptImage} className="w-full h-full object-cover opacity-70 group-hover:opacity-100" alt="Receipt" />
                        <div className="absolute inset-0 flex items-center justify-center opacity-0 group-hover:opacity-100 bg-black/40">
                          <Eye className="text-white" />
                        </div>
                     </div>
                     <div className="flex-1">
                        <div className="flex justify-between">
                           <div>
                              <h4 className="font-bold text-lg">
                                  {order.items && order.items.length > 0 ? (
                                      <div className="flex flex-col gap-1">
                                          {order.items.map((item, idx) => (
                                              <div key={idx} className="flex gap-2 text-sm">
                                                  <span>- {item.title}</span>
                                                  {item.userInput && <span className="text-yellow-400 text-xs bg-yellow-400/10 px-1 rounded">({item.userInput})</span>}
                                              </div>
                                          ))}
                                      </div>
                                  ) : (
                                      order.productTitle
                                  )}
                              </h4>
                              <p className="text-sm text-gray-400 mt-1">User: {order.userId}</p>
                              {order.userInput && <p className="text-yellow-400 bg-yellow-400/10 px-2 py-1 rounded inline-block text-xs mt-1">Player ID: {order.userInput}</p>}

                              {/* Order Type Badge */}
                              {(order.productType === ProductType.BALANCE || (order.items && order.items[0]?.type === ProductType.BALANCE)) && (
                                  <span className="mt-2 inline-block bg-purple-500/20 text-purple-400 px-2 py-1 rounded text-xs font-bold border border-purple-500/30">BALANS ARTIRMA</span>
                              )}

                              <div className="flex gap-2 mt-2">
                                <span className={`px-2 py-1 rounded text-xs ${order.status === OrderStatus.PENDING ? 'bg-yellow-500/20 text-yellow-500' : order.status === OrderStatus.COMPLETED ? 'bg-green-500/20 text-green-500' : 'bg-red-500/20 text-red-500'}`}>
                                  {order.status}
                                </span>
                              </div>
                           </div>
                           <div className="text-right">
                              <p className="text-2xl font-bold text-green-400">{order.totalPrice ? order.totalPrice.toFixed(2) : order.price.toFixed(2)} ₼</p>
                              <p className="text-xs text-gray-500">{new Date(order.date).toLocaleString()}</p>
                           </div>
                        </div>
                        {order.status === OrderStatus.PENDING && (
                           <div className="mt-4 flex gap-2">
                              <button onClick={() => openDeliveryModal(order)} className="bg-green-600 hover:bg-green-700 text-white px-6 py-2 rounded flex items-center gap-2 font-bold shadow-lg shadow-green-900/30">
                                  <Check className="w-4 h-4" /> 
                                  {(order.productType === ProductType.BALANCE || (order.items && order.items[0]?.type === ProductType.BALANCE)) ? "Balansı Təsdiqlə" : "Təsdiqlə və Göndər"}
                              </button>
                              <button onClick={() => cancelOrder(order.id)} className="bg-red-600 hover:bg-red-700 text-white px-4 py-2 rounded flex items-center gap-2"><X className="w-4 h-4" /> İmtina</button>
                           </div>
                        )}
                        {order.status === OrderStatus.COMPLETED && (
                           <div className="mt-2 text-sm text-gray-500">
                              Göndərilən Məlumat: <span className="text-white font-mono">{order.deliveredContent}</span>
                           </div>
                        )}
                     </div>
                  </div>
                ))}
             </div>
          </div>
        )}

        {/* CATEGORIES TAB (SEPARATE) */}
        {activeTab === 'categories' && (
          <div className="animate-fade-in space-y-6">
              <h3 className="text-xl font-bold mb-4 flex items-center gap-2"><LayoutGrid className="text-gaming-neon" /> Kateqoriya İdarəetməsi</h3>

              <div className="bg-slate-800 p-6 rounded-xl border border-gray-700 max-w-xl">
                    <h4 className="font-bold mb-4">Yeni Kateqoriya Yarat</h4>
                    <div className="flex gap-2 mb-6">
                       <input type="text" className="flex-1 bg-slate-900 p-3 rounded border border-gray-600" placeholder="Məs: PUBG Mobile" value={newCatName} onChange={e => setNewCatName(e.target.value)} />
                       <button onClick={() => { if(newCatName) { addCategory({id: `cat-${Date.now()}`, name: newCatName}); setNewCatName(''); }}} className="bg-gaming-neon text-black px-6 rounded font-bold hover:bg-cyan-400">Əlavə Et</button>
                    </div>

                    <h4 className="font-bold mb-4 text-gray-400 text-sm uppercase">Mövcud Kateqoriyalar</h4>
                    <div className="space-y-2">
                       {categories.map(c => (
                          <div key={c.id} className="flex justify-between items-center bg-slate-700 p-3 rounded-lg border border-slate-600">
                             <span className="font-medium">{c.name}</span>
                             <button onClick={() => deleteCategory(c.id)} className="text-red-400 hover:text-white p-1 rounded hover:bg-red-500/20"><Trash2 className="w-5 h-5" /></button>
                          </div>
                       ))}
                    </div>
                </div>
          </div>
        )}

        {/* PRODUCTS TAB (SEPARATE) */}
        {activeTab === 'products' && (
          <div className="space-y-8 animate-fade-in">
             <div className="bg-slate-800 p-6 rounded-xl border border-gray-700">
                <h3 className="text-xl font-bold mb-6 flex items-center gap-2"><Plus className="text-gaming-neon" /> Yeni Məhsul Yarat</h3>

                <form onSubmit={handleCreateProduct} className="grid grid-cols-1 lg:grid-cols-2 gap-8">
                   <div className="space-y-4">
                      {/* Image Select */}
                      <div 
                         className="border-2 border-dashed border-gray-600 rounded-xl h-48 flex flex-col items-center justify-center cursor-pointer hover:bg-slate-700/50 transition-colors relative overflow-hidden"
                         onClick={() => fileInputRef.current?.click()}
                      >
                         {productForm.image ? (
                           <img src={productForm.image} className="w-full h-full object-cover" alt="Preview" />
                         ) : (
                           <>
                             <UploadCloud className="w-10 h-10 text-gray-400 mb-2" />
                             <p className="text-sm text-gray-400">Şəkil Seçmək üçün toxun</p>
                           </>
                         )}
                         <input type="file" ref={fileInputRef} className="hidden" onChange={handleProductImageSelect} accept="image/*" />
                      </div>

                      <div className="grid grid-cols-2 gap-4">
                         <div>
                            <label className="text-xs text-gray-400">Kateqoriya</label>
                            <select className="w-full bg-slate-900 p-2 rounded border border-gray-600" value={productForm.categoryId} onChange={e => setProductForm({...productForm, categoryId: e.target.value})}>
                               <option value="">Seçin...</option>
                               {categories.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
                            </select>
                         </div>
                         <div>
                            <label className="text-xs text-gray-400">Məhsul Tipi</label>
                            <select className="w-full bg-slate-900 p-2 rounded border border-gray-600" value={productForm.type} onChange={e => setProductForm({...productForm, type: e.target.value as ProductType})}>
                               <option value={ProductType.LICENSE_KEY}>License Key (Kod)</option>
                               <option value={ProductType.ID_LOAD}>ID Yükləmə</option>
                               <option value={ProductType.ACCOUNT}>Hesab (Account)</option>
                            </select>
                         </div>
                      </div>
                   </div>

                   <div className="space-y-4">
                      <div>
                         <label className="text-xs text-gray-400">Məhsul Adı</label>
                         <input type="text" className="w-full bg-slate-900 p-2 rounded border border-gray-600" value={productForm.title} onChange={e => setProductForm({...productForm, title: e.target.value})} placeholder="Məs: 60 UC" />
                      </div>

                      <div className="grid grid-cols-3 gap-4">
                         <div>
                            <label className="text-xs text-gray-400">Maya Dəyəri (Cost)</label>
                            <input type="number" step="0.01" className="w-full bg-slate-900 p-2 rounded border border-gray-600" value={productForm.costPrice} onChange={e => setProductForm({...productForm, costPrice: parseFloat(e.target.value)})} />
                         </div>
                         <div>
                            <label className="text-xs text-gray-400">Satış Qiyməti</label>
                            <input type="number" step="0.01" className="w-full bg-slate-900 p-2 rounded border border-gray-600" value={productForm.price} onChange={e => setProductForm({...productForm, price: parseFloat(e.target.value)})} />
                         </div>
                         <div>
                            <label className="text-xs text-gray-400">Endirim %</label>
                            <input type="number" step="1" className="w-full bg-slate-900 p-2 rounded border border-gray-600" value={productForm.discountPercent} onChange={e => setProductForm({...productForm, discountPercent: parseFloat(e.target.value)})} />
                         </div>
                      </div>

                      {/* Calculated Final Price Display */}
                      <div className="bg-slate-900 p-2 rounded text-xs text-gray-400 flex justify-between">
                         <span>Müştərinin görəcəyi qiymət:</span>
                         <span className="text-green-400 font-bold">
                            {(Number(productForm.price) - (Number(productForm.price) * (Number(productForm.discountPercent)/100))).toFixed(2)} ₼
                         </span>
                      </div>

                       {productForm.type === ProductType.ID_LOAD && (
                        <div>
                           <label className="flex items-center gap-2 text-sm text-yellow-400 bg-yellow-400/10 p-2 rounded border border-yellow-400/20">
                              <input type="checkbox" checked={productForm.requiresInput} onChange={e => setProductForm({...productForm, requiresInput: e.target.checked})} />
                              İstifadəçi ID / Nickname daxil etməlidir?
                           </label>
                        </div>
                      )}

                      <button type="submit" className="w-full bg-gaming-neon text-black font-bold py-3 rounded hover:bg-cyan-400 transition-colors">Yadda Saxla</button>
                   </div>
                </form>
             </div>

             <div className="bg-slate-800 p-6 rounded-xl border border-gray-700">
                 <h4 className="font-bold mb-4">Mövcud Məhsullar</h4>
                 <div className="space-y-2 max-h-96 overflow-y-auto">
                    {products.map(p => (
                       <div key={p.id} className="flex justify-between items-center bg-slate-700 p-3 rounded border border-slate-600">
                          <div className="flex items-center gap-3">
                             <img src={p.image} className="w-10 h-10 rounded object-cover" alt="" />
                             <div>
                                <p className="font-bold text-white">{p.title}</p>
                                <p className="text-xs text-gray-400">{p.price.toFixed(2)} ₼</p>
                             </div>
                          </div>
                          <button onClick={() => deleteProduct(p.id)} className="text-red-400 hover:bg-red-500/20 p-2 rounded"><Trash2 className="w-5 h-5"/></button>
                       </div>
                    ))}
                 </div>
             </div>
          </div>
        )}

        {/* CMS TAB */}
        {activeTab === 'cms' && (
          <div className="space-y-6 animate-fade-in">
             <div className="flex gap-4 border-b border-gray-800 pb-4">
                <button onClick={() => setCmsSubTab('blogs')} className={`px-4 py-2 rounded-lg font-medium ${cmsSubTab === 'blogs' ? 'bg-gaming-neon text-black' : 'bg-slate-800 text-gray-400'}`}>Bloglar</button>
                <button onClick={() => setCmsSubTab('contracts')} className={`px-4 py-2 rounded-lg font-medium ${cmsSubTab === 'contracts' ? 'bg-gaming-neon text-black' : 'bg-slate-800 text-gray-400'}`}>Sözləşmələr</button>
                <button onClick={() => setCmsSubTab('comments')} className={`px-4 py-2 rounded-lg font-medium ${cmsSubTab === 'comments' ? 'bg-gaming-neon text-black' : 'bg-slate-800 text-gray-400'}`}>Rəylər</button>
             </div>

             {cmsSubTab === 'blogs' && (
               <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
                  {blogs.map(blog => (
                     <div key={blog.id} className="bg-slate-800 p-4 rounded-xl border border-gray-700 flex gap-4">
                        <img src={blog.image} className="w-24 h-24 object-cover rounded-lg" alt="" />
                        <div className="flex-1">
                           <h4 className="font-bold text-lg">{blog.title}</h4>
                           <p className="text-sm text-gray-400 line-clamp-2">{blog.content}</p>
                           <button onClick={() => deleteBlog(blog.id)} className="text-red-400 text-sm mt-2 hover:underline">Sil</button>
                        </div>
                     </div>
                  ))}
                  <div className="bg-slate-800 p-4 rounded-xl border border-dashed border-gray-600 flex items-center justify-center cursor-pointer hover:bg-slate-700" onClick={() => addBlog({id: `b-${Date.now()}`, title: 'Yeni Blog', content: 'Məzmun...', image: 'https://via.placeholder.com/150', date: new Date().toISOString()})}>
                      <span className="text-gray-400 font-bold">+ Yeni Blog Yaz</span>
                  </div>
               </div>
             )}

             {cmsSubTab === 'contracts' && (
                <div className="space-y-4">
                   {agreements.map(a => (
                      <div key={a.id} className="bg-slate-800 p-4 rounded-xl border border-gray-700">
                         <div className="flex justify-between items-center mb-2">
                            <h4 className="font-bold text-gaming-neon"><FileText className="inline w-4 h-4 mr-2"/> {a.title}</h4>
                            <button onClick={() => deleteAgreement(a.id)} className="text-red-400"><Trash2 className="w-4 h-4"/></button>
                         </div>
                         <textarea className="w-full bg-slate-900 border border-gray-600 rounded p-2 h-24 text-sm" defaultValue={a.content} />
                         <button className="bg-blue-600 text-white px-4 py-1 rounded text-xs mt-2">Yenilə</button>
                      </div>
                   ))}
                </div>
             )}

             {cmsSubTab === 'comments' && (
                <div className="space-y-4">
                   {comments.map(c => (
                      <div key={c.id} className="bg-slate-800 p-4 rounded-xl border border-gray-700 flex justify-between items-start">
                         <div>
                            <div className="flex items-center gap-2">
                               <span className="font-bold">{c.author}</span>
                               <span className="text-xs bg-slate-700 px-2 rounded uppercase">{c.type}</span>
                               {!c.isApproved && <span className="text-xs bg-red-900 text-red-300 px-2 rounded">Gözləmədə</span>}
                            </div>
                            <p className="text-gray-300 mt-1">{c.content}</p>
                         </div>
                         <div className="flex gap-2">
                            <button onClick={() => toggleCommentApproval(c.id)} className={`p-2 rounded ${c.isApproved ? 'bg-yellow-600' : 'bg-green-600'}`}>{c.isApproved ? 'Gizlə' : 'Təsdiqlə'}</button>
                            <button onClick={() => deleteComment(c.id)} className="bg-red-600 p-2 rounded"><Trash2 className="w-4 h-4"/></button>
                         </div>
                      </div>
                   ))}
                </div>
             )}
          </div>
        )}

        {/* SETTINGS TAB */}
        {activeTab === 'settings' && (
           <div className="flex flex-col lg:flex-row gap-8 animate-fade-in">
              <div className="w-full lg:w-48 space-y-2">
                 {['general', 'payment', 'hero', 'seo'].map(sub => (
                    <button key={sub} onClick={() => setSettingsSubTab(sub as any)} className={`w-full text-left px-4 py-2 rounded uppercase text-xs font-bold ${settingsSubTab === sub ? 'bg-gaming-neon text-black' : 'bg-slate-800 text-gray-400'}`}>
                       {sub} Ayarları
                    </button>
                 ))}
              </div>

              <div className="flex-1 bg-slate-800 p-6 rounded-xl border border-gray-700">
                 {settingsSubTab === 'general' && (
                    <div className="space-y-4">
                       <h3 className="font-bold text-lg mb-4">Ümumi Məlumatlar</h3>
                       <div><label className="text-xs text-gray-500">Sayt Adı</label><input className="w-full bg-slate-900 p-2 rounded border border-gray-600" value={siteSettings.siteName} onChange={e => updateSiteSettings({siteName: e.target.value})} /></div>
                       <div><label className="text-xs text-gray-500">Logo URL</label><input className="w-full bg-slate-900 p-2 rounded border border-gray-600" value={siteSettings.logoUrl} onChange={e => updateSiteSettings({logoUrl: e.target.value})} /></div>
                       <div><label className="text-xs text-gray-500">Discord Webhook</label><input className="w-full bg-slate-900 p-2 rounded border border-gray-600" value={siteSettings.discordWebhook} onChange={e => updateSiteSettings({discordWebhook: e.target.value})} /></div>
                    </div>
                 )}
                 {settingsSubTab === 'payment' && (
                    <div className="space-y-6">
                       <h3 className="font-bold text-lg mb-4">Ödəniş Sistemləri</h3>
                       {paymentMethods.map(pm => (
                          <div key={pm.id} className="border border-gray-700 p-4 rounded bg-slate-900">
                             <div className="flex justify-between mb-2">
                                <span className="font-bold">{pm.name}</span>
                                <button onClick={() => updatePaymentMethod(pm.id, {isActive: !pm.isActive})} className={`text-xs px-2 rounded ${pm.isActive ? 'bg-green-600' : 'bg-red-600'}`}>{pm.isActive ? 'Aktiv' : 'Passiv'}</button>
                             </div>
                             <input className="w-full bg-slate-800 p-2 rounded mb-2 text-sm" value={pm.details} onChange={e => updatePaymentMethod(pm.id, {details: e.target.value})} />
                             <textarea className="w-full bg-slate-800 p-2 rounded text-sm" value={pm.instructions} onChange={e => updatePaymentMethod(pm.id, {instructions: e.target.value})} />
                          </div>
                       ))}
                    </div>
                 )}
              </div>
           </div>
        )}
      </div>

      {/* Manual Delivery Modal */}
      {deliveryModal && (
        <div className="fixed inset-0 z-[60] bg-black/80 flex items-center justify-center p-4 backdrop-blur-sm">
           <div className="bg-slate-900 p-6 rounded-2xl border border-gray-700 w-full max-w-lg shadow-2xl">
              <h3 className="text-xl font-bold mb-2">Sifarişi Tamamla & Göndər</h3>
              <p className="text-gray-400 text-sm mb-4">Məhsul: <span className="text-white font-bold">{deliveryModal.productTitle}</span></p>

              <div className="mb-4">
                 <label className="block text-xs text-gaming-neon mb-2 uppercase font-bold">Müştəriyə göndəriləcək məlumat (Kod / Account)</label>
                 <textarea 
                    className="w-full bg-black border border-gray-600 rounded-lg p-3 text-white h-32 font-mono"
                    placeholder="E-pin kodu və ya Email:Pass bura yazın..."
                    value={deliveryContent}
                    onChange={(e) => setDeliveryContent(e.target.value)}
                 ></textarea>
                 <p className="text-xs text-gray-500 mt-2">Bu məlumat birbaşa müştərinin profilinə düşəcək.</p>
              </div>

              <div className="flex justify-end gap-3">
                 <button onClick={() => setDeliveryModal(null)} className="px-4 py-2 rounded text-gray-400 hover:text-white hover:bg-white/10">Bağla</button>
                 <button onClick={confirmDelivery} disabled={!deliveryContent} className={`px-6 py-2 rounded font-bold flex items-center gap-2 ${deliveryContent ? 'bg-green-600 hover:bg-green-500 text-white' : 'bg-gray-700 text-gray-500 cursor-not-allowed'}`}>
                    <Send className="w-4 h-4" /> Təsdiqlə
                 </button>
              </div>
           </div>
        </div>
      )}

      {/* Image Modal */}
      {viewReceipt && (
        <div className="fixed inset-0 z-[60] bg-black/95 flex items-center justify-center p-4 backdrop-blur-sm" onClick={() => setViewReceipt(null)}>
           <img src={viewReceipt} className="max-w-full max-h-[90vh] rounded shadow-2xl border border-gray-700" alt="Receipt Full" />
           <button className="absolute top-4 right-4 text-white bg-red-600 p-3 rounded-full hover:bg-red-700">
             <X />
           </button>
        </div>
      )}
    </div>
  );
};

export default Admin;

import React from 'react';
import { HashRouter, Routes, Route, useLocation } from 'react-router-dom';
import Navbar from './components/Navbar';
import Home from './pages/Home';
import ProductView from './pages/ProductView';
import Profile from './pages/Profile';
import Admin from './pages/Admin';
import Auth from './pages/Auth';
import Cart from './pages/Cart';
import { AppProvider, useApp } from './store';
import { MessageCircle } from 'lucide-react';

const Footer = () => {
   const { siteSettings } = useApp();
   return (
     <footer className="bg-slate-950 border-t border-gray-800 py-8 text-center text-gray-500 text-sm">
        <p>{siteSettings.footerText}</p>
        <p className="mt-2 text-xs">WhatsApp: {siteSettings.whatsappNumber}</p>
     </footer>
   )
}

// Live Chat Widget Component
const LiveChat = () => {
  return (
    <div className="fixed bottom-6 right-6 z-50">
      <button 
        onClick={() => alert("Canlı Dəstək tezliklə aktiv olacaq! Hələlik WhatsApp ilə əlaqə saxlayın.")}
        className="bg-green-500 hover:bg-green-600 text-white p-4 rounded-full shadow-lg shadow-green-500/30 transition-all transform hover:scale-110 flex items-center gap-2"
      >
        <MessageCircle className="w-6 h-6" />
        <span className="font-bold hidden md:inline">Canlı Dəstək</span>
      </button>
    </div>
  );
};

const Layout = ({ children }: { children?: React.ReactNode }) => {
  const location = useLocation();
  const isAdminPage = location.pathname.startsWith('/admin');
  const isAuthPage = location.pathname === '/auth';

  return (
    <div className="flex flex-col min-h-screen">
      {!isAdminPage && !isAuthPage && <Navbar />}
      <main className="flex-grow relative">
        {children}
      </main>
      {!isAdminPage && !isAuthPage && <Footer />}
      {!isAdminPage && !isAuthPage && <LiveChat />}
    </div>
  );
};

const App = () => {
  return (
    <AppProvider>
      <HashRouter>
        <Layout>
          <Routes>
            <Route path="/" element={<Home />} />
            <Route path="/auth" element={<Auth />} />
            <Route path="/cart" element={<Cart />} />
            <Route path="/product/:id" element={<ProductView />} />
            <Route path="/profile" element={<Profile />} />
            <Route path="/admin" element={<Admin />} />
          </Routes>
        </Layout>
      </HashRouter>
    </AppProvider>
  );
};

export default App;

