import React, { useState } from 'react';
import { useApp } from '../store';
import { useNavigate } from 'react-router-dom';
import { User, Mail, Lock, ArrowRight, Phone, KeyRound, ArrowLeft } from 'lucide-react';

type AuthView = 'login' | 'register' | 'forgot-password';

const Auth = () => {
  const [view, setView] = useState<AuthView>('login');
  const { login, register, resetPassword } = useApp();
  const navigate = useNavigate();

  // Login/Register Form State
  const [formData, setFormData] = useState({
    name: '',
    email: '',
    password: ''
  });

  // Forgot Password Flow State
  const [forgotStep, setForgotStep] = useState<1 | 2 | 3>(1); // 1: Phone, 2: Code, 3: New Password
  const [resetData, setResetData] = useState({
    phone: '',
    code: '',
    newPassword: ''
  });

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (view === 'login') {
      const success = login(formData.email, formData.password);
      if (success) {
        if(formData.email === 'admin@gamepay.az') {
           navigate('/admin');
        } else {
           navigate('/');
        }
      } else {
        alert("Yanlış email və ya şifrə!");
      }
    } else if (view === 'register') {
      if(formData.name && formData.email && formData.password) {
        register(formData.name, formData.email, formData.password);
        navigate('/');
      }
    }
  };

  const handleForgotSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (forgotStep === 1) {
      if (resetData.phone.length < 9) {
        alert("Düzgün mobil nömrə daxil edin.");
        return;
      }
      // Simulate sending SMS
      alert(`Təsdiq kodu ${resetData.phone} nömrəsinə göndərildi (Test Code: 1234)`);
      setForgotStep(2);
    } else if (forgotStep === 2) {
      if (resetData.code === '1234') {
         setForgotStep(3);
      } else {
         alert("Yanlış kod!");
      }
    } else if (forgotStep === 3) {
       if (resetData.newPassword.length < 6) {
         alert("Şifrə ən az 6 simvol olmalıdır.");
         return;
       }
       resetPassword(resetData.phone, resetData.newPassword);
       alert("Şifrə uğurla yeniləndi! İndi giriş edə bilərsiniz.");
       setView('login');
       setForgotStep(1);
       setResetData({phone: '', code: '', newPassword: ''});
    }
  };

  return (
    <div className="min-h-screen bg-gaming-dark flex items-center justify-center p-4">
      <div className="w-full max-w-md bg-gaming-card border border-gray-800 rounded-2xl p-8 shadow-2xl relative overflow-hidden">
         {/* Background Glow */}
         <div className="absolute top-0 left-0 w-full h-2 bg-gradient-to-r from-gaming-neon to-gaming-accent"></div>

         <div className="text-center mb-8">
           <h1 className="text-3xl font-black text-white mb-2">
             {view === 'login' ? 'Xoş Gəldiniz' : view === 'register' ? 'Qeydiyyat' : 'Şifrəni Yenilə'}
           </h1>
           <p className="text-gray-400 text-sm">GamePay dünyasına daxil olun</p>
         </div>

         {view === 'forgot-password' ? (
             <form onSubmit={handleForgotSubmit} className="space-y-4">
                {forgotStep === 1 && (
                  <div className="relative animate-fade-in">
                      <label className="text-xs text-gray-500 ml-1 mb-1 block">Mobil Nömrə</label>
                      <Phone className="absolute left-3 top-8 text-gray-500 w-5 h-5" />
                      <input 
                        type="tel" 
                        placeholder="+994 50 123 45 67" 
                        className="w-full bg-slate-900 border border-gray-700 rounded-lg py-3 pl-10 pr-4 text-white focus:border-gaming-neon outline-none"
                        value={resetData.phone}
                        onChange={e => setResetData({...resetData, phone: e.target.value})}
                      />
                      <p className="text-xs text-gray-500 mt-2">Təsdiq kodu SMS vasitəsilə göndəriləcək.</p>
                  </div>
                )}

                {forgotStep === 2 && (
                  <div className="relative animate-fade-in">
                      <label className="text-xs text-gray-500 ml-1 mb-1 block">Təsdiq Kodu</label>
                      <KeyRound className="absolute left-3 top-8 text-gray-500 w-5 h-5" />
                      <input 
                        type="text" 
                        placeholder="1234" 
                        className="w-full bg-slate-900 border border-gray-700 rounded-lg py-3 pl-10 pr-4 text-white focus:border-gaming-neon outline-none tracking-widest text-center font-mono text-lg"
                        value={resetData.code}
                        onChange={e => setResetData({...resetData, code: e.target.value})}
                      />
                  </div>
                )}

                {forgotStep === 3 && (
                  <div className="relative animate-fade-in">
                      <label className="text-xs text-gray-500 ml-1 mb-1 block">Yeni Şifrə</label>
                      <Lock className="absolute left-3 top-8 text-gray-500 w-5 h-5" />
                      <input 
                        type="password" 
                        placeholder="Yeni şifrənizi daxil edin" 
                        className="w-full bg-slate-900 border border-gray-700 rounded-lg py-3 pl-10 pr-4 text-white focus:border-gaming-neon outline-none"
                        value={resetData.newPassword}
                        onChange={e => setResetData({...resetData, newPassword: e.target.value})}
                      />
                  </div>
                )}

                <button type="submit" className="w-full bg-gaming-neon hover:bg-cyan-400 text-black font-bold py-3 rounded-lg flex items-center justify-center gap-2 transition-transform active:scale-95">
                   {forgotStep === 1 ? 'Kodu Göndər' : forgotStep === 2 ? 'Təsdiqlə' : 'Şifrəni Dəyiş'} <ArrowRight className="w-4 h-4" />
                </button>

                <button type="button" onClick={() => setView('login')} className="w-full text-gray-400 text-sm hover:text-white mt-2 flex items-center justify-center gap-1">
                   <ArrowLeft className="w-3 h-3"/> Geri Qayıt
                </button>
             </form>
         ) : (
            <form onSubmit={handleSubmit} className="space-y-4">
                {view === 'register' && (
                  <div className="relative">
                    <User className="absolute left-3 top-3.5 text-gray-500 w-5 h-5" />
                    <input 
                      type="text" 
                      placeholder="Ad Soyad" 
                      className="w-full bg-slate-900 border border-gray-700 rounded-lg py-3 pl-10 pr-4 text-white focus:border-gaming-neon outline-none"
                      value={formData.name}
                      onChange={e => setFormData({...formData, name: e.target.value})}
                    />
                  </div>
                )}
                <div className="relative">
                    <Mail className="absolute left-3 top-3.5 text-gray-500 w-5 h-5" />
                    <input 
                      type="email" 
                      placeholder="Email ünvanı" 
                      className="w-full bg-slate-900 border border-gray-700 rounded-lg py-3 pl-10 pr-4 text-white focus:border-gaming-neon outline-none"
                      value={formData.email}
                      onChange={e => setFormData({...formData, email: e.target.value})}
                    />
                </div>
                <div className="relative">
                    <Lock className="absolute left-3 top-3.5 text-gray-500 w-5 h-5" />
                    <input 
                      type="password" 
                      placeholder="Şifrə" 
                      className="w-full bg-slate-900 border border-gray-700 rounded-lg py-3 pl-10 pr-4 text-white focus:border-gaming-neon outline-none"
                      value={formData.password}
                      onChange={e => setFormData({...formData, password: e.target.value})}
                    />
                </div>

                {view === 'login' && (
                  <div className="flex justify-end">
                    <button type="button" onClick={() => { setView('forgot-password'); setForgotStep(1); }} className="text-xs text-gaming-neon hover:underline">
                      Şifrəni unutmusunuz?
                    </button>
                  </div>
                )}

                <button type="submit" className="w-full bg-gaming-neon hover:bg-cyan-400 text-black font-bold py-3 rounded-lg flex items-center justify-center gap-2 transition-transform active:scale-95">
                  {view === 'login' ? 'Daxil Ol' : 'Qeydiyyatdan Keç'} <ArrowRight className="w-4 h-4" />
                </button>
            </form>
         )}

         {view !== 'forgot-password' && (
           <div className="mt-6 text-center">
              <button 
                onClick={() => setView(view === 'login' ? 'register' : 'login')} 
                className="text-gray-400 text-sm hover:text-white underline decoration-gaming-accent"
              >
                {view === 'login' ? "Hesabınız yoxdur? Qeydiyyat" : "Artıq hesabınız var? Giriş"}
              </button>
           </div>
         )}

         <div className="mt-4 text-center border-t border-gray-800 pt-4">
             <p className="text-xs text-gray-500">Admin Girişi üçün:</p>
             <p className="text-xs text-gray-600 font-mono">admin@gamepay.az / admin</p>
         </div>
      </div>
    </div>
  );
};

export default Auth;

