import React, { useState } from 'react';
import { useApp } from '../store';
import { useNavigate } from 'react-router-dom';
import { User, Mail, Lock, ArrowRight, Phone, KeyRound, ArrowLeft } from 'lucide-react';

type AuthView = 'login' | 'register' | 'forgot-password';

const Auth = () => {
  const [view, setView] = useState<AuthView>('login');
  const { login, register, requestPasswordReset } = useApp();
  const navigate = useNavigate();

  // Login/Register Form State
  const [formData, setFormData] = useState({
    name: '',
    email: '',
    password: ''
  });

  // Forgot Password Flow State
  const [forgotStep, setForgotStep] = useState<1 | 2>(1); // 1: Phone, 2: Success Message
  const [resetPhone, setResetPhone] = useState('');

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (view === 'login') {
      const success = login(formData.email, formData.password);
      if (success) {
        if(formData.email === 'admin@gamepay.az') {
           navigate('/admin');
        } else {
           navigate('/');
        }
      } else {
        alert("Yanlış email və ya şifrə!");
      }
    } else if (view === 'register') {
      if(formData.name && formData.email && formData.password) {
        register(formData.name, formData.email, formData.password);
        navigate('/');
      }
    }
  };

  const handleForgotSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (forgotStep === 1) {
      if (resetPhone.length < 9) {
        alert("Düzgün mobil nömrə daxil edin.");
        return;
      }

      const success = requestPasswordReset(resetPhone);

      if(success) {
          // Success case - simulates link sent
          setForgotStep(2);
      } else {
          // Phone not found case - still show success message for security, but logic handled in store
          alert("Nömrə tapılmadı və ya xəta baş verdi.");
      }
    }
  };

  return (
    <div className="min-h-screen bg-gaming-dark flex items-center justify-center p-4">
      <div className="w-full max-w-md bg-gaming-card border border-gray-800 rounded-2xl p-8 shadow-2xl relative overflow-hidden">
