  // User Management
  const [resetModalUser, setResetModalUser] = useState<{id: string, name: string} | null>(null);
  const [adminNewPassword, setAdminNewPassword] = useState('');

  // States for Dashboard Date Filter
  const [statsPeriod, setStatsPeriod] = useState<number>(1); // 1 = Today

  // States for Forms
  const [newCatName, setNewCatName] = useState('');

  // Product Form
  const [productForm, setProductForm] = useState<Partial<Product> & { imageFile?: File | null }>({
    title: '', categoryId: '', price: 0, costPrice: 0, discountPercent: 0, type: ProductType.LICENSE_KEY, image: '', description: '', requiresInput: false
  });
  const fileInputRef = useRef<HTMLInputElement>(null);
  const logoInputRef = useRef<HTMLInputElement>(null);
  const heroInputRef = useRef<HTMLInputElement>(null);
  const bulkInputRef = useRef<HTMLInputElement>(null);

  if (!user || user.role !== 'admin') {
    return <div className="p-10 text-center text-red-500 font-bold text-2xl">Access Denied</div>;
  }

  // --- STATS LOGIC ---
  const getFilteredOrders = () => {
    const now = new Date();
    const past = new Date();

    // If statsPeriod is 1 (Today), we need to check only today's date string
    if (statsPeriod === 1) {
       return orders.filter(o => {
         const orderDate = new Date(o.date);
         return orderDate.toDateString() === now.toDateString() && o.status === OrderStatus.COMPLETED;
       });
    }

    past.setDate(now.getDate() - statsPeriod);
    past.setHours(0,0,0,0);

    return orders.filter(o => {
      const orderDate = new Date(o.date);
      return orderDate >= past && o.status === OrderStatus.COMPLETED;
    });
  };

  const filteredOrders = getFilteredOrders();
  const totalRevenue = filteredOrders.reduce((sum, o) => sum + (o.totalPrice || o.price || 0), 0);
  const totalProfit = totalRevenue * 0.2; 

  const getStatusBadge = (status: OrderStatus) => {
    switch (status) {
      case OrderStatus.PENDING: 
        return (
          <span className="flex items-center gap-1 px-2 py-0.5 rounded text-xs font-bold text-yellow-400 bg-yellow-400/10 border border-yellow-400/20">
            <Clock className="w-3 h-3" /> Gözləmədə
          </span>
        );
      case OrderStatus.PROCESSING: 
        return (
          <span className="flex items-center gap-1 px-2 py-0.5 rounded text-xs font-bold text-blue-400 bg-blue-400/10 border border-blue-400/20">
            <Loader2 className="w-3 h-3 animate-spin" /> Emalda
          </span>
        );
      case OrderStatus.COMPLETED: 
        return (
          <span className="flex items-center gap-1 px-2 py-0.5 rounded text-xs font-bold text-green-400 bg-green-400/10 border border-green-400/20">
            <CheckCircle className="w-3 h-3" /> Tamamlandı
          </span>
        );
      case OrderStatus.CANCELLED: 
        return (
          <span className="flex items-center gap-1 px-2 py-0.5 rounded text-xs font-bold text-red-400 bg-red-400/10 border border-red-400/20">
