                <div className="mb-4">
                    <label className="text-xs text-gray-500 mb-1 block">Yeni Şifrə</label>
                    <input 
                        type="text" 
                        className="w-full bg-black border border-gray-600 rounded p-3 text-white"
                        value={adminNewPassword}
                        onChange={(e) => setAdminNewPassword(e.target.value)}
                        placeholder="Yeni şifrə yazın..."
                    />
                </div>

                <div className="flex justify-end gap-3">
                    <button onClick={() => setResetModalUser(null)} className="px-4 py-2 rounded text-gray-400 hover:text-white hover:bg-white/10">Bağla</button>
                    <button onClick={handlePasswordReset} disabled={!adminNewPassword} className={`px-4 py-2 rounded font-bold ${adminNewPassword ? 'bg-green-600 hover:bg-green-500 text-white' : 'bg-gray-700 text-gray-500 cursor-not-allowed'}`}>
                        Yenilə
