export default Admin;

export enum ProductType {
  ID_LOAD = 'ID_LOAD',       
  LICENSE_KEY = 'LICENSE_KEY', 
  ACCOUNT = 'ACCOUNT',
  BALANCE = 'BALANCE' // New type for wallet top-up
}

export enum OrderStatus {
  PENDING = 'PENDING',
  PROCESSING = 'PROCESSING',
  COMPLETED = 'COMPLETED',
  CANCELLED = 'CANCELLED'
}

export interface Category {
  id: string;
  name: string;
  icon?: string;
  seoTitle?: string;
  seoKeywords?: string;
}

export interface Product {
  id: string;
  title: string;
  categoryId: string;
  type: ProductType;
  price: number;        
  costPrice: number;    
  discountPercent: number; 
  image: string;
  description: string;
  requiresInput?: boolean;
  inputLabel?: string;
  seoTitle?: string;
  seoKeywords?: string;
}

export interface CartItem {
  productId: string;
  title: string;
  price: number;
  image: string;
  type: ProductType;
  userInput?: string; // e.g. Player ID
}

export interface Blog {
  id: string;
  title: string;
  content: string;
  date: string;
  image: string;
}

export interface Agreement {
  id: string;
  title: string; 
  content: string;
}

export interface Comment {
  id: string;
  author: string;
  content: string;
  type: 'product' | 'blog' | 'site';
  targetId?: string; 
  isApproved: boolean;
  date: string;
}

export interface PaymentMethod {
  id: string;
  name: string;
  details: string; 
  instructions: string;
  isActive: boolean;
  icon: string;
}

export interface Order {
  id: string;
  userId: string;
  items: CartItem[]; // Support multiple items
  totalPrice: number;
  status: OrderStatus;
  date: string;
  paymentMethodName: string;
  receiptImage?: string; 
  deliveredContent?: string; 
  // Legacy support or fallback
  productTitle?: string;
  productType?: ProductType;
  userInput?: string; 
  productId?: string;
  price?: number;
}

export interface User {
  id: string;
  name: string;
  email: string;
  phone?: string; // Added for password reset flow
  role: 'admin' | 'user';
  balance: number;
  password?: string;
  avatar?: string;
  resetRequested?: boolean; // For admin panel logic
  isBanned?: boolean;
  resetToken?: string; // For manual link generation
}

export interface SocialLinks {
  instagram: string;
  telegram: string;
  tiktok: string;
  whatsapp: string;
}

export interface SiteSettings {
  siteName: string;
  logoUrl: string; // Now can be a blob URL
  heroBannerUrl: string;
  heroTitle: string;
  heroSubtitle: string;
  whatsappNumber: string;
  footerText: string;
  discordWebhook: string;
  seoTitle: string;
  seoDesc: string;
  socials: SocialLinks;
}

import React, { createContext, useContext, useState, ReactNode, useEffect } from 'react';
import { Product, Order, PaymentMethod, User, OrderStatus, ProductType, Category, SiteSettings, Blog, Agreement, Comment, CartItem } from './types';
import { INITIAL_PRODUCTS, INITIAL_PAYMENT_METHODS, MOCK_USERS, INITIAL_CATEGORIES, INITIAL_SETTINGS } from './constants';

interface AppContextType {
  user: User | null; 
  usersList: User[]; // Exposed for Admin
  isAuthenticated: boolean;
  products: Product[];
  categories: Category[];
  orders: Order[];
  paymentMethods: PaymentMethod[];
  siteSettings: SiteSettings;
  blogs: Blog[];
  agreements: Agreement[];
  comments: Comment[];
  cart: CartItem[];

  // Auth
  login: (email: string, pass: string) => boolean;
  register: (name: string, email: string, pass: string) => void;
  logout: () => void;
  updateUserProfile: (data: Partial<User>) => void;
  requestPasswordReset: (phone: string) => boolean;
  adminUpdateUserPassword: (userId: string, newPass: string) => void; // Admin action
  toggleUserBan: (userId: string) => void; // Admin Action
  generateResetLink: (userId: string) => string; // Admin Action
  confirmPasswordReset: (token: string, newPass: string) => boolean; // User Action via Link

  // Cart
  addToCart: (product: Product, userInput?: string) => void;
  removeFromCart: (index: number) => void;
  clearCart: () => void;

  // Order Actions
  placeOrder: (paymentMethodId: string, receiptFile: File) => Promise<boolean>;
  placeBalanceOrder: (amount: number, paymentMethodId: string, receiptFile: File) => Promise<boolean>;
  completeOrder: (orderId: string, deliveredContent: string) => void;
  cancelOrder: (orderId: string) => void;

  // Admin CMS
  addProduct: (product: Product) => void;
  addProducts: (newProducts: Product[]) => void;
  deleteProduct: (productId: string) => void;
  addCategory: (category: Category) => void;
  deleteCategory: (categoryId: string) => void;
  updateSiteSettings: (settings: Partial<SiteSettings>) => void;
  updateUserBalance: (amount: number) => void;
  addPaymentMethod: (method: PaymentMethod) => void;
  updatePaymentMethod: (id: string, details: Partial<PaymentMethod>) => void;

  // CMS
  addBlog: (blog: Blog) => void;
  deleteBlog: (id: string) => void;
  addAgreement: (agreement: Agreement) => void;
  deleteAgreement: (id: string) => void;
  toggleCommentApproval: (id: string) => void;
  deleteComment: (id: string) => void;
}

const AppContext = createContext<AppContextType | undefined>(undefined);

export const AppProvider = ({ children }: { children?: React.ReactNode }) => {
  const [user, setUser] = useState<User | null>(null);
  const [usersList, setUsersList] = useState<User[]>(MOCK_USERS);
  const [products, setProducts] = useState<Product[]>(INITIAL_PRODUCTS);
  const [categories, setCategories] = useState<Category[]>(INITIAL_CATEGORIES);
  const [orders, setOrders] = useState<Order[]>([]);
  const [paymentMethods, setPaymentMethods] = useState<PaymentMethod[]>(INITIAL_PAYMENT_METHODS);
  const [siteSettings, setSiteSettings] = useState<SiteSettings>(INITIAL_SETTINGS);
  const [cart, setCart] = useState<CartItem[]>([]);

  // CMS State
  const [blogs, setBlogs] = useState<Blog[]>([
    { id: 'b1', title: 'PUBG Yeni Sezon Başladı!', content: 'Yeni sezonun gəlişi ilə birlikdə...', date: new Date().toISOString(), image: 'https://images.unsplash.com/photo-1542751371-adc38448a05e' }
  ]);
  const [agreements, setAgreements] = useState<Agreement[]>([
    { id: 'a1', title: 'İstifadəçi Razılaşması', content: 'Saytımızdan istifadə edərkən...' },
    { id: 'a2', title: 'Məxfilik Siyasəti', content: 'Məlumatlarınız qorunur...' }
  ]);
  const [comments, setComments] = useState<Comment[]>([
    { id: 'c1', author: 'Elvin M.', content: 'Çox sürətli gəldi, təşəkkürlər!', type: 'product', targetId: 'p1', isApproved: true, date: new Date().toISOString() },
    { id: 'c2', author: 'Anonim', content: 'Gözləyirəm hələ...', type: 'site', isApproved: false, date: new Date().toISOString() }
  ]);

  const login = (email: string, pass: string) => {
    // Check against current state usersList, not just initial mock
    const foundUser = usersList.find(u => u.email === email && u.password === pass);
    if (foundUser) {
      if (foundUser.isBanned) {
        alert("Hesabınız bloklanıb. Zəhmət olmasa dəstək xidməti ilə əlaqə saxlayın.");
        return false;
      }
      setUser(foundUser);
      return true;
    }
    return false;
  };

  const register = (name: string, email: string, pass: string) => {
    const newUser: User = {
      id: `u-${Date.now()}`,
      name,
      email,
      role: 'user',
      balance: 0,
      password: pass,
      isBanned: false
    };
    setUsersList(prev => [...prev, newUser]);
    setUser(newUser);
  };

  const updateUserProfile = (data: Partial<User>) => {
    if (!user) return;
    const updatedUser = { ...user, ...data };

    // Update local session
    setUser(updatedUser);

    // Update master list
    setUsersList(prev => prev.map(u => u.id === user.id ? updatedUser : u));
  };

  const requestPasswordReset = (phone: string) => {
    // 1. Check if user exists with this phone
    const exists = usersList.find(u => u.phone === phone);

    if (exists) {
      // Flag the user for admin attention
      setUsersList(prev => prev.map(u => u.phone === phone ? { ...u, resetRequested: true } : u));
      return true; // Phone found
    }

    return false; // Phone not found
  };

  const generateResetLink = (userId: string) => {
      // Simple mock token generation
      const token = Math.random().toString(36).substring(2, 15) + Math.random().toString(36).substring(2, 15);

      setUsersList(prev => prev.map(u => u.id === userId ? { ...u, resetToken: token } : u));

      // In a real app this would be a full domain, here we use hash routing
      return `${window.location.origin}/#/auth?token=${token}`;
  };

  const confirmPasswordReset = (token: string, newPass: string) => {
      const userWithToken = usersList.find(u => u.resetToken === token);
      if(!userWithToken) return false;

      setUsersList(prev => prev.map(u => u.id === userWithToken.id ? { 
          ...u, 
          password: newPass, 
          resetToken: undefined, // Clear token
          resetRequested: false // Clear flag if it existed
      } : u));

      return true;
  };

  const adminUpdateUserPassword = (userId: string, newPass: string) => {
    setUsersList(prev => prev.map(u => u.id === userId ? { ...u, password: newPass, resetRequested: false } : u));
  };

  const toggleUserBan = (userId: string) => {
    setUsersList(prev => prev.map(u => u.id === userId ? { ...u, isBanned: !u.isBanned } : u));
  };

  const logout = () => {
    setUser(null);
    setCart([]);
  };

  const updateUserBalance = (amount: number) => {
    if(user) {
        const newBalance = user.balance + amount;
        const updatedUser = { ...user, balance: newBalance };
        setUser(updatedUser);
        setUsersList(prev => prev.map(u => u.id === user.id ? updatedUser : u));
    }
  };

  // --- CART LOGIC ---
  const addToCart = (product: Product, userInput?: string) => {
    const finalPrice = product.price - (product.price * (product.discountPercent / 100));
    setCart(prev => [...prev, {
      productId: product.id,
      title: product.title,
      price: finalPrice,
      image: product.image,
      type: product.type,
      userInput
    }]);
  };

  const removeFromCart = (index: number) => {
    setCart(prev => prev.filter((_, i) => i !== index));
  };

  const clearCart = () => setCart([]);

  // --- ORDER LOGIC ---

  // Regular Cart Checkout
  const placeOrder = async (paymentMethodId: string, receiptFile: File): Promise<boolean> => {
    if (!user || cart.length === 0) return false;
    const method = paymentMethods.find(p => p.id === paymentMethodId);
    if (!method) return false;

    const receiptUrl = URL.createObjectURL(receiptFile);
    const totalPrice = cart.reduce((sum, item) => sum + item.price, 0);

    const newOrder: Order = {
      id: `ord-${Date.now()}`,
      userId: user.id,
      items: [...cart],
      totalPrice: totalPrice,
      status: OrderStatus.PENDING,
      date: new Date().toISOString(),
      paymentMethodName: method.name,
      receiptImage: receiptUrl,
      // Fallback fields for legacy compatibility
      productTitle: cart.length > 1 ? `${cart.length} Məhsul` : cart[0].title,
      productId: 'cart-checkout',
      price: totalPrice,
      productType: ProductType.LICENSE_KEY
    };

    setOrders(prev => [newOrder, ...prev]);
    clearCart();
    return true;
  };

  // Balance Top-Up Request
  const placeBalanceOrder = async (amount: number, paymentMethodId: string, receiptFile: File): Promise<boolean> => {
    if (!user) return false;
    const method = paymentMethods.find(p => p.id === paymentMethodId);
    if (!method) return false;
    const receiptUrl = URL.createObjectURL(receiptFile);

    const newOrder: Order = {
      id: `bal-${Date.now()}`,
      userId: user.id,
      items: [{
        productId: 'balance-topup',
        title: 'Balans Artımı',
        price: amount,
        image: 'https://via.placeholder.com/150',
        type: ProductType.BALANCE
      }],
      totalPrice: amount,
      status: OrderStatus.PENDING,
      date: new Date().toISOString(),
      paymentMethodName: method.name,
      receiptImage: receiptUrl,
      productTitle: 'Balans Artımı',
      productType: ProductType.BALANCE,
      price: amount
    };

    setOrders(prev => [newOrder, ...prev]);
    return true;
  };

  const completeOrder = (orderId: string, deliveredContent: string) => {
    setOrders(prev => prev.map(order => {
      if (order.id !== orderId) return order;

      // Auto-update balance if it's a balance order
      if (order.items[0]?.type === ProductType.BALANCE) {
         updateUserBalance(order.totalPrice);
      }

      return { 
        ...order, 
        status: OrderStatus.COMPLETED,
        deliveredContent: deliveredContent 
      };
    }));
  };

  const cancelOrder = (orderId: string) => {
    setOrders(prev => prev.map(order => order.id === orderId ? { ...order, status: OrderStatus.CANCELLED } : order));
  };

  // --- CMS Actions ---
  const addProduct = (product: Product) => setProducts(prev => [...prev, product]);
  const addProducts = (newProducts: Product[]) => setProducts(prev => [...prev, ...newProducts]);
  const deleteProduct = (productId: string) => setProducts(prev => prev.filter(p => p.id !== productId));
  const addCategory = (category: Category) => setCategories(prev => [...prev, category]);
  const deleteCategory = (categoryId: string) => setCategories(prev => prev.filter(c => c.id !== categoryId));
  const updateSiteSettings = (settings: Partial<SiteSettings>) => setSiteSettings(prev => ({ ...prev, ...settings }));
  const addPaymentMethod = (method: PaymentMethod) => setPaymentMethods(prev => [...prev, method]);
  const updatePaymentMethod = (id: string, details: Partial<PaymentMethod>) => setPaymentMethods(prev => prev.map(pm => pm.id === id ? { ...pm, ...details } : pm));

  const addBlog = (blog: Blog) => setBlogs(prev => [...prev, blog]);
  const deleteBlog = (id: string) => setBlogs(prev => prev.filter(b => b.id !== id));
  const addAgreement = (agreement: Agreement) => setAgreements(prev => [...prev, agreement]);
  const deleteAgreement = (id: string) => setAgreements(prev => prev.filter(a => a.id !== id));
  const toggleCommentApproval = (id: string) => setComments(prev => prev.map(c => c.id === id ? {...c, isApproved: !c.isApproved} : c));
  const deleteComment = (id: string) => setComments(prev => prev.filter(c => c.id !== id));

  return (
    <AppContext.Provider value={{ 
      user, usersList, isAuthenticated: !!user,
      products, categories, orders, paymentMethods, siteSettings, cart,
      blogs, agreements, comments,
      login, register, logout, requestPasswordReset, updateUserProfile, adminUpdateUserPassword, toggleUserBan, generateResetLink, confirmPasswordReset,
      addToCart, removeFromCart, clearCart,
      placeOrder, placeBalanceOrder, completeOrder, cancelOrder, updateUserBalance,
      addPaymentMethod, updatePaymentMethod,
      addProduct, addProducts, deleteProduct, addCategory, deleteCategory, updateSiteSettings,
      addBlog, deleteBlog, addAgreement, deleteAgreement, toggleCommentApproval, deleteComment
    }}>
      {children}
    </AppContext.Provider>
  );
};

export const useApp = () => {
  const context = useContext(AppContext);
  if (!context) throw new Error("useApp must be used within AppProvider");
  return context;
};

