export default Admin;

import React, { useState, useEffect } from 'react';
import { useApp } from '../store';
import { useNavigate, useLocation } from 'react-router-dom';
import { User, Mail, Lock, ArrowRight, Phone, KeyRound, ArrowLeft, CheckCircle } from 'lucide-react';

type AuthView = 'login' | 'register' | 'forgot-password' | 'reset-confirm';

const Auth = () => {
  const [view, setView] = useState<AuthView>('login');
  const { login, register, requestPasswordReset, confirmPasswordReset } = useApp();
  const navigate = useNavigate();
  const location = useLocation();

  // Login/Register Form State
  const [formData, setFormData] = useState({
    name: '',
    email: '',
    password: ''
  });

  // Forgot Password Flow State
  const [forgotStep, setForgotStep] = useState<1 | 2>(1); // 1: Phone, 2: Success Message
  const [resetPhone, setResetPhone] = useState('');

  // Reset Confirm State
  const [resetToken, setResetToken] = useState<string | null>(null);
  const [newPassword, setNewPassword] = useState('');

  useEffect(() => {
      // Check for reset token in URL
      const searchParams = new URLSearchParams(location.search);
      const token = searchParams.get('token');
      if (token) {
          setResetToken(token);
          setView('reset-confirm');
      }
  }, [location]);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (view === 'login') {
      const success = login(formData.email, formData.password);
      if (success) {
        if(formData.email === 'admin@gamepay.az') {
           navigate('/admin');
        } else {
           navigate('/');
        }
      } else {
        alert("Yanlış email və ya şifrə!");
      }
    } else if (view === 'register') {
      if(formData.name && formData.email && formData.password) {
        register(formData.name, formData.email, formData.password);
        navigate('/');
      }
    }
  };

  const handleForgotSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (forgotStep === 1) {
      if (resetPhone.length < 9) {
        alert("Düzgün mobil nömrə daxil edin.");
        return;
      }

      const success = requestPasswordReset(resetPhone);

      if(success) {
          // Success case - simulates link sent
          setForgotStep(2);
      } else {
          // Phone not found case - still show success message for security, but logic handled in store
          alert("Nömrə tapılmadı və ya xəta baş verdi.");
      }
    }
  };

  const handleResetConfirm = (e: React.FormEvent) => {
      e.preventDefault();
      if(resetToken && newPassword.length >= 6) {
          const success = confirmPasswordReset(resetToken, newPassword);
          if(success) {
              alert("Şifrə uğurla yeniləndi! İndi giriş edə bilərsiniz.");
              setView('login');
              setNewPassword('');
              setResetToken(null);
              navigate('/auth'); // Clear token from URL
          } else {
              alert("Link etibarsızdır və ya istifadə olunub.");
          }
      } else {
          alert("Şifrə ən az 6 simvol olmalıdır.");
      }
  };

  return (
    <div className="min-h-screen bg-gaming-dark flex items-center justify-center p-4">
      <div className="w-full max-w-md bg-gaming-card border border-gray-800 rounded-2xl p-8 shadow-2xl relative overflow-hidden">
         {/* Background Glow */}
         <div className="absolute top-0 left-0 w-full h-2 bg-gradient-to-r from-gaming-neon to-gaming-accent"></div>

         <div className="text-center mb-8">
           <h1 className="text-3xl font-black text-white mb-2">
             {view === 'login' ? 'Xoş Gəldiniz' : view === 'register' ? 'Qeydiyyat' : view === 'reset-confirm' ? 'Yeni Şifrə' : 'Şifrəni Yenilə'}
           </h1>
           <p className="text-gray-400 text-sm">GamePay dünyasına daxil olun</p>
         </div>

         {view === 'reset-confirm' ? (
             <form onSubmit={handleResetConfirm} className="space-y-4 animate-fade-in">
                 <div className="relative">
                      <label className="text-xs text-gray-500 ml-1 mb-1 block">Yeni Şifrəniz</label>
                      <Lock className="absolute left-3 top-8 text-gray-500 w-5 h-5" />
                      <input 
                        type="password" 
                        placeholder="Yeni şifrə daxil edin" 
                        className="w-full bg-slate-900 border border-gray-700 rounded-lg py-3 pl-10 pr-4 text-white focus:border-gaming-neon outline-none"
                        value={newPassword}
                        onChange={e => setNewPassword(e.target.value)}
                      />
                  </div>
                  <button type="submit" className="w-full bg-green-600 hover:bg-green-700 text-white font-bold py-3 rounded-lg flex items-center justify-center gap-2 transition-transform active:scale-95">
                       <CheckCircle className="w-4 h-4" /> Şifrəni Yenilə
                  </button>
             </form>
         ) : view === 'forgot-password' ? (
             <div className="space-y-4">
                {forgotStep === 1 ? (
                    <form onSubmit={handleForgotSubmit} className="space-y-4">
                        <div className="relative animate-fade-in">
                            <label className="text-xs text-gray-500 ml-1 mb-1 block">Mobil Nömrə</label>
                            <Phone className="absolute left-3 top-8 text-gray-500 w-5 h-5" />
                            <input 
                                type="tel" 
                                placeholder="+994 50 123 45 67" 
                                className="w-full bg-slate-900 border border-gray-700 rounded-lg py-3 pl-10 pr-4 text-white focus:border-gaming-neon outline-none"
                                value={resetPhone}
                                onChange={e => setResetPhone(e.target.value)}
                            />
                            <p className="text-xs text-gray-500 mt-2">Şifrə yeniləmə linki bu nömrəyə göndəriləcək.</p>
                        </div>
                        <button type="submit" className="w-full bg-gaming-neon hover:bg-cyan-400 text-black font-bold py-3 rounded-lg flex items-center justify-center gap-2 transition-transform active:scale-95">
                           Linki Göndər <ArrowRight className="w-4 h-4" />
                        </button>
                    </form>
                ) : (
                    <div className="text-center py-6 animate-fade-in">
                        <div className="w-16 h-16 bg-green-500/20 text-green-500 rounded-full flex items-center justify-center mx-auto mb-4">
                            <Mail className="w-8 h-8"/>
                        </div>
                        <h3 className="text-xl font-bold text-white mb-2">Link Göndərildi!</h3>
                        <p className="text-gray-400 text-sm mb-6">
                            Şifrə yeniləmə linki SMS vasitəsilə <b>{resetPhone}</b> nömrəsinə göndərildi. 
                            <br/><br/>
                            <span className="text-xs text-gray-500">Əgər link gəlmədisə və ya xəta baş verdisə, Admin panelindən hesabınız bərpa olunacaq.</span>
                        </p>
                        <button onClick={() => setView('login')} className="bg-slate-800 text-white px-6 py-2 rounded-lg hover:bg-slate-700">
                            Girişə Qayıt
                        </button>
                    </div>
                )}

                {forgotStep === 1 && (
                    <button type="button" onClick={() => setView('login')} className="w-full text-gray-400 text-sm hover:text-white mt-2 flex items-center justify-center gap-1">
                    <ArrowLeft className="w-3 h-3"/> Geri Qayıt
                    </button>
                )}
             </div>
         ) : (
            <form onSubmit={handleSubmit} className="space-y-4">
                {view === 'register' && (
                  <div className="relative">
                    <User className="absolute left-3 top-3.5 text-gray-500 w-5 h-5" />
                    <input 
                      type="text" 
                      placeholder="Ad Soyad" 
                      className="w-full bg-slate-900 border border-gray-700 rounded-lg py-3 pl-10 pr-4 text-white focus:border-gaming-neon outline-none"
                      value={formData.name}
                      onChange={e => setFormData({...formData, name: e.target.value})}
                    />
                  </div>
                )}
                <div className="relative">
                    <Mail className="absolute left-3 top-3.5 text-gray-500 w-5 h-5" />
                    <input 
                      type="email" 
                      placeholder="Email ünvanı" 
                      className="w-full bg-slate-900 border border-gray-700 rounded-lg py-3 pl-10 pr-4 text-white focus:border-gaming-neon outline-none"
                      value={formData.email}
                      onChange={e => setFormData({...formData, email: e.target.value})}
                    />
                </div>
                <div className="relative">
                    <Lock className="absolute left-3 top-3.5 text-gray-500 w-5 h-5" />
                    <input 
                      type="password" 
                      placeholder="Şifrə" 
                      className="w-full bg-slate-900 border border-gray-700 rounded-lg py-3 pl-10 pr-4 text-white focus:border-gaming-neon outline-none"
                      value={formData.password}
                      onChange={e => setFormData({...formData, password: e.target.value})}
                    />
                </div>

                {view === 'login' && (
                  <div className="flex justify-end">
                    <button type="button" onClick={() => { setView('forgot-password'); setForgotStep(1); setResetPhone(''); }} className="text-xs text-gaming-neon hover:underline">
                      Şifrəni unutmusunuz?
                    </button>
                  </div>
                )}

                <button type="submit" className="w-full bg-gaming-neon hover:bg-cyan-400 text-black font-bold py-3 rounded-lg flex items-center justify-center gap-2 transition-transform active:scale-95">
                  {view === 'login' ? 'Daxil Ol' : 'Qeydiyyatdan Keç'} <ArrowRight className="w-4 h-4" />
                </button>
            </form>
         )}

         {view !== 'forgot-password' && view !== 'reset-confirm' && (
           <div className="mt-6 text-center">
              <button 
                onClick={() => setView(view === 'login' ? 'register' : 'login')} 
                className="text-gray-400 text-sm hover:text-white underline decoration-gaming-accent"
              >
                {view === 'login' ? "Hesabınız yoxdur? Qeydiyyat" : "Artıq hesabınız var? Giriş"}
              </button>
           </div>
         )}

         <div className="mt-4 text-center border-t border-gray-800 pt-4">
             <p className="text-xs text-gray-500">Admin Girişi üçün:</p>
             <p className="text-xs text-gray-600 font-mono">admin@gamepay.az / admin</p>
         </div>
      </div>
    </div>
  );
};

export default Auth;

export enum ProductType {
  ID_LOAD = 'ID_LOAD',       
  LICENSE_KEY = 'LICENSE_KEY', 
  ACCOUNT = 'ACCOUNT',
  BALANCE = 'BALANCE' // New type for wallet top-up
}

export enum OrderStatus {
  PENDING = 'PENDING',
  PROCESSING = 'PROCESSING',
  COMPLETED = 'COMPLETED',
  CANCELLED = 'CANCELLED'
}

export interface Category {
  id: string;
  name: string;
  icon?: string;
  seoTitle?: string;
  seoKeywords?: string;
}

export interface Product {
  id: string;
  title: string;
  categoryId: string;
  type: ProductType;
  price: number;        
  costPrice: number;    
  discountPercent: number; 
  image: string;
  description: string;
  requiresInput?: boolean;
  inputLabel?: string;
  seoTitle?: string;
  seoKeywords?: string;
}

export interface CartItem {
  productId: string;
  title: string;
  price: number;
  image: string;
  type: ProductType;
  userInput?: string; // e.g. Player ID
  quantity: number; // Added quantity
}

export interface Blog {
  id: string;
  title: string;
  content: string;
  date: string;
  image: string;
}

export interface Agreement {
  id: string;
  title: string; 
  content: string;
}

export interface Comment {
  id: string;
  author: string;
  content: string;
  type: 'product' | 'blog' | 'site';
  targetId?: string; 
  isApproved: boolean;
  date: string;
}

export interface PaymentMethod {
  id: string;
  name: string;
  details: string; 
  instructions: string;
  isActive: boolean;
  icon: string;
}

export interface Order {
  id: string;
  userId: string;
  items: CartItem[]; // Support multiple items
  totalPrice: number;
  discountApplied?: number; // Track promo code discount
  status: OrderStatus;
  date: string;
  paymentMethodName: string;
  receiptImage?: string; 
  deliveredContent?: string; 
  // Legacy support or fallback
  productTitle?: string;
  productType?: ProductType;
  userInput?: string; 
  productId?: string;
  price?: number;
}

export interface User {
  id: string;
  name: string;
  email: string;
  phone: string; // Made mandatory
  role: 'admin' | 'user';
  balance: number;
  password?: string;
  avatar?: string;
  resetRequested?: boolean; // For admin panel logic
  isBanned?: boolean;
  resetToken?: string; // For manual link generation
}

export interface SocialLinks {
  instagram: string;
  telegram: string;
  tiktok: string;
  whatsapp: string;
}

export interface SiteSettings {
  siteName: string;
  logoUrl: string; // Now can be a blob URL
  heroBannerUrl: string;
  heroTitle: string;
  heroSubtitle: string;
  whatsappNumber: string;
  footerText: string;
  discordWebhook: string;
  seoTitle: string;
  seoDesc: string;
  socials: SocialLinks;
}

export interface PromoCode {
  code: string;
  discountPercent: number;
}

import React, { createContext, useContext, useState, ReactNode, useEffect } from 'react';
import { Product, Order, PaymentMethod, User, OrderStatus, ProductType, Category, SiteSettings, Blog, Agreement, Comment, CartItem } from './types';
import { INITIAL_PRODUCTS, INITIAL_PAYMENT_METHODS, MOCK_USERS, INITIAL_CATEGORIES, INITIAL_SETTINGS } from './constants';

interface AppContextType {
  user: User | null; 
  usersList: User[]; // Exposed for Admin
  isAuthenticated: boolean;
  products: Product[];
  categories: Category[];
  orders: Order[];
  paymentMethods: PaymentMethod[];
  siteSettings: SiteSettings;
  blogs: Blog[];
  agreements: Agreement[];
  comments: Comment[];
  cart: CartItem[];

  // Auth
  login: (email: string, pass: string) => boolean;
  register: (name: string, email: string, phone: string, pass: string) => void;
  logout: () => void;
  updateUserProfile: (data: Partial<User>) => void;
  changePassword: (currentPass: string, newPass: string) => boolean;
  requestPasswordReset: (phone: string) => boolean;
  adminUpdateUserPassword: (userId: string, newPass: string) => void; // Admin action
  toggleUserBan: (userId: string) => void; // Admin Action
  generateResetLink: (userId: string) => string; // Admin Action
  confirmPasswordReset: (token: string, newPass: string) => boolean; // User Action via Link

  // Cart
  addToCart: (product: Product, userInput?: string) => void;
  updateCartQuantity: (index: number, delta: number) => void;
  removeFromCart: (index: number) => void;
  clearCart: () => void;

  // Order Actions
  placeOrder: (paymentMethodId: string | 'BALANCE', receiptFile?: File, promoDiscount?: number) => Promise<boolean>;
  placeBalanceOrder: (amount: number, paymentMethodId: string, receiptFile: File) => Promise<boolean>;
  completeOrder: (orderId: string, deliveredContent: string) => void;
  cancelOrder: (orderId: string) => void;

  // Admin CMS
  addProduct: (product: Product) => void;
  addProducts: (newProducts: Product[]) => void;
  deleteProduct: (productId: string) => void;
  addCategory: (category: Category) => void;
  deleteCategory: (categoryId: string) => void;
  updateSiteSettings: (settings: Partial<SiteSettings>) => void;
  updateUserBalance: (amount: number) => void;
  addPaymentMethod: (method: PaymentMethod) => void;
  updatePaymentMethod: (id: string, details: Partial<PaymentMethod>) => void;

  // CMS
  addBlog: (blog: Blog) => void;
  deleteBlog: (id: string) => void;
  addAgreement: (agreement: Agreement) => void;
  deleteAgreement: (id: string) => void;
  toggleCommentApproval: (id: string) => void;
  deleteComment: (id: string) => void;
}

const AppContext = createContext<AppContextType | undefined>(undefined);

export const AppProvider = ({ children }: { children?: React.ReactNode }) => {
  const [user, setUser] = useState<User | null>(null);
  const [usersList, setUsersList] = useState<User[]>(MOCK_USERS);
  const [products, setProducts] = useState<Product[]>(INITIAL_PRODUCTS);
  const [categories, setCategories] = useState<Category[]>(INITIAL_CATEGORIES);
  const [orders, setOrders] = useState<Order[]>([]);
  const [paymentMethods, setPaymentMethods] = useState<PaymentMethod[]>(INITIAL_PAYMENT_METHODS);
  const [siteSettings, setSiteSettings] = useState<SiteSettings>(INITIAL_SETTINGS);
  const [cart, setCart] = useState<CartItem[]>([]);

  // CMS State
  const [blogs, setBlogs] = useState<Blog[]>([
    { id: 'b1', title: 'PUBG Yeni Sezon Başladı!', content: 'Yeni sezonun gəlişi ilə birlikdə...', date: new Date().toISOString(), image: 'https://images.unsplash.com/photo-1542751371-adc38448a05e' }
  ]);
  const [agreements, setAgreements] = useState<Agreement[]>([
    { id: 'a1', title: 'İstifadəçi Razılaşması', content: 'Saytımızdan istifadə edərkən...' },
    { id: 'a2', title: 'Məxfilik Siyasəti', content: 'Məlumatlarınız qorunur...' }
  ]);
  const [comments, setComments] = useState<Comment[]>([
    { id: 'c1', author: 'Elvin M.', content: 'Çox sürətli gəldi, təşəkkürlər!', type: 'product', targetId: 'p1', isApproved: true, date: new Date().toISOString() },
    { id: 'c2', author: 'Anonim', content: 'Gözləyirəm hələ...', type: 'site', isApproved: false, date: new Date().toISOString() }
  ]);

  const login = (email: string, pass: string) => {
    // Check against current state usersList
    const foundUser = usersList.find(u => u.email === email && u.password === pass);
    if (foundUser) {
      if (foundUser.isBanned) {
        alert("Hesabınız bloklanıb. Zəhmət olmasa dəstək xidməti ilə əlaqə saxlayın.");
        return false;
      }
      setUser(foundUser);
      return true;
    }
    return false;
  };

  const register = (name: string, email: string, phone: string, pass: string) => {
    const newUser: User = {
      id: `u-${Date.now()}`,
      name,
      email,
      phone,
      role: 'user',
      balance: 0,
      password: pass,
      isBanned: false
    };
    setUsersList(prev => [...prev, newUser]);
    setUser(newUser);
  };

  const updateUserProfile = (data: Partial<User>) => {
    if (!user) return;
    const updatedUser = { ...user, ...data };
    setUser(updatedUser);
    setUsersList(prev => prev.map(u => u.id === user.id ? updatedUser : u));
  };

  const changePassword = (currentPass: string, newPass: string) => {
      if(!user) return false;
      if(user.password !== currentPass) return false;

      const updatedUser = { ...user, password: newPass };
      setUser(updatedUser);
      setUsersList(prev => prev.map(u => u.id === user.id ? updatedUser : u));
      return true;
  };

  const requestPasswordReset = (phone: string) => {
    const exists = usersList.find(u => u.phone === phone);
    if (exists) {
      setUsersList(prev => prev.map(u => u.phone === phone ? { ...u, resetRequested: true } : u));
      return true; 
    }
    return false;
  };

  const generateResetLink = (userId: string) => {
      const token = Math.random().toString(36).substring(2, 15) + Math.random().toString(36).substring(2, 15);
      setUsersList(prev => prev.map(u => u.id === userId ? { ...u, resetToken: token } : u));
      return `${window.location.origin}/#/auth?token=${token}`;
  };

  const confirmPasswordReset = (token: string, newPass: string) => {
      const userWithToken = usersList.find(u => u.resetToken === token);
      if(!userWithToken) return false;

      setUsersList(prev => prev.map(u => u.id === userWithToken.id ? { 
          ...u, 
          password: newPass, 
          resetToken: undefined, // Clear token
          resetRequested: false // Clear flag
      } : u));
      return true;
  };

  const adminUpdateUserPassword = (userId: string, newPass: string) => {
    setUsersList(prev => prev.map(u => u.id === userId ? { ...u, password: newPass, resetRequested: false } : u));
  };

  const toggleUserBan = (userId: string) => {
    setUsersList(prev => prev.map(u => u.id === userId ? { ...u, isBanned: !u.isBanned } : u));
  };

  const logout = () => {
    setUser(null);
    setCart([]);
  };

  const updateUserBalance = (amount: number) => {
    if(user) {
        const newBalance = user.balance + amount;
        const updatedUser = { ...user, balance: newBalance };
        setUser(updatedUser);
        setUsersList(prev => prev.map(u => u.id === user.id ? updatedUser : u));
    }
  };

  // --- CART LOGIC ---
  const addToCart = (product: Product, userInput?: string) => {
    const finalPrice = product.price - (product.price * (product.discountPercent / 100));

    setCart(prev => {
        // Check if item exists (same product and same user input if applicable)
        const existingIndex = prev.findIndex(item => item.productId === product.id && item.userInput === userInput);

        if (existingIndex > -1) {
            const newCart = [...prev];
            newCart[existingIndex].quantity += 1;
            return newCart;
        } else {
            return [...prev, {
                productId: product.id,
                title: product.title,
                price: finalPrice,
                image: product.image,
                type: product.type,
                userInput,
                quantity: 1
            }];
        }
    });
  };

  const updateCartQuantity = (index: number, delta: number) => {
      setCart(prev => {
          const newCart = [...prev];
          const item = newCart[index];
          const newQty = item.quantity + delta;

          if (newQty <= 0) {
              return prev.filter((_, i) => i !== index);
          }

          item.quantity = newQty;
          return newCart;
      });
  };

  const removeFromCart = (index: number) => {
    setCart(prev => prev.filter((_, i) => i !== index));
  };

  const clearCart = () => setCart([]);

  // --- ORDER LOGIC ---

  const placeOrder = async (paymentMethodId: string | 'BALANCE', receiptFile?: File, promoDiscount: number = 0): Promise<boolean> => {
    if (!user || cart.length === 0) return false;

    const subTotal = cart.reduce((sum, item) => sum + (item.price * item.quantity), 0);
    const totalPrice = subTotal - promoDiscount;

    // Logic for Wallet Balance Payment
    if (paymentMethodId === 'BALANCE') {
        if (user.balance < totalPrice) {
            alert("Balansınızda kifayət qədər vəsait yoxdur.");
            return false;
        }

        // Deduct balance
        updateUserBalance(-totalPrice);

        // Create Order as Completed or Processing (Instant)
        const newOrder: Order = {
            id: `ord-${Date.now()}`,
            userId: user.id,
            items: [...cart],
            totalPrice: totalPrice,
            discountApplied: promoDiscount,
            status: OrderStatus.PROCESSING, // Balance orders are typically automated or instant
            date: new Date().toISOString(),
            paymentMethodName: 'Wallet Balance',
            // Fallback fields
            productTitle: cart.length > 1 ? `${cart.length} Məhsul` : cart[0].title,
            productId: 'cart-checkout',
            price: totalPrice,
            productType: ProductType.LICENSE_KEY
        };
        setOrders(prev => [newOrder, ...prev]);
        clearCart();
        return true;
    }

    // Logic for Manual Payment (Receipt)
    const method = paymentMethods.find(p => p.id === paymentMethodId);
    if (!method || !receiptFile) return false;

    const receiptUrl = URL.createObjectURL(receiptFile);

    const newOrder: Order = {
      id: `ord-${Date.now()}`,
      userId: user.id,
      items: [...cart],
      totalPrice: totalPrice,
      discountApplied: promoDiscount,
      status: OrderStatus.PENDING,
      date: new Date().toISOString(),
      paymentMethodName: method.name,
      receiptImage: receiptUrl,
      // Fallback fields
      productTitle: cart.length > 1 ? `${cart.length} Məhsul` : cart[0].title,
      productId: 'cart-checkout',
      price: totalPrice,
      productType: ProductType.LICENSE_KEY
    };

    setOrders(prev => [newOrder, ...prev]);
    clearCart();
    return true;
  };

  const placeBalanceOrder = async (amount: number, paymentMethodId: string, receiptFile: File): Promise<boolean> => {
    if (!user) return false;
    const method = paymentMethods.find(p => p.id === paymentMethodId);
    if (!method) return false;
    const receiptUrl = URL.createObjectURL(receiptFile);

    const newOrder: Order = {
      id: `bal-${Date.now()}`,
      userId: user.id,
      items: [{
        productId: 'balance-topup',
        title: 'Balans Artımı',
        price: amount,
        image: 'https://via.placeholder.com/150',
        type: ProductType.BALANCE,
        quantity: 1
      }],
      totalPrice: amount,
      status: OrderStatus.PENDING,
      date: new Date().toISOString(),
      paymentMethodName: method.name,
      receiptImage: receiptUrl,
      productTitle: 'Balans Artımı',
      productType: ProductType.BALANCE,
      price: amount
    };

    setOrders(prev => [newOrder, ...prev]);
    return true;
  };

  const completeOrder = (orderId: string, deliveredContent: string) => {
    setOrders(prev => prev.map(order => {
      if (order.id !== orderId) return order;

      // Auto-update balance if it's a balance order
      if (order.items[0]?.type === ProductType.BALANCE) {
         updateUserBalance(order.totalPrice);
      }

      return { 
        ...order, 
        status: OrderStatus.COMPLETED,
        deliveredContent: deliveredContent 
      };
    }));
  };

  const cancelOrder = (orderId: string) => {
    setOrders(prev => prev.map(order => order.id === orderId ? { ...order, status: OrderStatus.CANCELLED } : order));
  };

  // --- CMS Actions ---
  const addProduct = (product: Product) => setProducts(prev => [...prev, product]);
  const addProducts = (newProducts: Product[]) => setProducts(prev => [...prev, ...newProducts]);
  const deleteProduct = (productId: string) => setProducts(prev => prev.filter(p => p.id !== productId));
  const addCategory = (category: Category) => setCategories(prev => [...prev, category]);
  const deleteCategory = (categoryId: string) => setCategories(prev => prev.filter(c => c.id !== categoryId));
  const updateSiteSettings = (settings: Partial<SiteSettings>) => setSiteSettings(prev => ({ ...prev, ...settings }));
  const addPaymentMethod = (method: PaymentMethod) => setPaymentMethods(prev => [...prev, method]);
  const updatePaymentMethod = (id: string, details: Partial<PaymentMethod>) => setPaymentMethods(prev => prev.map(pm => pm.id === id ? { ...pm, ...details } : pm));

  const addBlog = (blog: Blog) => setBlogs(prev => [...prev, blog]);
  const deleteBlog = (id: string) => setBlogs(prev => prev.filter(b => b.id !== id));
  const addAgreement = (agreement: Agreement) => setAgreements(prev => [...prev, agreement]);
  const deleteAgreement = (id: string) => setAgreements(prev => prev.filter(a => a.id !== id));
  const toggleCommentApproval = (id: string) => setComments(prev => prev.map(c => c.id === id ? {...c, isApproved: !c.isApproved} : c));
  const deleteComment = (id: string) => setComments(prev => prev.filter(c => c.id !== id));

  return (
    <AppContext.Provider value={{ 
      user, usersList, isAuthenticated: !!user,
      products, categories, orders, paymentMethods, siteSettings, cart,
      blogs, agreements, comments,
      login, register, logout, requestPasswordReset, updateUserProfile, adminUpdateUserPassword, toggleUserBan, generateResetLink, confirmPasswordReset, changePassword,
      addToCart, updateCartQuantity, removeFromCart, clearCart,
      placeOrder, placeBalanceOrder, completeOrder, cancelOrder, updateUserBalance,
      addPaymentMethod, updatePaymentMethod,
      addProduct, addProducts, deleteProduct, addCategory, deleteCategory, updateSiteSettings,
      addBlog, deleteBlog, addAgreement, deleteAgreement, toggleCommentApproval, deleteComment
    }}>
      {children}
    </AppContext.Provider>
  );
};

export const useApp = () => {
  const context = useContext(AppContext);
  if (!context) throw new Error("useApp must be used within AppProvider");
  return context;
};

import React, { useState, useEffect } from 'react';
import { useApp } from '../store';
import { useNavigate, useLocation } from 'react-router-dom';
import { User, Mail, Lock, ArrowRight, Phone, KeyRound, ArrowLeft, CheckCircle } from 'lucide-react';

type AuthView = 'login' | 'register' | 'forgot-password' | 'reset-confirm';

const Auth = () => {
  const [view, setView] = useState<AuthView>('login');
  const { login, register, requestPasswordReset, confirmPasswordReset } = useApp();
  const navigate = useNavigate();
  const location = useLocation();

  // Login/Register Form State
  const [formData, setFormData] = useState({
    name: '',
    email: '',
    phone: '',
    password: ''
  });

  // Forgot Password Flow State
  const [forgotStep, setForgotStep] = useState<1 | 2>(1); // 1: Phone, 2: Success Message
  const [resetPhone, setResetPhone] = useState('');

  // Reset Confirm State
  const [resetToken, setResetToken] = useState<string | null>(null);
  const [newPassword, setNewPassword] = useState('');

  useEffect(() => {
      // Check for reset token in URL
      const searchParams = new URLSearchParams(location.search);
      const token = searchParams.get('token');
      if (token) {
          setResetToken(token);
          setView('reset-confirm');
      }
  }, [location]);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (view === 'login') {
      const success = login(formData.email, formData.password);
      if (success) {
        if(formData.email === 'admin@gamepay.az') {
           navigate('/admin');
        } else {
           navigate('/');
        }
      } else {
        alert("Yanlış email və ya şifrə!");
      }
    } else if (view === 'register') {
      if(formData.name && formData.email && formData.phone && formData.password) {
        register(formData.name, formData.email, formData.phone, formData.password);
        navigate('/');
      } else {
          alert("Bütün xanaları doldurun!");
      }
    }
  };

  const handleForgotSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (forgotStep === 1) {
      if (resetPhone.length < 9) {
        alert("Düzgün mobil nömrə daxil edin.");
        return;
      }

      const success = requestPasswordReset(resetPhone);

      if(success) {
          // Success case - simulates link sent
          setForgotStep(2);
      } else {
          // Phone not found case - still show success message for security, but logic handled in store
          alert("Nömrə tapılmadı və ya xəta baş verdi.");
      }
    }
  };

  const handleResetConfirm = (e: React.FormEvent) => {
      e.preventDefault();
      if(resetToken && newPassword.length >= 6) {
          const success = confirmPasswordReset(resetToken, newPassword);
          if(success) {
              alert("Şifrə uğurla yeniləndi! İndi giriş edə bilərsiniz.");
              setView('login');
              setNewPassword('');
              setResetToken(null);
              navigate('/auth'); // Clear token from URL
          } else {
              alert("Link etibarsızdır və ya istifadə olunub.");
          }
      } else {
          alert("Şifrə ən az 6 simvol olmalıdır.");
      }
  };

  return (
    <div className="min-h-screen bg-gaming-dark flex items-center justify-center p-4">
      <div className="w-full max-w-md bg-gaming-card border border-gray-800 rounded-2xl p-8 shadow-2xl relative overflow-hidden">
         {/* Background Glow */}
         <div className="absolute top-0 left-0 w-full h-2 bg-gradient-to-r from-gaming-neon to-gaming-accent"></div>

         <div className="text-center mb-8">
           <h1 className="text-3xl font-black text-white mb-2">
             {view === 'login' ? 'Xoş Gəldiniz' : view === 'register' ? 'Qeydiyyat' : view === 'reset-confirm' ? 'Yeni Şifrə' : 'Şifrəni Yenilə'}
           </h1>
           <p className="text-gray-400 text-sm">GamePay dünyasına daxil olun</p>
         </div>

         {view === 'reset-confirm' ? (
             <form onSubmit={handleResetConfirm} className="space-y-4 animate-fade-in">
                 <div className="relative">
                      <label className="text-xs text-gray-500 ml-1 mb-1 block">Yeni Şifrəniz</label>
                      <Lock className="absolute left-3 top-8 text-gray-500 w-5 h-5" />
                      <input 
                        type="password" 
                        placeholder="Yeni şifrə daxil edin" 
                        className="w-full bg-slate-900 border border-gray-700 rounded-lg py-3 pl-10 pr-4 text-white focus:border-gaming-neon outline-none"
                        value={newPassword}
                        onChange={e => setNewPassword(e.target.value)}
                      />
                  </div>
                  <button type="submit" className="w-full bg-green-600 hover:bg-green-700 text-white font-bold py-3 rounded-lg flex items-center justify-center gap-2 transition-transform active:scale-95">
                       <CheckCircle className="w-4 h-4" /> Şifrəni Yenilə
                  </button>
             </form>
         ) : view === 'forgot-password' ? (
             <div className="space-y-4">
                {forgotStep === 1 ? (
                    <form onSubmit={handleForgotSubmit} className="space-y-4">
                        <div className="relative animate-fade-in">
                            <label className="text-xs text-gray-500 ml-1 mb-1 block">Mobil Nömrə</label>
                            <Phone className="absolute left-3 top-8 text-gray-500 w-5 h-5" />
                            <input 
                                type="tel" 
                                placeholder="+994 50 123 45 67" 
                                className="w-full bg-slate-900 border border-gray-700 rounded-lg py-3 pl-10 pr-4 text-white focus:border-gaming-neon outline-none"
                                value={resetPhone}
                                onChange={e => setResetPhone(e.target.value)}
                            />
                            <p className="text-xs text-gray-500 mt-2">Şifrə yeniləmə linki bu nömrəyə göndəriləcək.</p>
                        </div>
                        <button type="submit" className="w-full bg-gaming-neon hover:bg-cyan-400 text-black font-bold py-3 rounded-lg flex items-center justify-center gap-2 transition-transform active:scale-95">
                           Linki Göndər <ArrowRight className="w-4 h-4" />
                        </button>
                    </form>
                ) : (
                    <div className="text-center py-6 animate-fade-in">
                        <div className="w-16 h-16 bg-green-500/20 text-green-500 rounded-full flex items-center justify-center mx-auto mb-4">
                            <Mail className="w-8 h-8"/>
                        </div>
                        <h3 className="text-xl font-bold text-white mb-2">Link Göndərildi!</h3>
                        <p className="text-gray-400 text-sm mb-6">
                            Şifrə yeniləmə linki SMS vasitəsilə <b>{resetPhone}</b> nömrəsinə göndərildi. 
                            <br/><br/>
                            <span className="text-xs text-gray-500">Əgər link gəlmədisə və ya xəta baş verdisə, Admin panelindən hesabınız bərpa olunacaq.</span>
                        </p>
                        <button onClick={() => setView('login')} className="bg-slate-800 text-white px-6 py-2 rounded-lg hover:bg-slate-700">
                            Girişə Qayıt
                        </button>
                    </div>
                )}

                {forgotStep === 1 && (
                    <button type="button" onClick={() => setView('login')} className="w-full text-gray-400 text-sm hover:text-white mt-2 flex items-center justify-center gap-1">
                    <ArrowLeft className="w-3 h-3"/> Geri Qayıt
                    </button>
                )}
             </div>
         ) : (
            <form onSubmit={handleSubmit} className="space-y-4">
                {view === 'register' && (
                  <div className="relative">
                    <User className="absolute left-3 top-3.5 text-gray-500 w-5 h-5" />
                    <input 
                      type="text" 
                      placeholder="Ad Soyad" 
                      className="w-full bg-slate-900 border border-gray-700 rounded-lg py-3 pl-10 pr-4 text-white focus:border-gaming-neon outline-none"
                      value={formData.name}
                      onChange={e => setFormData({...formData, name: e.target.value})}
                    />
                  </div>
                )}
                {view === 'register' && (
                  <div className="relative">
                    <Phone className="absolute left-3 top-3.5 text-gray-500 w-5 h-5" />
                    <input 
                      type="tel" 
                      placeholder="Mobil Nömrə" 
                      className="w-full bg-slate-900 border border-gray-700 rounded-lg py-3 pl-10 pr-4 text-white focus:border-gaming-neon outline-none"
                      value={formData.phone}
                      onChange={e => setFormData({...formData, phone: e.target.value})}
                    />
                  </div>
                )}
                <div className="relative">
                    <Mail className="absolute left-3 top-3.5 text-gray-500 w-5 h-5" />
                    <input 
                      type="email" 
                      placeholder="Email ünvanı" 
                      className="w-full bg-slate-900 border border-gray-700 rounded-lg py-3 pl-10 pr-4 text-white focus:border-gaming-neon outline-none"
                      value={formData.email}
                      onChange={e => setFormData({...formData, email: e.target.value})}
                    />
                </div>
                <div className="relative">
                    <Lock className="absolute left-3 top-3.5 text-gray-500 w-5 h-5" />
                    <input 
                      type="password" 
                      placeholder="Şifrə" 
                      className="w-full bg-slate-900 border border-gray-700 rounded-lg py-3 pl-10 pr-4 text-white focus:border-gaming-neon outline-none"
                      value={formData.password}
                      onChange={e => setFormData({...formData, password: e.target.value})}
                    />
                </div>

                {view === 'login' && (
                  <div className="flex justify-end">
                    <button type="button" onClick={() => { setView('forgot-password'); setForgotStep(1); setResetPhone(''); }} className="text-xs text-gaming-neon hover:underline">
                      Şifrəni unutmusunuz?
                    </button>
                  </div>
                )}

                <button type="submit" className="w-full bg-gaming-neon hover:bg-cyan-400 text-black font-bold py-3 rounded-lg flex items-center justify-center gap-2 transition-transform active:scale-95">
                  {view === 'login' ? 'Daxil Ol' : 'Qeydiyyatdan Keç'} <ArrowRight className="w-4 h-4" />
                </button>
            </form>
         )}

         {view !== 'forgot-password' && view !== 'reset-confirm' && (
           <div className="mt-6 text-center">
              <button 
                onClick={() => setView(view === 'login' ? 'register' : 'login')} 
                className="text-gray-400 text-sm hover:text-white underline decoration-gaming-accent"
              >
                {view === 'login' ? "Hesabınız yoxdur? Qeydiyyat" : "Artıq hesabınız var? Giriş"}
              </button>
           </div>
         )}

         <div className="mt-4 text-center border-t border-gray-800 pt-4">
             <p className="text-xs text-gray-500">Admin Girişi üçün:</p>
             <p className="text-xs text-gray-600 font-mono">admin@gamepay.az / admin</p>
         </div>
      </div>
    </div>
  );
};

export default Auth;

import React, { useState } from 'react';
import { useApp } from '../store';
import { Trash2, CreditCard, Upload, CheckCircle, ArrowRight, Minus, Plus, Tag, Wallet } from 'lucide-react';
import { useNavigate } from 'react-router-dom';
import { MOCK_PROMO_CODES } from '../constants';

const Cart = () => {
  const { cart, updateCartQuantity, removeFromCart, paymentMethods, placeOrder, user, isAuthenticated } = useApp();
  const navigate = useNavigate();

  const [selectedMethod, setSelectedMethod] = useState<string | 'BALANCE' | null>(null);
  const [receiptFile, setReceiptFile] = useState<File | null>(null);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [orderComplete, setOrderComplete] = useState(false);

  // Promo Code State
  const [promoCode, setPromoCode] = useState('');
  const [appliedPromo, setAppliedPromo] = useState<{code: string, discountPercent: number} | null>(null);
  const [promoError, setPromoError] = useState('');

  const subTotal = cart.reduce((sum, item) => sum + (item.price * item.quantity), 0);
  const discountAmount = appliedPromo ? (subTotal * appliedPromo.discountPercent / 100) : 0;
  const totalAmount = subTotal - discountAmount;

  const handleApplyPromo = () => {
      const found = MOCK_PROMO_CODES.find(p => p.code === promoCode.toUpperCase());
      if (found) {
          setAppliedPromo(found);
          setPromoError('');
      } else {
          setPromoError('Yanlış promo kod');
          setAppliedPromo(null);
      }
  };

  const handleCheckout = async () => {
     if(!selectedMethod) return;

     // Validate manual payment
     if (selectedMethod !== 'BALANCE' && !receiptFile) {
         alert("Zəhmət olmasa qəbz yükləyin.");
         return;
     }

     setIsSubmitting(true);
     // Pass undefined for receipt if paying with balance
     const success = await placeOrder(selectedMethod, receiptFile || undefined, discountAmount);
     setIsSubmitting(false);

     if (success) {
        setOrderComplete(true);
     }
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      setReceiptFile(e.target.files[0]);
    }
  };

  const getSelectedPaymentDetails = () => paymentMethods.find(p => p.id === selectedMethod);

  if (orderComplete) {
    return (
        <div className="min-h-screen bg-gaming-dark flex items-center justify-center p-4">
            <div className="text-center bg-gaming-card p-8 rounded-2xl border border-gray-800 shadow-2xl max-w-md w-full animate-fade-in">
                <div className="w-20 h-20 bg-green-500/20 rounded-full flex items-center justify-center mx-auto mb-6">
                  <CheckCircle className="w-10 h-10 text-green-500" />
                </div>
                <h2 className="text-3xl font-bold text-white mb-4">Sifariş Qəbul Edildi!</h2>
                <p className="text-gray-400 mb-8">
                  {selectedMethod === 'BALANCE' 
                    ? "Ödəniş balansdan çıxıldı. Sifarişiniz emal olunur." 
                    : "Sifarişiniz manual yoxlanışa göndərildi. Ödəniş təsdiqləndikdən sonra məhsullar profilinizdə görünəcək."}
                </p>
                <button
                  onClick={() => navigate('/profile')}
                  className="w-full bg-gaming-accent hover:bg-purple-700 text-white font-bold py-3 px-8 rounded-lg transition-all"
                >
                  Sifarişlərimə Get
                </button>
            </div>
        </div>
    );
  }

  return (
    <div className="min-h-screen bg-gaming-dark py-10 px-4">
       <div className="max-w-6xl mx-auto">
          <h1 className="text-3xl font-bold mb-8">Səbətiniz</h1>

          {cart.length === 0 ? (
              <div className="text-center py-20 bg-slate-900/50 rounded-xl border border-gray-800">
                  <p className="text-gray-500 text-xl mb-4">Səbətiniz boşdur.</p>
                  <button onClick={() => navigate('/')} className="text-gaming-neon hover:underline">Mağazaya Keç</button>
              </div>
          ) : (
              <div className="flex flex-col lg:flex-row gap-8">
                  {/* Cart Items */}
                  <div className="flex-1 space-y-4">
                      {cart.map((item, index) => (
                          <div key={index} className="bg-gaming-card p-4 rounded-xl border border-gray-800 flex flex-col sm:flex-row items-center gap-4">
                             <img src={item.image} className="w-20 h-20 rounded object-cover" alt="" />
                             <div className="flex-1 text-center sm:text-left">
                                 <h3 className="font-bold text-white">{item.title}</h3>
                                 <p className="text-gray-400 text-sm">Vahid qiymət: {item.price.toFixed(2)} ₼</p>
                                 {item.userInput && <p className="text-xs text-gray-500 mt-1">Info: {item.userInput}</p>}
                             </div>

                             {/* Quantity Controls */}
                             <div className="flex items-center gap-3 bg-slate-900 rounded-lg p-1">
                                 <button onClick={() => updateCartQuantity(index, -1)} className="p-2 hover:bg-gray-700 rounded text-gray-400 hover:text-white"><Minus className="w-4 h-4"/></button>
                                 <span className="font-bold text-white w-6 text-center">{item.quantity}</span>
                                 <button onClick={() => updateCartQuantity(index, 1)} className="p-2 hover:bg-gray-700 rounded text-gray-400 hover:text-white"><Plus className="w-4 h-4"/></button>
                             </div>

                             <div className="text-right min-w-[80px]">
                                 <p className="text-gaming-neon font-bold text-lg">{(item.price * item.quantity).toFixed(2)} ₼</p>
                             </div>

                             <button onClick={() => removeFromCart(index)} className="text-red-500 hover:bg-red-500/10 p-2 rounded">
                                 <Trash2 className="w-5 h-5" />
                             </button>
                          </div>
                      ))}
                  </div>

                  {/* Checkout Sidebar */}
                  <div className="w-full lg:w-96">
                      <div className="bg-gaming-card p-6 rounded-xl border border-gray-800 sticky top-24">
                          <h2 className="text-xl font-bold mb-4">Sifariş Məlumatı</h2>

                          {/* Promo Code */}
                          <div className="mb-6">
                              <div className="flex gap-2">
                                  <input 
                                    type="text" 
                                    placeholder="Promo Kod" 
                                    className="flex-1 bg-slate-900 border border-gray-700 rounded px-3 py-2 text-sm text-white focus:border-gaming-neon outline-none uppercase"
                                    value={promoCode}
                                    onChange={e => setPromoCode(e.target.value)}
                                  />
                                  <button onClick={handleApplyPromo} className="bg-slate-700 hover:bg-slate-600 text-white px-3 py-2 rounded">
                                      <Tag className="w-4 h-4" />
                                  </button>
                              </div>
                              {promoError && <p className="text-red-500 text-xs mt-1">{promoError}</p>}
                              {appliedPromo && <p className="text-green-500 text-xs mt-1 font-bold">Promo tətbiq edildi: {appliedPromo.discountPercent}% ENDİRİM</p>}
                          </div>

                          <div className="space-y-2 mb-6 border-t border-gray-700 pt-4">
                             <div className="flex justify-between text-gray-400">
                                 <span>Məhsul Dəyəri:</span>
                                 <span>{subTotal.toFixed(2)} ₼</span>
                             </div>
                             {appliedPromo && (
                                <div className="flex justify-between text-green-400">
                                    <span>Endirim:</span>
                                    <span>-{discountAmount.toFixed(2)} ₼</span>
                                </div>
                             )}
                             <div className="flex justify-between text-xl font-bold text-white pt-2 border-t border-gray-700">
                                 <span>Yekun:</span>
                                 <span className="text-gaming-neon">{totalAmount.toFixed(2)} ₼</span>
                             </div>
                          </div>

                          {!isAuthenticated ? (
                              <button onClick={() => navigate('/auth')} className="w-full bg-gaming-neon text-black font-bold py-3 rounded mb-4">Ödəniş üçün Daxil Ol</button>
                          ) : (
                              <>
                                <h3 className="font-bold mb-2 text-sm text-gray-400 uppercase">Ödəniş Metodu Seçin</h3>
                                <div className="space-y-2 mb-6">
                                    {/* Pay with Balance Option */}
                                    <button
                                        onClick={() => setSelectedMethod('BALANCE')}
                                        className={`w-full p-3 rounded-lg border flex items-center justify-between gap-2 transition-all text-sm text-left
                                            ${selectedMethod === 'BALANCE' 
                                            ? 'border-gaming-neon bg-gaming-neon/10' 
                                            : 'border-gray-700 bg-slate-900 hover:border-gray-500'}`}
                                    >
                                        <div className="flex items-center gap-2">
                                            <Wallet className="w-4 h-4 text-purple-400" />
                                            <span className="text-white font-bold">Balansdan Ödə</span>
                                        </div>
                                        <span className="text-gray-400 text-xs">Cari: {user?.balance.toFixed(2)} ₼</span>
                                    </button>

                                    {/* Manual Methods */}
                                    {paymentMethods.filter(pm => pm.isActive).map(pm => (
                                        <button
                                        key={pm.id}
                                        onClick={() => setSelectedMethod(pm.id)}
                                        className={`w-full p-3 rounded-lg border flex items-center gap-2 transition-all text-sm text-left
                                            ${selectedMethod === pm.id 
                                            ? 'border-gaming-neon bg-gaming-neon/10' 
                                            : 'border-gray-700 bg-slate-900 hover:border-gray-500'}`}
                                        >
                                        <CreditCard className="w-4 h-4 text-gray-400" />
                                        <span className="text-white">{pm.name}</span>
                                        </button>
                                    ))}
                                </div>

                                {/* Manual Payment Details */}
                                {selectedMethod && selectedMethod !== 'BALANCE' && (
                                    <div className="mb-6 animate-fade-in">
                                        <div className="bg-slate-900 p-4 rounded mb-4 text-sm">
                                            <p className="text-gray-400 mb-1">Hesab:</p>
                                            <p className="font-mono text-white mb-2">{getSelectedPaymentDetails()?.details}</p>
                                            <p className="text-xs text-gray-500">{getSelectedPaymentDetails()?.instructions}</p>
                                        </div>

                                        <div className="relative border-2 border-dashed border-gray-600 rounded-lg p-4 hover:bg-slate-800/50 transition-colors text-center cursor-pointer">
                                            <input type="file" accept="image/*" onChange={handleFileChange} className="absolute inset-0 w-full h-full opacity-0 cursor-pointer" />
                                            <Upload className="w-6 h-6 text-gray-400 mx-auto mb-1" />
                                            <p className="text-xs text-gray-300">
                                                {receiptFile ? <span className="text-green-400">{receiptFile.name}</span> : "Qəbz yüklə"}
                                            </p>
                                        </div>
                                    </div>
                                )}

                                <button 
                                    onClick={handleCheckout}
                                    disabled={!selectedMethod || (selectedMethod !== 'BALANCE' && !receiptFile) || isSubmitting}
                                    className={`w-full py-3 rounded-lg font-bold flex items-center justify-center gap-2
                                    ${(!selectedMethod || (selectedMethod !== 'BALANCE' && !receiptFile) || isSubmitting) 
                                        ? 'bg-gray-700 text-gray-500 cursor-not-allowed' 
                                        : 'bg-green-600 hover:bg-green-700 text-white'}`}
                                >
                                    {isSubmitting ? 'Yoxlanılır...' : 'Sifarişi Tamamla'} <ArrowRight className="w-4 h-4"/>
                                </button>
                              </>
                          )}
                      </div>
                  </div>
              </div>
          )}
       </div>
    </div>
  );
};

export default Cart;

import React, { useState, useRef } from 'react';
import { useApp } from '../store';
import { Order, OrderStatus } from '../types';
import { Clock, CheckCircle, XCircle, Copy, Plus, CreditCard, Upload, Send, Loader2, Edit, Camera, Save, Lock, User as UserIcon } from 'lucide-react';

const Profile = () => {
  const { user, orders, placeBalanceOrder, paymentMethods, updateUserProfile, changePassword } = useApp();
  const [activeTab, setActiveTab] = useState<'orders' | 'security'>('orders');

  // Top Up
  const [showTopUp, setShowTopUp] = useState(false);
  const [topUpAmount, setTopUpAmount] = useState<number>(10);
  const [selectedMethod, setSelectedMethod] = useState<string | null>(null);
  const [receiptFile, setReceiptFile] = useState<File | null>(null);

  // Edit Profile State
  const [isEditing, setIsEditing] = useState(false);
  const [editName, setEditName] = useState(user?.name || '');
  const [editEmail, setEditEmail] = useState(user?.email || '');
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Change Password State
  const [currentPass, setCurrentPass] = useState('');
  const [newPass, setNewPass] = useState('');
  const [passMsg, setPassMsg] = useState('');

  const myOrders = orders.filter(o => o.userId === user?.id);

  const getStatusBadge = (status: OrderStatus) => {
    switch (status) {
      case OrderStatus.PENDING: 
        return (
          <span className="flex items-center gap-1 px-2 py-0.5 rounded text-xs font-bold text-yellow-400 bg-yellow-400/10 border border-yellow-400/20">
            <Clock className="w-3 h-3" /> Gözləmədə
          </span>
        );
      case OrderStatus.PROCESSING: 
        return (
          <span className="flex items-center gap-1 px-2 py-0.5 rounded text-xs font-bold text-blue-400 bg-blue-400/10 border border-blue-400/20">
            <Loader2 className="w-3 h-3 animate-spin" /> Emalda
          </span>
        );
      case OrderStatus.COMPLETED: 
        return (
          <span className="flex items-center gap-1 px-2 py-0.5 rounded text-xs font-bold text-green-400 bg-green-400/10 border border-green-400/20">
            <CheckCircle className="w-3 h-3" /> Tamamlandı
          </span>
        );
      case OrderStatus.CANCELLED: 
        return (
          <span className="flex items-center gap-1 px-2 py-0.5 rounded text-xs font-bold text-red-400 bg-red-400/10 border border-red-400/20">
            <XCircle className="w-3 h-3" /> Ləğv Edildi
          </span>
        );
    }
  };

  const copyToClipboard = (text: string) => {
    navigator.clipboard.writeText(text);
    alert("Kopyalandı!");
  };

  const handleTopUpSubmit = async () => {
    if(!selectedMethod || !receiptFile || topUpAmount <= 0) return;
    await placeBalanceOrder(topUpAmount, selectedMethod, receiptFile);
    setShowTopUp(false);
    setReceiptFile(null);
    alert("Balans artırma sorğusu göndərildi! Admin təsdiqindən sonra balansınıza əlavə olunacaq.");
  };

  const handleAvatarUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
      const file = e.target.files?.[0];
      if (file) {
          const imageUrl = URL.createObjectURL(file);
          updateUserProfile({ avatar: imageUrl });
      }
  };

  const handleSaveProfile = () => {
      updateUserProfile({ name: editName, email: editEmail });
      setIsEditing(false);
  };

  const handleChangePassword = (e: React.FormEvent) => {
      e.preventDefault();
      if (changePassword(currentPass, newPass)) {
          setPassMsg("Şifrə uğurla dəyişdirildi!");
          setCurrentPass('');
          setNewPass('');
      } else {
          setPassMsg("Cari şifrə yanlışdır.");
      }
  };

  if(!user) return null;

  return (
    <div className="max-w-7xl mx-auto px-4 py-8">
      {/* Account Info Card */}
      <div className="flex flex-col md:flex-row items-center justify-between gap-6 mb-10 bg-gaming-card p-6 rounded-2xl border border-gray-800 relative overflow-hidden">
        <div className="absolute top-0 right-0 p-4 opacity-5 pointer-events-none">
            <CreditCard className="w-64 h-64" />
        </div>

        <div className="flex flex-col md:flex-row items-center gap-6 z-10 w-full">
            {/* Avatar Section */}
            <div className="relative group">
                <div className="w-24 h-24 rounded-full border-2 border-gaming-neon overflow-hidden bg-slate-800">
                    {user.avatar ? (
                        <img src={user.avatar} alt={user.name} className="w-full h-full object-cover" />
                    ) : (
                        <div className="w-full h-full flex items-center justify-center text-2xl font-bold text-gray-500">
                            {user.name.charAt(0)}
                        </div>
                    )}
                </div>
                <button 
                    onClick={() => fileInputRef.current?.click()}
                    className="absolute bottom-0 right-0 bg-slate-900 text-white p-2 rounded-full border border-gray-600 hover:bg-gaming-neon hover:text-black transition-colors"
                >
                    <Camera className="w-4 h-4" />
                </button>
                <input type="file" ref={fileInputRef} hidden accept="image/*" onChange={handleAvatarUpload} />
            </div>

            {/* Info Section */}
            <div className="text-center md:text-left flex-1 space-y-2">
                {isEditing ? (
                    <div className="space-y-2 max-w-sm">
                        <input 
                            type="text" 
                            className="bg-slate-900 border border-gray-700 rounded px-3 py-1 text-white w-full"
                            value={editName}
                            onChange={e => setEditName(e.target.value)}
                            placeholder="Ad Soyad"
                        />
                        <input 
                            type="email" 
                            className="bg-slate-900 border border-gray-700 rounded px-3 py-1 text-white w-full"
                            value={editEmail}
                            onChange={e => setEditEmail(e.target.value)}
                            placeholder="Email"
                        />
                        <div className="flex gap-2 mt-2">
                             <button onClick={handleSaveProfile} className="bg-green-600 px-3 py-1 rounded text-sm flex items-center gap-1 hover:bg-green-700"><Save className="w-3 h-3"/> Yadda Saxla</button>
                             <button onClick={() => setIsEditing(false)} className="bg-gray-700 px-3 py-1 rounded text-sm hover:bg-gray-600">Ləğv Et</button>
                        </div>
                    </div>
                ) : (
                    <>
                        <h1 className="text-2xl font-bold text-white flex items-center justify-center md:justify-start gap-2">
                            {user.name} 
                            <button onClick={() => { setIsEditing(true); setEditName(user.name); setEditEmail(user.email); }} className="text-gray-500 hover:text-white"><Edit className="w-4 h-4" /></button>
                        </h1>
                        <p className="text-gray-400">{user.email}</p>
                        <p className="text-gray-500 text-sm">{user.phone || 'Mobil nömrə yoxdur'}</p>
                    </>
                )}
            </div>

            {/* Balance Section */}
            <div className="bg-slate-900/80 backdrop-blur-sm p-4 rounded-xl border border-gray-700 text-center min-w-[200px]">
                <p className="text-gray-400 text-sm mb-1">Mövcud Balans</p>
                <p className="text-3xl font-mono font-bold text-gaming-neon">{user.balance.toFixed(2)} ₼</p>
                <button onClick={() => setShowTopUp(true)} className="mt-3 w-full bg-gaming-neon text-black font-bold py-2 rounded text-sm hover:bg-cyan-400 flex items-center justify-center gap-2">
                    <Plus className="w-4 h-4" /> Balans Artır
                </button>
            </div>
        </div>
      </div>

      <div className="flex gap-4 mb-6 border-b border-gray-800 pb-2">
          <button onClick={() => setActiveTab('orders')} className={`pb-2 font-bold ${activeTab === 'orders' ? 'text-gaming-neon border-b-2 border-gaming-neon' : 'text-gray-400'}`}>Sifariş Tarixçəsi</button>
          <button onClick={() => setActiveTab('security')} className={`pb-2 font-bold ${activeTab === 'security' ? 'text-gaming-neon border-b-2 border-gaming-neon' : 'text-gray-400'}`}>Təhlükəsizlik</button>
      </div>

      {activeTab === 'orders' && (
        <div className="space-y-4 animate-fade-in">
            {myOrders.length === 0 ? (
            <p className="text-gray-500">Hələ heç bir sifariş yoxdur.</p>
            ) : (
            myOrders.map(order => (
                <div key={order.id} className="bg-gaming-card rounded-xl p-6 border border-gray-800 hover:border-gray-700 transition-all">
                <div className="flex flex-col md:flex-row justify-between md:items-center gap-4">

                    <div className="flex-1">
                    <div className="flex items-center gap-3 mb-1">
                        <h3 className="text-lg font-bold text-white">{order.productTitle || (order.items && order.items.length > 0 ? order.items[0].title : 'Order')} {order.items && order.items.length > 1 && `(+${order.items.length - 1} digər)`}</h3>
                        {getStatusBadge(order.status)}
                    </div>
                    <div className="text-sm text-gray-400">
                        ID: {order.id} • {new Date(order.date).toLocaleDateString()}
                    </div>
                    </div>

                    <div className="text-right">
                        <div className="text-xl font-bold text-white">{order.totalPrice ? order.totalPrice.toFixed(2) : (order.price || 0).toFixed(2)} ₼</div>
                        <div className="text-sm text-gray-500">{order.paymentMethodName}</div>
                    </div>

                </div>

                {/* Delivery Section */}
                {order.status === OrderStatus.COMPLETED && order.deliveredContent && (
                    <div className="mt-4 pt-4 border-t border-gray-800 bg-slate-900/50 -mx-6 -mb-6 px-6 py-4 rounded-b-xl">
                    <p className="text-xs text-green-400 mb-1 uppercase font-bold tracking-wider flex items-center gap-1">
                        <CheckCircle className="w-3 h-3" /> Təslimat
                    </p>
                    <div className="flex items-center gap-2 bg-black/40 p-3 rounded border border-gray-700">
                        <code className="text-gaming-neon font-mono flex-1 break-all">{order.deliveredContent}</code>
                        <button 
                        onClick={() => copyToClipboard(order.deliveredContent!)}
                        className="p-2 hover:bg-gray-700 rounded text-gray-400 hover:text-white"
                        >
                        <Copy className="w-4 h-4" />
                        </button>
                    </div>
                    </div>
                )}
                </div>
            ))
            )}
        </div>
      )}

      {activeTab === 'security' && (
          <div className="max-w-md bg-gaming-card p-6 rounded-xl border border-gray-800 animate-fade-in">
              <h3 className="text-xl font-bold text-white mb-4 flex items-center gap-2"><Lock className="w-5 h-5"/> Şifrəni Dəyiş</h3>
              <form onSubmit={handleChangePassword} className="space-y-4">
                  <div>
                      <label className="text-xs text-gray-400 block mb-1">Cari Şifrə</label>
                      <input type="password" required className="w-full bg-slate-900 border border-gray-700 rounded p-2 text-white" value={currentPass} onChange={e => setCurrentPass(e.target.value)} />
                  </div>
                  <div>
                      <label className="text-xs text-gray-400 block mb-1">Yeni Şifrə</label>
                      <input type="password" required className="w-full bg-slate-900 border border-gray-700 rounded p-2 text-white" value={newPass} onChange={e => setNewPass(e.target.value)} />
                  </div>
                  {passMsg && <p className={`text-sm ${passMsg.includes('uğurla') ? 'text-green-500' : 'text-red-500'}`}>{passMsg}</p>}
                  <button type="submit" className="w-full bg-blue-600 hover:bg-blue-700 text-white font-bold py-2 rounded">Yadda Saxla</button>
              </form>
          </div>
      )}

      {/* Top Up Modal */}
      {showTopUp && (
          <div className="fixed inset-0 z-50 bg-black/80 flex items-center justify-center p-4 backdrop-blur-sm">
             <div className="bg-slate-900 p-6 rounded-2xl border border-gray-700 w-full max-w-md shadow-2xl animate-fade-in">
