  // Drag and Drop Logic
  const handleDrag = (e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    if (e.type === "dragenter" || e.type === "dragover") {
      setDragActive(true);
    } else if (e.type === "dragleave") {
      setDragActive(false);
    }
  };

  const handleDrop = (e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    setDragActive(false);
    if (e.dataTransfer.files && e.dataTransfer.files[0]) {
      const file = e.dataTransfer.files[0];
      setProductForm({...productForm, imageFile: file, image: URL.createObjectURL(file)});
    }
  };

  const handleProductImageSelect = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if(file) {
      setProductForm({...productForm, imageFile: file, image: URL.createObjectURL(file)});
    }
  };

  const handleLogoUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
      const file = e.target.files?.[0];
      if(file) {
          updateSiteSettings({ logoUrl: URL.createObjectURL(file) });
      }
  };

  const handleHeroUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
      const file = e.target.files?.[0];
      if(file) {
          updateSiteSettings({ heroBannerUrl: URL.createObjectURL(file) });
      }
  };

  const handleCreateProduct = (e: React.FormEvent) => {
    e.preventDefault();
    if(!productForm.title || !productForm.price || !productForm.categoryId) {
      alert("Əsas xanaları doldurun!");
      return;
    }
    const product: Product = {
      id: `prod-${Date.now()}`,
      title: productForm.title!,
      categoryId: productForm.categoryId!,
      type: productForm.type || ProductType.LICENSE_KEY,
      price: Number(productForm.price),
      costPrice: Number(productForm.costPrice || 0),
      discountPercent: Number(productForm.discountPercent || 0),
      image: productForm.image || 'https://via.placeholder.com/300',
      description: productForm.description || '',
      requiresInput: productForm.requiresInput,
      inputLabel: productForm.inputLabel,
      seoTitle: productForm.seoTitle,
      seoKeywords: productForm.seoKeywords
    };
    addProduct(product);
    setProductForm({ title: '', categoryId: '', price: 0, costPrice: 0, discountPercent: 0, type: ProductType.LICENSE_KEY, image: '', description: '', requiresInput: false, seoTitle: '', seoKeywords: '' });
    alert("Məhsul yaradıldı!");
  };

  const downloadTemplate = () => {
      const csvContent = "data:text/csv;charset=utf-8,Title,CategoryId,Type(LICENSE_KEY/ID_LOAD/ACCOUNT),Price,CostPrice,DiscountPercent,Description,ImageURL\nExample Product,cat1,LICENSE_KEY,10.00,8.00,0,This is an example product,https://via.placeholder.com/150";
      const encodedUri = encodeURI(csvContent);
      const link = document.createElement("a");
      link.setAttribute("href", encodedUri);
      link.setAttribute("download", "products_template.csv");
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);
  };

  const handleBulkImport = (e: React.ChangeEvent<HTMLInputElement>) => {
      const file = e.target.files?.[0];
      if (!file) return;

      const reader = new FileReader();
      reader.onload = (event) => {
          const text = event.target?.result as string;
          if (!text) return;

          const lines = text.split('\n');
          const newProducts: Product[] = [];

          // Skip header row
          for (let i = 1; i < lines.length; i++) {
              const line = lines[i].trim();
              if (!line) continue;

              // Simple CSV split (note: doesn't handle commas inside quotes)
              const cols = line.split(',');
              if (cols.length < 5) continue; // Basic validation

              const [title, categoryId, typeStr, price, costPrice, discountPercent, description, image] = cols;

              let type = ProductType.LICENSE_KEY;
              if (typeStr === 'ID_LOAD') type = ProductType.ID_LOAD;
              if (typeStr === 'ACCOUNT') type = ProductType.ACCOUNT;

              newProducts.push({
                  id: `prod-${Date.now()}-${i}`,
                  title: title,
                  categoryId: categoryId,
                  type: type,
                  price: parseFloat(price) || 0,
                  costPrice: parseFloat(costPrice) || 0,
                  discountPercent: parseFloat(discountPercent) || 0,
                  description: description || '',
                  image: image || 'https://via.placeholder.com/150',
                  requiresInput: type === ProductType.ID_LOAD
              });
          }

          if (newProducts.length > 0) {
              addProducts(newProducts);
              alert(`${newProducts.length} məhsul uğurla əlavə edildi!`);
          } else {
              alert("Faylda düzgün məlumat tapılmadı.");
          }
      };
      reader.readAsText(file);
      e.target.value = ''; // Reset input
  };

  const handlePasswordReset = () => {
      if(resetModalUser && adminNewPassword) {
          adminUpdateUserPassword(resetModalUser.id, adminNewPassword);
