                    <Search className="absolute left-3 top-3 text-gray-500 w-4 h-4" />
                    <input 
                      type="text" 
                      placeholder="Sifariş ID, User, Məhsul..." 
                      className="w-full bg-slate-900 border border-gray-700 rounded-lg pl-9 pr-4 py-2 text-sm focus:border-gaming-neon outline-none"
                      value={orderSearch}
                      onChange={e => setOrderSearch(e.target.value)}
                    />
