    categories, addCategory, deleteCategory, addProduct, deleteProduct, addProducts,
    blogs, addBlog, deleteBlog, agreements, addAgreement, deleteAgreement,
    comments, toggleCommentApproval, deleteComment, logout,
    usersList, adminUpdateUserPassword, toggleUserBan, generateResetLink,
    promoCodes, addPromoCode, deletePromoCode, togglePromoCode
  } = useApp();

  const [activeTab, setActiveTab] = useState<'dashboard' | 'orders' | 'products' | 'categories' | 'promos' | 'payments' | 'cms' | 'users' | 'settings'>('dashboard');
  const [cmsSubTab, setCmsSubTab] = useState<'blogs' | 'contracts' | 'comments'>('blogs');
  const [settingsSubTab, setSettingsSubTab] = useState<'general' | 'hero' | 'seo'>('general');
  const [productSubTab, setProductSubTab] = useState<'list' | 'add'>('list');
  const [mobileMenuOpen, setMobileMenuOpen] = useState(false);

  // Modals & Search
  const [viewReceipt, setViewReceipt] = useState<string | null>(null);
  const [deliveryModal, setDeliveryModal] = useState<{orderId: string, productTitle: string} | null>(null);
  const [deliveryContent, setDeliveryContent] = useState('');
  const [orderSearch, setOrderSearch] = useState('');

  // User Management
  const [resetModalUser, setResetModalUser] = useState<{id: string, name: string} | null>(null);
  const [userOrdersModal, setUserOrdersModal] = useState<string | null>(null); // UserId
  const [adminNewPassword, setAdminNewPassword] = useState('');
  const [generatedLink, setGeneratedLink] = useState<string | null>(null);
  const [showPasswords, setShowPasswords] = useState(false);

  // States for Dashboard Date Filter
  const [statsPeriod, setStatsPeriod] = useState<number>(1); // 1 = Today

  // Category Form
  const [newCatName, setNewCatName] = useState('');
  const [newCatImage, setNewCatImage] = useState('');
  const [newCatSeoTitle, setNewCatSeoTitle] = useState('');
  const [newCatSeoKeys, setNewCatSeoKeys] = useState('');

  // Promo Code Form
  const [newPromoCode, setNewPromoCode] = useState('');
  const [newPromoDiscount, setNewPromoDiscount] = useState(0);

  // Product Form
  const [productForm, setProductForm] = useState<Partial<Product> & { imageFile?: File | null }>({
    title: '', categoryId: '', price: 0, costPrice: 0, discountPercent: 0, type: ProductType.LICENSE_KEY, image: '', description: '', requiresInput: false, seoTitle: '', seoKeywords: ''
  });
  const fileInputRef = useRef<HTMLInputElement>(null);
  const catImageInputRef = useRef<HTMLInputElement>(null);
  const logoInputRef = useRef<HTMLInputElement>(null);
  const heroInputRef = useRef<HTMLInputElement>(null);
  const bulkInputRef = useRef<HTMLInputElement>(null);
  const [dragActive, setDragActive] = useState(false);

  if (!user || user.role !== 'admin') {
    return <div className="p-10 text-center text-red-500 font-bold text-2xl">Access Denied</div>;
  }

  // --- STATS LOGIC ---
  const getFilteredOrders = () => {
    const now = new Date();
    const past = new Date();

    // If statsPeriod is 1 (Today), we need to check only today's date string
    if (statsPeriod === 1) {
       return orders.filter(o => {
         const orderDate = new Date(o.date);
         return orderDate.toDateString() === now.toDateString() && o.status === OrderStatus.COMPLETED;
       });
    }

    past.setDate(now.getDate() - statsPeriod);
    past.setHours(0,0,0,0);

    return orders.filter(o => {
      const orderDate = new Date(o.date);
      return orderDate >= past && o.status === OrderStatus.COMPLETED;
    });
  };

  const filteredOrders = getFilteredOrders();
  const totalRevenue = filteredOrders.reduce((sum, o) => sum + (o.totalPrice || o.price || 0), 0);

  // --- HANDLERS ---

  const handleLogout = () => {
    logout();
    navigate('/');
  };

  const openDeliveryModal = (order: Order) => {
    if (order.productType === ProductType.BALANCE || (order.items && order.items[0]?.type === ProductType.BALANCE)) {
        if(window.confirm("Bu balans artımıdır. Təsdiqləsəniz istifadəçi balansına avtomatik pul əlavə olunacaq.")) {
            completeOrder(order.id, "Balans Artırıldı");
        }
    } else {
        const title = order.productTitle || (order.items && order.items.length > 0 ? order.items.map(i => i.title).join(', ') : 'Order');
        setDeliveryModal({ orderId: order.id, productTitle: title });
        setDeliveryContent('');
    }
  };

  const confirmDelivery = () => {
    if(!deliveryModal || !deliveryContent) return;
    completeOrder(deliveryModal.orderId, deliveryContent);
    setDeliveryModal(null);
    setDeliveryContent('');
    alert("Sifariş tamamlandı və məlumat istifadəçiyə göndərildi!");
  };

  // Drag and Drop Logic
  const handleDrag = (e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    if (e.type === "dragenter" || e.type === "dragover") {
      setDragActive(true);
    } else if (e.type === "dragleave") {
      setDragActive(false);
    }
  };

  const handleDrop = (e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    setDragActive(false);
    if (e.dataTransfer.files && e.dataTransfer.files[0]) {
      const file = e.dataTransfer.files[0];
      setProductForm({...productForm, imageFile: file, image: URL.createObjectURL(file)});
    }
  };

  const handleProductImageSelect = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if(file) {
      setProductForm({...productForm, imageFile: file, image: URL.createObjectURL(file)});
    }
  };

  const handleLogoUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
      const file = e.target.files?.[0];
      if(file) {
          updateSiteSettings({ logoUrl: URL.createObjectURL(file) });
      }
  };

  const handleHeroUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
      const file = e.target.files?.[0];
      if(file) {
          updateSiteSettings({ heroBannerUrl: URL.createObjectURL(file) });
      }
  };

  const handleCreateProduct = (e: React.FormEvent) => {
    e.preventDefault();
    if(!productForm.title || !productForm.price || !productForm.categoryId) {
      alert("Əsas xanaları doldurun!");
      return;
    }
    const product: Product = {
      id: `prod-${Date.now()}`,
      title: productForm.title!,
      categoryId: productForm.categoryId!,
      type: productForm.type || ProductType.LICENSE_KEY,
      price: Number(productForm.price),
      costPrice: Number(productForm.costPrice || 0),
      discountPercent: Number(productForm.discountPercent || 0),
      image: productForm.image || 'https://via.placeholder.com/300',
      description: productForm.description || '',
      requiresInput: productForm.requiresInput,
      inputLabel: productForm.inputLabel,
      seoTitle: productForm.seoTitle,
      seoKeywords: productForm.seoKeywords
    };
    addProduct(product);
    setProductForm({ title: '', categoryId: '', price: 0, costPrice: 0, discountPercent: 0, type: ProductType.LICENSE_KEY, image: '', description: '', requiresInput: false, seoTitle: '', seoKeywords: '' });
    alert("Məhsul yaradıldı!");
    setProductSubTab('list'); // Switch back to list view
  };

  const downloadTemplate = () => {
      const csvContent = "data:text/csv;charset=utf-8,Title,CategoryId,Type(LICENSE_KEY/ID_LOAD/ACCOUNT),Price,CostPrice,DiscountPercent,Description,ImageURL\nExample Product,cat1,LICENSE_KEY,10.00,8.00,0,This is an example product,https://via.placeholder.com/150";
      const encodedUri = encodeURI(csvContent);
      const link = document.createElement("a");
      link.setAttribute("href", encodedUri);
      link.setAttribute("download", "products_template.csv");
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);
  };

  const handleBulkImport = (e: React.ChangeEvent<HTMLInputElement>) => {
      const file = e.target.files?.[0];
      if (!file) return;

      const reader = new FileReader();
      reader.onload = (event) => {
          const text = event.target?.result as string;
          if (!text) return;

          const lines = text.split('\n');
          const newProducts: Product[] = [];

          for (let i = 1; i < lines.length; i++) {
              const line = lines[i].trim();
              if (!line) continue;
              const cols = line.split(',');
              if (cols.length < 5) continue; 

              const [title, categoryId, typeStr, price, costPrice, discountPercent, description, image] = cols;

              let type = ProductType.LICENSE_KEY;
              if (typeStr === 'ID_LOAD') type = ProductType.ID_LOAD;
              if (typeStr === 'ACCOUNT') type = ProductType.ACCOUNT;

              newProducts.push({
                  id: `prod-${Date.now()}-${i}`,
                  title: title,
                  categoryId: categoryId,
                  type: type,
                  price: parseFloat(price) || 0,
                  costPrice: parseFloat(costPrice) || 0,
                  discountPercent: parseFloat(discountPercent) || 0,
                  description: description || '',
                  image: image || 'https://via.placeholder.com/150',
                  requiresInput: type === ProductType.ID_LOAD
              });
          }

          if (newProducts.length > 0) {
              addProducts(newProducts);
              alert(`${newProducts.length} məhsul uğurla əlavə edildi!`);
          } else {
              alert("Faylda düzgün məlumat tapılmadı.");
          }
      };
      reader.readAsText(file);
      e.target.value = ''; // Reset input
  };

  const handlePasswordReset = () => {
      if(resetModalUser && adminNewPassword) {
          adminUpdateUserPassword(resetModalUser.id, adminNewPassword);
          setResetModalUser(null);
          setAdminNewPassword('');
          setGeneratedLink(null);
          alert("Şifrə uğurla dəyişdirildi!");
      }
  };

  const handleGenerateLink = () => {
      if (resetModalUser) {
          const link = generateResetLink(resetModalUser.id);
          setGeneratedLink(link);
      }
  };

  const handleAddCategory = () => {
    if(newCatName) { 
        addCategory({
            id: `cat-${Date.now()}`, 
            name: newCatName, 
            image: newCatImage || 'https://via.placeholder.com/150',
            seoTitle: newCatSeoTitle, 
            seoKeywords: newCatSeoKeys
        }); 
        setNewCatName(''); 
        setNewCatImage('');
        setNewCatSeoTitle('');
        setNewCatSeoKeys('');
    }
  };

  const handleCatImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
      const file = e.target.files?.[0];
      if (file) {
          setNewCatImage(URL.createObjectURL(file));
      }
  };

  const handleAddPromo = () => {
      if (newPromoCode && newPromoDiscount > 0) {
          addPromoCode({
              id: `promo-${Date.now()}`,
              code: newPromoCode.toUpperCase(),
              discountPercent: newPromoDiscount,
              isActive: true
          });
          setNewPromoCode('');
          setNewPromoDiscount(0);
      } else {
          alert("Məlumatları düzgün daxil edin");
      }
  };

  const filteredOrderList = orders.filter(o => 
    o.id.toLowerCase().includes(orderSearch.toLowerCase()) || 
    (o.userId && o.userId.toLowerCase().includes(orderSearch.toLowerCase())) ||
    (o.productTitle && o.productTitle.toLowerCase().includes(orderSearch.toLowerCase()))
  );

  const NavContent = () => (
      <>
        <div className="p-6 border-b border-gray-800 flex justify-between items-center">
          <h2 className="text-2xl font-black text-gaming-neon tracking-tighter">ADMIN PANEL</h2>
          <button onClick={() => setMobileMenuOpen(false)} className="md:hidden text-gray-400"><X /></button>
        </div>

        <nav className="p-4 space-y-2 flex-1 overflow-y-auto">
          {[
             {id: 'dashboard', icon: BarChart3, label: 'Statistika'},
             {id: 'orders', icon: ShoppingBag, label: 'Sifarişlər', count: orders.filter(o=>o.status===OrderStatus.PENDING).length},
             {id: 'users', icon: Users, label: 'İstifadəçilər', count: usersList.filter(u => u.resetRequested).length},
             {id: 'products', icon: Package, label: 'Məhsullar'},
             {id: 'categories', icon: LayoutGrid, label: 'Kateqoriyalar'},
             {id: 'promos', icon: Ticket, label: 'Promo Kodlar'},
             {id: 'payments', icon: Wallet, label: 'Ödəniş Sistemləri'},
             {id: 'cms', icon: FileText, label: 'Sayt / CMS'},
             {id: 'settings', icon: Settings, label: 'Ayarlar'},
          ].map(item => (
            <button 
              key={item.id}
              onClick={() => { setActiveTab(item.id as any); setMobileMenuOpen(false); }}
              className={`w-full text-left px-4 py-3 rounded-lg flex items-center gap-3 transition-colors 
                ${activeTab === item.id ? 'bg-gaming-accent text-white shadow-lg shadow-purple-900/20' : 'text-gray-400 hover:bg-slate-800'}`}
            >
              <item.icon className="w-5 h-5" /> 
              <span className="font-medium">{item.label}</span>
              {item.count ? <span className="ml-auto bg-red-500 text-white text-xs px-2 py-0.5 rounded-full animate-pulse">{item.count}</span> : null}
            </button>
          ))}
        </nav>

        <div className="p-4 border-t border-gray-800">
          <button onClick={handleLogout} className="w-full flex items-center gap-2 text-red-400 hover:text-white hover:bg-red-900/20 px-4 py-3 rounded-lg transition-colors">
            <LogOut className="w-5 h-5" /> Çıxış
          </button>
        </div>
      </>
  );

  return (
    <div className="min-h-screen bg-slate-950 text-white flex flex-col md:flex-row relative">
      {/* Mobile Toggle */}
      <div className="md:hidden p-4 bg-slate-900 border-b border-gray-800 flex justify-between items-center sticky top-0 z-40">
          <span className="font-black text-gaming-neon">ADMIN PANEL</span>
          <button onClick={() => setMobileMenuOpen(true)}><Menu className="w-6 h-6"/></button>
      </div>

      {/* Sidebar - Desktop */}
      <div className="hidden md:flex w-64 bg-slate-900 border-r border-gray-800 flex-col shrink-0 h-screen sticky top-0 overflow-y-auto">
         <NavContent />
      </div>

      {/* Sidebar - Mobile Drawer */}
      {mobileMenuOpen && (
          <div className="fixed inset-0 z-50 bg-black/80 flex md:hidden">
              <div className="w-3/4 bg-slate-900 h-full flex flex-col animate-slide-in-left">
                  <NavContent />
              </div>
              <div className="flex-1" onClick={() => setMobileMenuOpen(false)}></div>
          </div>
      )}

      {/* Content Area */}
      <div className="flex-1 p-4 md:p-10 overflow-y-auto">

        {/* DASHBOARD TAB */}
        {activeTab === 'dashboard' && (
          <div className="space-y-8 animate-fade-in">
             <div className="flex justify-between items-center mb-6">
                <h3 className="text-2xl font-bold">Satış Statistikası</h3>
                <div className="bg-slate-800 rounded-lg p-1 flex">
                    <button onClick={() => setStatsPeriod(1)} className={`px-4 py-1 rounded-md text-sm ${statsPeriod === 1 ? 'bg-gaming-neon text-black font-bold' : 'text-gray-400 hover:text-white'}`}>Bu Gün</button>
                    <button onClick={() => setStatsPeriod(7)} className={`hidden sm:block px-4 py-1 rounded-md text-sm ${statsPeriod === 7 ? 'bg-gaming-neon text-black font-bold' : 'text-gray-400 hover:text-white'}`}>7 Gün</button>
                    <button onClick={() => setStatsPeriod(30)} className={`px-4 py-1 rounded-md text-sm ${statsPeriod === 30 ? 'bg-gaming-neon text-black font-bold' : 'text-gray-400 hover:text-white'}`}>30 Gün</button>
                    <button onClick={() => setStatsPeriod(9999)} className={`px-4 py-1 rounded-md text-sm ${statsPeriod === 9999 ? 'bg-gaming-neon text-black font-bold' : 'text-gray-400 hover:text-white'}`}>Ümumi</button>
                </div>
             </div>

             <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                <div className="bg-slate-800 p-6 rounded-2xl border border-gray-700 relative overflow-hidden group hover:border-gaming-neon transition-colors">
                   <div className="absolute top-0 right-0 p-4 opacity-10 group-hover:opacity-20 transition-opacity">
                      <CreditCard className="w-20 h-20 text-gaming-neon" />
                   </div>
                   <p className="text-gray-400 text-sm font-medium">Dövriyyə (Gəlir)</p>
                   <p className="text-3xl font-bold text-white mt-2">{totalRevenue.toFixed(2)} ₼</p>
                   <p className="text-xs text-green-400 mt-1 flex items-center gap-1"><Check className="w-3 h-3"/> {filteredOrders.length} Uğurlu Sifariş</p>
                </div>

                 <div className="bg-slate-800 p-6 rounded-2xl border border-gray-700 relative overflow-hidden">
                   <p className="text-gray-400 text-sm font-medium">Aktiv Sifarişlər (Gözləyən)</p>
                   <p className="text-3xl font-bold text-yellow-400 mt-2">{orders.filter(o=>o.status===OrderStatus.PENDING).length}</p>
                   <p className="text-xs text-yellow-300 mt-1">Təsdiqlənməlidir</p>
                </div>

                <div className="bg-slate-800 p-6 rounded-2xl border border-gray-700 relative overflow-hidden">
                   <p className="text-gray-400 text-sm font-medium">Ortalama Səbət Dəyəri</p>
                   <p className="text-3xl font-bold text-blue-400 mt-2">{filteredOrders.length > 0 ? (totalRevenue / filteredOrders.length).toFixed(2) : 0} ₼</p>
                </div>
             </div>
          </div>
        )}

        {/* ORDERS TAB */}
        {activeTab === 'orders' && (
          <div className="space-y-6 animate-fade-in">
             {/* ... Order content remains similar, omitting for brevity ... */}
             <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4 mb-4">
                <h3 className="text-xl font-bold">Sifariş İdarəetməsi</h3>
                <div className="relative w-full md:w-64">
                    <Search className="absolute left-3 top-3 text-gray-500 w-4 h-4" />
                    <input 
                      type="text" 
                      placeholder="Sifariş ID, User, Məhsul..." 
                      className="w-full bg-slate-900 border border-gray-700 rounded-lg pl-9 pr-4 py-2 text-sm focus:border-gaming-neon outline-none"
                      value={orderSearch}
                      onChange={e => setOrderSearch(e.target.value)}
                    />
                </div>
             </div>
             {/* Simple Order List for brevity */}
             <div className="space-y-4">
                 {filteredOrderList.map(order => (
                     <div key={order.id} className="bg-slate-800 p-4 rounded-xl border border-gray-700 flex justify-between items-center">
                         <div>
                             <p className="font-bold">{order.productTitle || (order.items && order.items[0].title)}</p>
                             <p className="text-sm text-gray-400">{order.userId} - {order.totalPrice} ₼</p>
                         </div>
                         <div className="flex gap-2">
                             {order.status === OrderStatus.PENDING && (
                                 <button onClick={() => openDeliveryModal(order)} className="bg-green-600 px-3 py-1 rounded text-sm">Təsdiqlə</button>
                             )}
                             <span className="text-xs border border-gray-600 px-2 py-1 rounded">{order.status}</span>
                         </div>
                     </div>
                 ))}
             </div>
          </div>
        )}

        {/* USERS TAB */}
        {activeTab === 'users' && (
            <div className="space-y-6 animate-fade-in">
                {/* ... User content ... */}
                <h3 className="text-xl font-bold flex items-center gap-2"><Users className="text-gaming-neon"/> İstifadəçi İdarəetməsi</h3>
                <div className="space-y-2">
                    {usersList.map(u => (
                        <div key={u.id} className="bg-slate-800 p-4 rounded-xl border border-gray-700 flex justify-between items-center">
                            <div>
                                <p className="font-bold">{u.name}</p>
                                <p className="text-sm text-gray-400">{u.email} ({u.balance} ₼)</p>
                            </div>
                            <button onClick={() => { setResetModalUser({id: u.id, name: u.name}); setGeneratedLink(null); }} className="bg-slate-700 px-3 py-1 rounded text-sm">Şifrəni Dəyiş</button>
                        </div>
                    ))}
                </div>
            </div>
        )}

        {/* PROMO CODES TAB */}
        {activeTab === 'promos' && (
            <div className="space-y-6 animate-fade-in">
                <h3 className="text-xl font-bold flex items-center gap-2"><Ticket className="text-gaming-neon"/> Promo Kodlar</h3>

                <div className="bg-slate-800 p-6 rounded-xl border border-gray-700 flex flex-col md:flex-row gap-4 items-end">
                    <div className="flex-1 w-full">
                        <label className="text-xs text-gray-400 mb-1 block">Kod (Məs: ENDIRIM10)</label>
                        <input className="w-full bg-slate-900 border border-gray-600 rounded p-2 uppercase" value={newPromoCode} onChange={e => setNewPromoCode(e.target.value)} />
                    </div>
                    <div className="w-full md:w-32">
                        <label className="text-xs text-gray-400 mb-1 block">Endirim %</label>
                        <input type="number" className="w-full bg-slate-900 border border-gray-600 rounded p-2" value={newPromoDiscount} onChange={e => setNewPromoDiscount(Number(e.target.value))} />
                    </div>
                    <button onClick={handleAddPromo} className="w-full md:w-auto bg-green-600 text-white font-bold px-6 py-2 rounded hover:bg-green-700">Yarat</button>
                </div>

                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
                    {promoCodes.map(promo => (
                        <div key={promo.id} className="bg-slate-800 p-4 rounded-xl border border-gray-700 flex justify-between items-center">
                            <div>
                                <p className="font-mono text-xl font-bold text-gaming-neon">{promo.code}</p>
                                <p className="text-sm text-gray-400">{promo.discountPercent}% Endirim</p>
                            </div>
                            <div className="flex gap-2">
                                <button onClick={() => togglePromoCode(promo.id)} className={`px-3 py-1 rounded text-xs font-bold ${promo.isActive ? 'bg-green-600/20 text-green-400' : 'bg-red-600/20 text-red-400'}`}>
                                    {promo.isActive ? 'Aktiv' : 'Passiv'}
                                </button>
                                <button onClick={() => deletePromoCode(promo.id)} className="text-red-500 hover:text-white"><Trash2 className="w-4 h-4"/></button>
                            </div>
                        </div>
                    ))}
                </div>
            </div>
        )}

        {/* CATEGORIES TAB */}
        {activeTab === 'categories' && (
          <div className="animate-fade-in space-y-6">
              <h3 className="text-xl font-bold mb-4 flex items-center gap-2"><LayoutGrid className="text-gaming-neon" /> Kateqoriya İdarəetməsi</h3>

              <div className="bg-slate-800 p-6 rounded-xl border border-gray-700 max-w-xl">
                    <h4 className="font-bold mb-4">Yeni Kateqoriya Yarat</h4>
                    <div className="space-y-4 mb-6">
                       <div>
                           <label className="text-xs text-gray-400">Kateqoriya Adı</label>
                           <input type="text" className="w-full bg-slate-900 p-3 rounded border border-gray-600" placeholder="Məs: PUBG Mobile" value={newCatName} onChange={e => setNewCatName(e.target.value)} />
                       </div>

                       {/* Image Upload */}
                       <div onClick={() => catImageInputRef.current?.click()} className="border-2 border-dashed border-gray-600 rounded-lg p-4 flex flex-col items-center justify-center cursor-pointer hover:bg-slate-700 transition-colors h-32 relative overflow-hidden">
                            {newCatImage ? (
                                <img src={newCatImage} className="h-full object-contain" alt="Preview" />
                            ) : (
                                <div className="text-center text-gray-400">
                                    <UploadCloud className="w-8 h-8 mx-auto mb-2"/>
                                    <span className="text-xs">Fotoqraf Yüklə</span>
                                </div>
                            )}
                            <input type="file" ref={catImageInputRef} hidden accept="image/*" onChange={handleCatImageUpload} />
                        </div>

                       <button onClick={handleAddCategory} className="bg-gaming-neon text-black px-6 py-2 rounded font-bold hover:bg-cyan-400 w-full">Əlavə Et</button>
