  Clock, CheckCircle, XCircle, Loader2, KeyRound, Ban, History, Link2, Menu, Tag, List, Ticket
} from 'lucide-react';
import { useNavigate } from 'react-router-dom';

const Admin = () => {
  const navigate = useNavigate();
  const { 
    user, orders, completeOrder, cancelOrder, products, 
    paymentMethods, updatePaymentMethod, addPaymentMethod, siteSettings, updateSiteSettings,
    categories, addCategory, deleteCategory, addProduct, deleteProduct, addProducts,
    blogs, addBlog, deleteBlog, agreements, addAgreement, deleteAgreement,
    comments, toggleCommentApproval, deleteComment, logout,
    usersList, adminUpdateUserPassword, toggleUserBan, generateResetLink,
    promoCodes, addPromoCode, deletePromoCode, togglePromoCode
  } = useApp();

  const [activeTab, setActiveTab] = useState<'dashboard' | 'orders' | 'products' | 'categories' | 'promos' | 'payments' | 'cms' | 'users' | 'settings'>('dashboard');
  const [cmsSubTab, setCmsSubTab] = useState<'blogs' | 'contracts' | 'comments'>('blogs');
  const [settingsSubTab, setSettingsSubTab] = useState<'general' | 'hero' | 'seo'>('general');
  const [productSubTab, setProductSubTab] = useState<'list' | 'add'>('list');
  const [mobileMenuOpen, setMobileMenuOpen] = useState(false);

  // Modals & Search
  const [viewReceipt, setViewReceipt] = useState<string | null>(null);
  const [deliveryModal, setDeliveryModal] = useState<{orderId: string, productTitle: string} | null>(null);
  const [deliveryContent, setDeliveryContent] = useState('');
  const [orderSearch, setOrderSearch] = useState('');

  // User Management
  const [resetModalUser, setResetModalUser] = useState<{id: string, name: string} | null>(null);
  const [userOrdersModal, setUserOrdersModal] = useState<string | null>(null); // UserId
  const [adminNewPassword, setAdminNewPassword] = useState('');
  const [generatedLink, setGeneratedLink] = useState<string | null>(null);
  const [showPasswords, setShowPasswords] = useState(false);

  // States for Dashboard Date Filter
  const [statsPeriod, setStatsPeriod] = useState<number>(1); // 1 = Today

  // Category Form
  const [newCatName, setNewCatName] = useState('');
  const [newCatImage, setNewCatImage] = useState('');
  const [newCatSeoTitle, setNewCatSeoTitle] = useState('');
  const [newCatSeoKeys, setNewCatSeoKeys] = useState('');

  // Promo Code Form
  const [newPromoCode, setNewPromoCode] = useState('');
  const [newPromoDiscount, setNewPromoDiscount] = useState(0);

  // Product Form
  const [productForm, setProductForm] = useState<Partial<Product> & { imageFile?: File | null }>({
    title: '', categoryId: '', price: 0, costPrice: 0, discountPercent: 0, type: ProductType.LICENSE_KEY, image: '', description: '', requiresInput: false, seoTitle: '', seoKeywords: ''
  });
  const fileInputRef = useRef<HTMLInputElement>(null);
  const catImageInputRef = useRef<HTMLInputElement>(null);
  const logoInputRef = useRef<HTMLInputElement>(null);
  const heroInputRef = useRef<HTMLInputElement>(null);
  const bulkInputRef = useRef<HTMLInputElement>(null);
  const [dragActive, setDragActive] = useState(false);

  if (!user || user.role !== 'admin') {
    return <div className="p-10 text-center text-red-500 font-bold text-2xl">Access Denied</div>;
  }

  // --- STATS LOGIC ---
  const getFilteredOrders = () => {
    const now = new Date();
    const past = new Date();

    // If statsPeriod is 1 (Today), we need to check only today's date string
    if (statsPeriod === 1) {
       return orders.filter(o => {
         const orderDate = new Date(o.date);
         return orderDate.toDateString() === now.toDateString() && o.status === OrderStatus.COMPLETED;
       });
    }

    past.setDate(now.getDate() - statsPeriod);
    past.setHours(0,0,0,0);

    return orders.filter(o => {
      const orderDate = new Date(o.date);
      return orderDate >= past && o.status === OrderStatus.COMPLETED;
    });
  };

  const filteredOrders = getFilteredOrders();
  const totalRevenue = filteredOrders.reduce((sum, o) => sum + (o.totalPrice || o.price || 0), 0);

  // --- HANDLERS ---

  const handleLogout = () => {
