  const handleBulkImport = (e: React.ChangeEvent<HTMLInputElement>) => {
      const file = e.target.files?.[0];
      if (!file) return;

      const reader = new FileReader();
      reader.onload = (event) => {
          const text = event.target?.result as string;
          if (!text) return;

          const lines = text.split('\n');
          const newProducts: Product[] = [];

          for (let i = 1; i < lines.length; i++) {
              const line = lines[i].trim();
              if (!line) continue;
              const cols = line.split(',');
              if (cols.length < 5) continue; 

              const [title, categoryId, typeStr, price, costPrice, discountPercent, description, image] = cols;

              let type = ProductType.LICENSE_KEY;
              if (typeStr === 'ID_LOAD') type = ProductType.ID_LOAD;
              if (typeStr === 'ACCOUNT') type = ProductType.ACCOUNT;

              newProducts.push({
                  id: `prod-${Date.now()}-${i}`,
                  title: title,
                  categoryId: categoryId,
                  type: type,
                  price: parseFloat(price) || 0,
                  costPrice: parseFloat(costPrice) || 0,
                  discountPercent: parseFloat(discountPercent) || 0,
                  description: description || '',
                  image: image || 'https://via.placeholder.com/150',
                  requiresInput: type === ProductType.ID_LOAD
              });
          }

          if (newProducts.length > 0) {
              addProducts(newProducts);
              alert(`${newProducts.length} məhsul uğurla əlavə edildi!`);
          } else {
              alert("Faylda düzgün məlumat tapılmadı.");
          }
      };
