         <div className="absolute inset-0 bg-gradient-to-t from-gaming-dark via-transparent to-black/30" />
         <div className="absolute bottom-0 left-0 w-full p-8 md:p-16 flex flex-col items-center justify-center text-center">
             <h1 className="text-4xl md:text-6xl font-black text-white mb-4 drop-shadow-lg tracking-tighter uppercase">{siteSettings.heroTitle}</h1>
             <p className="text-gray-200 text-lg md:text-xl max-w-2xl drop-shadow-md">{siteSettings.heroSubtitle}</p>
         </div>
      </div>

      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 -mt-8 relative z-20">

        {/* 2. SEARCH BAR */}
        <div className="bg-gaming-card border border-gray-700 rounded-2xl p-2 shadow-2xl flex items-center max-w-2xl mx-auto mb-16">
            <Search className="ml-4 text-gray-400 w-6 h-6" />
            <input 
              type="text" 
              placeholder="Məhsul axtar..." 
              value={search}
              onChange={(e) => setSearch(e.target.value)}
              className="w-full bg-transparent border-none text-white px-4 py-3 focus:ring-0 outline-none text-lg"
            />
            <button className="bg-gaming-neon text-black font-bold px-6 py-3 rounded-xl hover:bg-cyan-400 transition-colors">
                Axtar
            </button>
        </div>

        {/* 3. CATEGORIES */}
        <div className="mb-16">
            <div className="flex items-center justify-between mb-6">
                <h2 className="text-2xl font-bold text-white border-l-4 border-gaming-neon pl-4">Kateqoriyalar</h2>
            </div>

            <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
                {categories.map(cat => (
                    <div 
