                            <div className="w-full h-full bg-slate-800 flex items-center justify-center">
                                <span className="text-4xl">🎮</span>
                            </div>
                        )}
                        <div className="absolute inset-0 bg-black/50 group-hover:bg-black/30 transition-colors flex items-center justify-center">
                            <h3 className="text-xl font-bold text-white uppercase tracking-wider">{cat.name}</h3>
                        </div>
                    </div>
                ))}
            </div>
        </div>

        {/* 4. POPULAR PRODUCTS (Tabs) */}
        <div className="mb-16">
            <div className="flex flex-col md:flex-row md:items-center justify-between mb-8 gap-4">
                <h2 className="text-2xl font-bold text-white border-l-4 border-gaming-accent pl-4">Populyar Məhsullar</h2>

                {/* Category Tabs for Home Page Filter */}
                <div className="flex overflow-x-auto space-x-2 pb-2 scrollbar-hide">
                    <button
                        onClick={() => setActiveCat('All')}
                        className={`px-4 py-1.5 rounded-full text-sm font-bold transition-all whitespace-nowrap
                            ${activeCat === 'All' ? 'bg-white text-black' : 'bg-slate-800 text-gray-400 hover:bg-slate-700'}`}
                    >
                        Hamısı
                    </button>
                    {categories.map(cat => (
                        <button
                            key={cat.id}
                            onClick={() => setActiveCat(cat.id)}
                            className={`px-4 py-1.5 rounded-full text-sm font-bold transition-all whitespace-nowrap
                                ${activeCat === cat.id ? 'bg-white text-black' : 'bg-slate-800 text-gray-400 hover:bg-slate-700'}`}
                        >
                            {cat.name}
                        </button>
                    ))}
                </div>
            </div>

            {/* Product Grid */}
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6">
                {filteredProducts.map(product => (
                    <ProductCard key={product.id} product={product} />
                ))}
            </div>

            {filteredProducts.length === 0 && (
                <div className="text-center py-20 bg-slate-900/50 rounded-xl border border-gray-800">
                    <p className="text-gray-500 text-xl">Axtarışa uyğun məhsul tapılmadı.</p>
                </div>
