            ))}
        </div>

      </div>
    </div>
  );
};

export default Home;

import React, { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { useApp } from '../store';
import { Product } from '../types';
import { ArrowLeft, CheckCircle, ShieldCheck, ShoppingCart } from 'lucide-react';

const ProductView = () => {
  const { id } = useParams<{ id: string }>();
  const navigate = useNavigate();
  const { products, addToCart } = useApp();

  const [product, setProduct] = useState<Product | undefined>(undefined);
  const [userInput, setUserInput] = useState('');
  const [added, setAdded] = useState(false);

  useEffect(() => {
    const found = products.find(p => p.id === id);
    if (found) setProduct(found);
    else navigate('/');
  }, [id, products, navigate]);

  if (!product) return null;

  const handleAddToCart = () => {
    if (product.requiresInput && !userInput) {
      alert("Zəhmət olmasa tələb olunan məlumatı daxil edin.");
      return;
    }
    addToCart(product, userInput);

    // Show feedback instead of redirecting
    setAdded(true);
    setTimeout(() => setAdded(false), 2000);
  };

  const finalPrice = product.price - (product.price * (product.discountPercent / 100));

  return (
    <div className="min-h-screen bg-gaming-dark py-10 px-4">
      <div className="max-w-3xl mx-auto">
        <button onClick={() => navigate('/')} className="flex items-center text-gray-400 hover:text-white mb-6">
          <ArrowLeft className="w-4 h-4 mr-2" /> Mağazaya Qayıt
        </button>

        <div className="bg-gaming-card rounded-2xl border border-gray-800 overflow-hidden shadow-2xl animate-fade-in">
          <div className="p-6 md:p-8">
            <div className="flex flex-col md:flex-row gap-6 mb-8">
              <img src={product.image} alt={product.title} className="w-full md:w-1/3 rounded-lg object-cover aspect-video shadow-lg" />
              <div>
                <h1 className="text-2xl font-bold text-white mb-2">{product.title}</h1>
                <div className="flex items-center gap-2 mb-4">
                    <div className="text-gaming-accent font-bold text-2xl">{finalPrice.toFixed(2)} ₼</div>
                    {product.discountPercent > 0 && (
                        <span className="text-gray-500 line-through text-sm">{product.price.toFixed(2)} ₼</span>
                    )}
                </div>
                <p className="text-gray-400 text-sm leading-relaxed">{product.description}</p>
                <div className="mt-4 flex items-center gap-2 text-xs text-gray-500 bg-slate-900/50 p-2 rounded w-fit border border-gray-700">
                  <ShieldCheck className="w-4 h-4 text-green-500" />
                  <span>Manual Təsdiqləmə • Ani Təslimat</span>
                </div>
              </div>
            </div>

            {product.requiresInput && (
              <div className="mb-8 p-4 bg-slate-900/50 rounded-lg border border-gray-700">
                <label className="block text-sm font-medium text-gaming-neon mb-2">
                  {product.inputLabel || "Account ID / Link"} <span className="text-red-500">*</span>
                </label>
                <input
                  type="text"
                  value={userInput}
                  onChange={(e) => setUserInput(e.target.value)}
                  className="w-full bg-black border border-gray-600 rounded-lg p-3 text-white focus:ring-2 focus:ring-gaming-neon outline-none transition-all"
                  placeholder="Məlumatı bura daxil edin..."
                />
                <p className="text-xs text-gray-500 mt-2">Bu məlumat sifarişin yerinə yetirilməsi üçün vacibdir.</p>
              </div>
            )}

            <button
              onClick={handleAddToCart}
              className={`w-full font-bold py-4 rounded-lg transition-all flex items-center justify-center gap-2 shadow-lg transform hover:-translate-y-0.5
                  ${added ? 'bg-green-600 text-white' : 'bg-gaming-neon hover:bg-cyan-400 text-black'}`}
            >
              {added ? (
                  <>
                     <CheckCircle className="w-5 h-5" /> Səbətə Əlavə Edildi
                  </>
              ) : (
                  <>
                     <ShoppingCart className="w-5 h-5" /> Səbətə At
                  </>
              )}
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

export default ProductView;

import React, { useState, useRef } from 'react';
import { useApp } from '../store';
import { Order, OrderStatus, ProductType } from '../types';
import { Clock, CheckCircle, XCircle, Copy, Plus, CreditCard, Upload, Send, Loader2, Edit, Camera, Save, Lock, User as UserIcon, LogOut, Calendar } from 'lucide-react';
import { useNavigate } from 'react-router-dom';

const Profile = () => {
  const { user, orders, placeBalanceOrder, paymentMethods, updateUserProfile, changePassword, logout } = useApp();
  const navigate = useNavigate();
  const [activeTab, setActiveTab] = useState<'orders' | 'subscriptions' | 'security'>('orders');

  // Edit Profile State
  const [isEditing, setIsEditing] = useState(false);
  const [editName, setEditName] = useState(user?.name || '');
  const [editEmail, setEditEmail] = useState(user?.email || '');
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Change Password State
  const [currentPass, setCurrentPass] = useState('');
  const [newPass, setNewPass] = useState('');
  const [passMsg, setPassMsg] = useState('');

  const myOrders = orders.filter(o => o.userId === user?.id);

  // Filter subscriptions (Accounts with expiry or type Account)
  const mySubscriptions = myOrders.filter(o => 
     o.status === OrderStatus.COMPLETED && 
     (o.items.some(i => i.type === ProductType.ACCOUNT) || o.expiryDate)
  );

  const handleLogout = () => {
    logout();
    navigate('/');
  };

  const getStatusBadge = (status: OrderStatus) => {
    switch (status) {
      case OrderStatus.PENDING: 
        return (
          <span className="flex items-center gap-1 px-2 py-0.5 rounded text-xs font-bold text-yellow-400 bg-yellow-400/10 border border-yellow-400/20">
            <Clock className="w-3 h-3" /> Gözləmədə
          </span>
        );
      case OrderStatus.PROCESSING: 
        return (
          <span className="flex items-center gap-1 px-2 py-0.5 rounded text-xs font-bold text-blue-400 bg-blue-400/10 border border-blue-400/20">
            <Loader2 className="w-3 h-3 animate-spin" /> Emalda
          </span>
        );
      case OrderStatus.COMPLETED: 
        return (
          <span className="flex items-center gap-1 px-2 py-0.5 rounded text-xs font-bold text-green-400 bg-green-400/10 border border-green-400/20">
            <CheckCircle className="w-3 h-3" /> Tamamlandı
          </span>
        );
      case OrderStatus.CANCELLED: 
        return (
          <span className="flex items-center gap-1 px-2 py-0.5 rounded text-xs font-bold text-red-400 bg-red-400/10 border border-red-400/20">
            <XCircle className="w-3 h-3" /> Ləğv Edildi
          </span>
        );
    }
  };

  const copyToClipboard = (text: string) => {
    navigator.clipboard.writeText(text);
    alert("Kopyalandı!");
  };

  const handleAvatarUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
      const file = e.target.files?.[0];
      if (file) {
          const imageUrl = URL.createObjectURL(file);
          updateUserProfile({ avatar: imageUrl });
      }
  };

  const handleSaveProfile = () => {
      updateUserProfile({ name: editName, email: editEmail });
      setIsEditing(false);
  };

  const handleChangePassword = (e: React.FormEvent) => {
      e.preventDefault();
      if (changePassword(currentPass, newPass)) {
          setPassMsg("Şifrə uğurla dəyişdirildi!");
          setCurrentPass('');
          setNewPass('');
      } else {
          setPassMsg("Cari şifrə yanlışdır.");
      }
  };

  const getDaysRemaining = (expiryStr?: string) => {
     if(!expiryStr) return null;
     const expiry = new Date(expiryStr);
     const now = new Date();
     const diffTime = expiry.getTime() - now.getTime();
     const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));
     return diffDays > 0 ? diffDays : 0;
  };

  if(!user) return null;

  return (
    <div className="max-w-7xl mx-auto px-4 py-8">
      {/* Account Info Card */}
      <div className="flex flex-col md:flex-row items-center justify-between gap-6 mb-10 bg-gaming-card p-6 rounded-2xl border border-gray-800 relative overflow-hidden">
        <div className="absolute top-0 right-0 p-4 opacity-5 pointer-events-none">
            <CreditCard className="w-64 h-64" />
        </div>

        <div className="flex flex-col md:flex-row items-center gap-6 z-10 w-full">
            {/* Avatar Section */}
            <div className="relative group">
                <div className="w-24 h-24 rounded-full border-2 border-gaming-neon overflow-hidden bg-slate-800">
                    {user.avatar ? (
                        <img src={user.avatar} alt={user.name} className="w-full h-full object-cover" />
                    ) : (
                        <div className="w-full h-full flex items-center justify-center text-2xl font-bold text-gray-500">
                            {user.name.charAt(0)}
                        </div>
                    )}
                </div>
                <button 
                    onClick={() => fileInputRef.current?.click()}
                    className="absolute bottom-0 right-0 bg-slate-900 text-white p-2 rounded-full border border-gray-600 hover:bg-gaming-neon hover:text-black transition-colors"
                >
                    <Camera className="w-4 h-4" />
                </button>
                <input type="file" ref={fileInputRef} hidden accept="image/*" onChange={handleAvatarUpload} />
            </div>

            {/* Info Section */}
            <div className="text-center md:text-left flex-1 space-y-2">
                {isEditing ? (
                    <div className="space-y-2 max-w-sm">
                        <input 
                            type="text" 
                            className="bg-slate-900 border border-gray-700 rounded px-3 py-1 text-white w-full"
                            value={editName}
                            onChange={e => setEditName(e.target.value)}
                            placeholder="Ad Soyad"
                        />
                        <input 
                            type="email" 
                            className="bg-slate-900 border border-gray-700 rounded px-3 py-1 text-white w-full"
                            value={editEmail}
                            onChange={e => setEditEmail(e.target.value)}
                            placeholder="Email"
                        />
                        <div className="flex gap-2 mt-2">
                             <button onClick={handleSaveProfile} className="bg-green-600 px-3 py-1 rounded text-sm flex items-center gap-1 hover:bg-green-700"><Save className="w-3 h-3"/> Yadda Saxla</button>
                             <button onClick={() => setIsEditing(false)} className="bg-gray-700 px-3 py-1 rounded text-sm hover:bg-gray-600">Ləğv Et</button>
                        </div>
                    </div>
                ) : (
                    <>
                        <h1 className="text-2xl font-bold text-white flex items-center justify-center md:justify-start gap-2">
                            {user.name} 
                            <button onClick={() => { setIsEditing(true); setEditName(user.name); setEditEmail(user.email); }} className="text-gray-500 hover:text-white"><Edit className="w-4 h-4" /></button>
                        </h1>
                        <p className="text-gray-400">{user.email}</p>
                        <p className="text-gray-500 text-sm">{user.phone || 'Mobil nömrə yoxdur'}</p>
                    </>
                )}
            </div>

            {/* Balance Section */}
            <div className="flex flex-col gap-3 min-w-[200px]">
                <div className="bg-slate-900/80 backdrop-blur-sm p-4 rounded-xl border border-gray-700 text-center">
                    <p className="text-gray-400 text-sm mb-1">Mövcud Balans</p>
                    <p className="text-3xl font-mono font-bold text-gaming-neon">{user.balance.toFixed(2)} ₼</p>
                    <button onClick={() => navigate('/balance')} className="mt-3 w-full bg-gaming-neon text-black font-bold py-2 rounded text-sm hover:bg-cyan-400 flex items-center justify-center gap-2">
                        <Plus className="w-4 h-4" /> Balans Artır
                    </button>
                </div>

                <button 
                  onClick={handleLogout}
                  className="w-full bg-red-900/20 hover:bg-red-900/40 text-red-500 border border-red-900/50 font-bold py-3 rounded-xl transition-colors flex items-center justify-center gap-2"
                >
                    <LogOut className="w-5 h-5" /> Çıxış Et
                </button>
            </div>
        </div>
      </div>

      <div className="flex gap-4 mb-6 border-b border-gray-800 pb-2 overflow-x-auto">
          <button onClick={() => setActiveTab('orders')} className={`pb-2 font-bold whitespace-nowrap ${activeTab === 'orders' ? 'text-gaming-neon border-b-2 border-gaming-neon' : 'text-gray-400'}`}>Sifariş Tarixçəsi</button>
          <button onClick={() => setActiveTab('subscriptions')} className={`pb-2 font-bold whitespace-nowrap ${activeTab === 'subscriptions' ? 'text-gaming-neon border-b-2 border-gaming-neon' : 'text-gray-400'}`}>Abunəliklərim</button>
          <button onClick={() => setActiveTab('security')} className={`pb-2 font-bold whitespace-nowrap ${activeTab === 'security' ? 'text-gaming-neon border-b-2 border-gaming-neon' : 'text-gray-400'}`}>Təhlükəsizlik</button>
      </div>

      {activeTab === 'orders' && (
        <div className="space-y-4 animate-fade-in">
            {myOrders.length === 0 ? (
            <p className="text-gray-500">Hələ heç bir sifariş yoxdur.</p>
            ) : (
            myOrders.map(order => (
                <div key={order.id} className="bg-gaming-card rounded-xl p-6 border border-gray-800 hover:border-gray-700 transition-all">
                <div className="flex flex-col md:flex-row justify-between md:items-center gap-4">

                    <div className="flex-1">
                    <div className="flex items-center gap-3 mb-1">
                        <h3 className="text-lg font-bold text-white">{order.productTitle || (order.items && order.items.length > 0 ? order.items[0].title : 'Order')} {order.items && order.items.length > 1 && `(+${order.items.length - 1} digər)`}</h3>
                        {getStatusBadge(order.status)}
                    </div>
                    <div className="text-sm text-gray-400">
                        ID: {order.id} • {new Date(order.date).toLocaleDateString()}
                    </div>
                    </div>

                    <div className="text-right">
                        <div className="text-xl font-bold text-white">{order.totalPrice ? order.totalPrice.toFixed(2) : (order.price || 0).toFixed(2)} ₼</div>
                        <div className="text-sm text-gray-500">{order.paymentMethodName}</div>
                    </div>

                </div>

                {/* Delivery Section */}
                {order.status === OrderStatus.COMPLETED && order.deliveredContent && (
                    <div className="mt-4 pt-4 border-t border-gray-800 bg-slate-900/50 -mx-6 -mb-6 px-6 py-4 rounded-b-xl">
                    <p className="text-xs text-green-400 mb-1 uppercase font-bold tracking-wider flex items-center gap-1">
                        <CheckCircle className="w-3 h-3" /> Təslimat
                    </p>
                    <div className="flex items-center gap-2 bg-black/40 p-3 rounded border border-gray-700">
                        <code className="text-gaming-neon font-mono flex-1 break-all">{order.deliveredContent}</code>
                        <button 
                        onClick={() => copyToClipboard(order.deliveredContent!)}
                        className="p-2 hover:bg-gray-700 rounded text-gray-400 hover:text-white"
                        >
                        <Copy className="w-4 h-4" />
                        </button>
                    </div>
                    </div>
                )}
                </div>
            ))
            )}
        </div>
      )}

      {activeTab === 'subscriptions' && (
          <div className="space-y-4 animate-fade-in">
             {mySubscriptions.length === 0 ? (
                 <div className="text-center py-10 border border-dashed border-gray-700 rounded-xl">
                     <p className="text-gray-500">Aktiv abunəlik tapılmadı.</p>
                 </div>
             ) : (
                 mySubscriptions.map(sub => {
                     const daysLeft = getDaysRemaining(sub.expiryDate);
                     return (
                         <div key={sub.id} className="bg-gaming-card p-6 rounded-xl border border-gray-800 flex flex-col md:flex-row gap-6">
                              <div className="flex-1">
                                  <h3 className="text-xl font-bold text-white mb-2">{sub.items[0].title}</h3>
                                  <div className="bg-black/30 p-3 rounded border border-gray-700 inline-block mb-4">
                                      <p className="text-xs text-gray-400 mb-1">Hesab Məlumatları</p>
                                      <code className="text-gaming-neon">{sub.deliveredContent}</code>
                                  </div>
                              </div>
                              <div className="w-full md:w-64 bg-slate-900 p-4 rounded-xl border border-gray-700 flex flex-col items-center justify-center text-center">
                                  {daysLeft !== null ? (
                                      <>
                                          <p className="text-gray-400 text-xs uppercase font-bold mb-2">Bitməyinə qalıb</p>
                                          <div className={`text-4xl font-black ${daysLeft < 3 ? 'text-red-500' : 'text-green-400'}`}>
                                              {daysLeft} GÜN
                                          </div>
                                          <p className="text-xs text-gray-500 mt-2">Bitmə tarixi: {sub.expiryDate && new Date(sub.expiryDate).toLocaleDateString()}</p>
                                      </>
                                  ) : (
                                      <p className="text-gray-500">Müddət təyin edilməyib</p>
                                  )}
                              </div>
                         </div>
                     )
                 })
             )}
          </div>
      )}

      {activeTab === 'security' && (
          <div className="max-w-md bg-gaming-card p-6 rounded-xl border border-gray-800 animate-fade-in">
              <h3 className="text-xl font-bold text-white mb-4 flex items-center gap-2"><Lock className="w-5 h-5"/> Şifrəni Dəyiş</h3>
              <form onSubmit={handleChangePassword} className="space-y-4">
                  <div>
                      <label className="text-xs text-gray-400 block mb-1">Cari Şifrə</label>
                      <input type="password" required className="w-full bg-slate-900 border border-gray-700 rounded p-2 text-white" value={currentPass} onChange={e => setCurrentPass(e.target.value)} />
                  </div>
                  <div>
                      <label className="text-xs text-gray-400 block mb-1">Yeni Şifrə</label>
                      <input type="password" required className="w-full bg-slate-900 border border-gray-700 rounded p-2 text-white" value={newPass} onChange={e => setNewPass(e.target.value)} />
                  </div>
                  {passMsg && <p className={`text-sm ${passMsg.includes('uğurla') ? 'text-green-500' : 'text-red-500'}`}>{passMsg}</p>}
                  <button type="submit" className="w-full bg-blue-600 hover:bg-blue-700 text-white font-bold py-2 rounded">Yadda Saxla</button>
              </form>
          </div>
      )}
    </div>
  );
};

