                            Girişə Qayıt
                        </button>
                    </div>
                )}

                {forgotStep === 1 && (
                    <button type="button" onClick={() => setView('login')} className="w-full text-gray-400 text-sm hover:text-white mt-2 flex items-center justify-center gap-1">
