                )}
             </div>
         ) : (
            <form onSubmit={handleSubmit} className="space-y-4">
                {view === 'register' && (
                  <div className="relative">
                    <User className="absolute left-3 top-3.5 text-gray-500 w-5 h-5" />
                    <input 
