                 <Link to="/auth" className="bg-gaming-neon text-black px-3 py-1.5 rounded-lg text-xs font-bold flex items-center gap-1 hover:bg-cyan-400 transition-colors">
                    <LogIn className="w-3 h-3" /> Giriş
                 </Link>
             )}

             <button
              onClick={() => setIsOpen(!isOpen)}
              className="inline-flex items-center justify-center p-2 rounded-md text-gray-400 hover:text-white hover:bg-gray-700 focus:outline-none"
            >
              {isOpen ? <X className="h-6 w-6" /> : <Menu className="h-6 w-6" />}
            </button>
          </div>
        </div>
      </div>

      {/* Mobile menu (Drawer) */}
      {isOpen && (
        <div className="lg:hidden bg-gaming-card border-b border-gray-700">
          <div className="px-2 pt-2 pb-3 space-y-1 sm:px-3">
            {isAuthenticated && (
               <div className="px-3 py-2 mb-2 flex items-center gap-2 text-gaming-neon font-bold border-b border-gray-700 pb-3">
                 <Wallet className="w-5 h-5" /> Balans: {user?.balance.toFixed(2)} ₼
               </div>
            )}

            {navLinks.map((link, idx) => (
                <Link key={idx} to={link.path} onClick={() => setIsOpen(false)} className="text-gray-300 hover:text-white block px-3 py-2 rounded-md text-base font-medium">
                    {link.name}
                </Link>
            ))}

            {isAuthenticated && (
              <Link to="/profile" onClick={() => setIsOpen(false)} className="text-gray-300 hover:text-white block px-3 py-2 rounded-md text-base font-medium">Profilim</Link>
            )}
             {user?.role === 'admin' && (
                  <Link to="/admin" onClick={() => setIsOpen(false)} className="text-red-400 hover:text-white block px-3 py-2 rounded-md text-base font-medium">Admin Panel</Link>
            )}

            {!isAuthenticated && (
                <Link to="/auth" onClick={() => setIsOpen(false)} className="mt-4 w-full bg-gaming-neon text-black block text-center px-3 py-3 rounded-lg text-base font-bold">
                    Qeydiyyatdan Keç
                </Link>
            )}
          </div>
        </div>
      )}
    </nav>
  );
};

export default Navbar;

import React, { useState, useRef } from 'react';
import { useApp } from '../store';
import { Order, OrderStatus, ProductType, Product, Category, PromoCode } from '../types';
import { 
