import React, { useState, useRef } from 'react';
import { useApp } from '../store';
import { Order, OrderStatus, ProductType } from '../types';
import { Clock, CheckCircle, XCircle, Copy, Plus, CreditCard, Upload, Send, Loader2, Edit, Camera, Save, Lock, User as UserIcon, LogOut, Calendar, Package, TrendingUp, Shield, Filter, AlertTriangle } from 'lucide-react';
import { useNavigate } from 'react-router-dom';

const Profile = () => {
  const { user, orders, updateUserProfile, changePassword, logout } = useApp();
  const navigate = useNavigate();
  const [activeTab, setActiveTab] = useState<'orders' | 'subscriptions' | 'settings'>('orders');

  // Logical Addition: Order Filter State
  const [orderFilter, setOrderFilter] = useState<'ALL' | OrderStatus>('ALL');

  // Edit Profile State
  const [isEditing, setIsEditing] = useState(false);
  const [editName, setEditName] = useState(user?.name || '');
  const [editEmail, setEditEmail] = useState(user?.email || '');
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Change Password State
  const [currentPass, setCurrentPass] = useState('');
  const [newPass, setNewPass] = useState('');
  const [passMsg, setPassMsg] = useState('');

  const myOrders = orders.filter(o => o.userId === user?.id).sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());

  // Filtered orders logic
  const filteredOrders = myOrders.filter(o => orderFilter === 'ALL' || o.status === orderFilter);

  // Stats
  const totalSpent = myOrders.filter(o => o.status === OrderStatus.COMPLETED).reduce((acc, curr) => acc + (curr.totalPrice || 0), 0);
  const completedOrdersCount = myOrders.filter(o => o.status === OrderStatus.COMPLETED).length;

  // Filter subscriptions
  const mySubscriptions = myOrders.filter(o => 
     o.status === OrderStatus.COMPLETED && 
     (o.items.some(i => i.type === ProductType.ACCOUNT) || o.expiryDate)
  );

  const handleLogout = () => {
    logout();
    navigate('/');
  };

  const getStatusBadge = (status: OrderStatus) => {
    switch (status) {
      case OrderStatus.PENDING: 
        return <span className="bg-yellow-500/10 text-yellow-500 border border-yellow-500/20 px-2 py-1 rounded text-xs font-bold flex items-center gap-1"><Clock className="w-3 h-3"/> Gözləmədə</span>;
      case OrderStatus.PROCESSING: 
        return <span className="bg-blue-500/10 text-blue-500 border border-blue-500/20 px-2 py-1 rounded text-xs font-bold flex items-center gap-1"><Loader2 className="w-3 h-3 animate-spin"/> Emalda</span>;
      case OrderStatus.COMPLETED: 
        return <span className="bg-green-500/10 text-green-500 border border-green-500/20 px-2 py-1 rounded text-xs font-bold flex items-center gap-1"><CheckCircle className="w-3 h-3"/> Tamamlandı</span>;
      case OrderStatus.CANCELLED: 
        return <span className="bg-red-500/10 text-red-500 border border-red-500/20 px-2 py-1 rounded text-xs font-bold flex items-center gap-1"><XCircle className="w-3 h-3"/> Ləğv</span>;
    }
  };

  const copyToClipboard = (text: string) => {
    navigator.clipboard.writeText(text);
    // Logical enhancement: Change button text temporarily or use alert
    alert("Kopyalandı!"); 
  };

  const handleAvatarUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
      const file = e.target.files?.[0];
      if (file) {
          const imageUrl = URL.createObjectURL(file);
          updateUserProfile({ avatar: imageUrl });
      }
  };

  const handleSaveProfile = () => {
      updateUserProfile({ name: editName, email: editEmail });
      setIsEditing(false);
  };

  const handleChangePassword = (e: React.FormEvent) => {
      e.preventDefault();
      if (changePassword(currentPass, newPass)) {
          setPassMsg("Şifrə uğurla dəyişdirildi!");
          setCurrentPass('');
          setNewPass('');
      } else {
          setPassMsg("Cari şifrə yanlışdır.");
      }
  };

  const getDaysRemaining = (expiryStr?: string) => {
     if(!expiryStr) return 0;
     const expiry = new Date(expiryStr);
     const now = new Date();
     const diffTime = expiry.getTime() - now.getTime();
     const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));
     return diffDays > 0 ? diffDays : 0;
  };

  if(!user) return null;

  return (
    <div className="min-h-screen bg-gaming-dark py-10 px-4">
      <div className="max-w-7xl mx-auto">

        {/* Main Dashboard Layout */}
        <div className="grid grid-cols-1 lg:grid-cols-4 gap-8">

            {/* Sidebar / User Info */}
            <div className="lg:col-span-1 space-y-6">
                {/* User Card */}
                <div className="bg-slate-900/50 backdrop-blur-xl border border-gray-800 rounded-3xl p-6 text-center relative overflow-hidden group">
                    <div className="absolute top-0 left-0 w-full h-24 bg-gradient-to-b from-gaming-neon/20 to-transparent"></div>

                    <div className="relative inline-block mb-4">
                        <div className="w-28 h-28 rounded-full border-4 border-slate-900 bg-slate-800 overflow-hidden shadow-2xl relative">
                            {user.avatar ? (
                                <img src={user.avatar} alt={user.name} className="w-full h-full object-cover" />
                            ) : (
                                <div className="w-full h-full flex items-center justify-center text-3xl font-bold text-gray-500">{user.name.charAt(0)}</div>
                            )}
                        </div>
                        <button onClick={() => fileInputRef.current?.click()} className="absolute bottom-1 right-1 bg-gaming-neon text-black p-2 rounded-full hover:scale-110 transition-transform shadow-lg">
                            <Camera className="w-4 h-4" />
                        </button>
                        <input type="file" ref={fileInputRef} hidden accept="image/*" onChange={handleAvatarUpload} />
                    </div>

                    {isEditing ? (
                        <div className="space-y-2 mb-4">
                            <input className="w-full bg-black/30 border border-gray-600 rounded px-3 py-2 text-center text-sm text-white" value={editName} onChange={e => setEditName(e.target.value)} />
                            <input className="w-full bg-black/30 border border-gray-600 rounded px-3 py-2 text-center text-sm text-white" value={editEmail} onChange={e => setEditEmail(e.target.value)} />
                            <div className="flex justify-center gap-2">
                                <button onClick={handleSaveProfile} className="bg-green-600 p-2 rounded text-white"><Save className="w-4 h-4"/></button>
                                <button onClick={() => setIsEditing(false)} className="bg-red-600 p-2 rounded text-white"><XCircle className="w-4 h-4"/></button>
                            </div>
                        </div>
                    ) : (
                        <>
                            <h2 className="text-xl font-bold text-white flex items-center justify-center gap-2">
                                {user.name}
                                <button onClick={() => { setIsEditing(true); setEditName(user.name); setEditEmail(user.email); }} className="text-gray-500 hover:text-white"><Edit className="w-3 h-3" /></button>
                            </h2>
                            <p className="text-gray-400 text-sm mb-6">{user.email}</p>
                        </>
                    )}

                    <div className="bg-black/30 rounded-xl p-4 border border-gray-700/50 mb-6">
                        <p className="text-gray-400 text-xs uppercase font-bold tracking-wider mb-1">Balans</p>
                        <p className="text-3xl font-mono font-bold text-gaming-neon">{user.balance.toFixed(2)} ₼</p>
                        <button onClick={() => navigate('/balance')} className="mt-3 w-full bg-gaming-neon hover:bg-cyan-400 text-black font-bold py-2 rounded-lg text-sm transition-colors flex items-center justify-center gap-2">
                            <Plus className="w-4 h-4" /> Artır
                        </button>
                    </div>

                    <button onClick={handleLogout} className="text-red-400 hover:text-red-300 text-sm font-medium flex items-center justify-center gap-2 w-full py-2 hover:bg-red-500/10 rounded-lg transition-colors">
                        <LogOut className="w-4 h-4" /> Çıxış Et
                    </button>
                </div>

                {/* Quick Stats */}
                <div className="bg-slate-900/50 border border-gray-800 rounded-3xl p-6 space-y-4">
                    <div className="flex items-center justify-between p-3 bg-black/20 rounded-xl">
                        <div className="flex items-center gap-3">
                            <div className="bg-blue-500/20 p-2 rounded-lg text-blue-400"><Package className="w-5 h-5"/></div>
                            <div>
                                <p className="text-xs text-gray-400">Sifarişlər</p>
                                <p className="font-bold text-white">{completedOrdersCount}</p>
                            </div>
                        </div>
                    </div>
                    <div className="flex items-center justify-between p-3 bg-black/20 rounded-xl">
                        <div className="flex items-center gap-3">
                            <div className="bg-green-500/20 p-2 rounded-lg text-green-400"><TrendingUp className="w-5 h-5"/></div>
                            <div>
                                <p className="text-xs text-gray-400">Xərclənən</p>
                                <p className="font-bold text-white">{totalSpent.toFixed(2)} ₼</p>
                            </div>
                        </div>
                    </div>
                </div>
            </div>

            {/* Main Content Area */}
            <div className="lg:col-span-3">
                {/* Navigation Tabs */}
                <div className="flex items-center gap-2 mb-8 overflow-x-auto pb-2 scrollbar-hide">
                    {[
                        { id: 'orders', label: 'Sifariş Tarixçəsi', icon: Clock },
                        { id: 'subscriptions', label: 'Abunəliklər', icon: Calendar },
                        { id: 'settings', label: 'Tənzimləmələr', icon: Shield },
                    ].map(tab => (
                        <button
                            key={tab.id}
                            onClick={() => setActiveTab(tab.id as any)}
                            className={`flex items-center gap-2 px-6 py-3 rounded-full font-bold text-sm transition-all whitespace-nowrap
                                ${activeTab === tab.id 
                                    ? 'bg-white text-black shadow-lg shadow-white/10 scale-105' 
                                    : 'bg-slate-800 text-gray-400 hover:bg-slate-700 hover:text-white'}`}
                        >
                            <tab.icon className="w-4 h-4" /> {tab.label}
                        </button>
                    ))}
                </div>

                <div className="bg-slate-900/30 border border-gray-800 rounded-3xl p-6 min-h-[500px]">
                    {activeTab === 'orders' && (
                        <div className="space-y-4 animate-fade-in">
                            {/* Logical Feature: Order Status Filters */}
                            <div className="flex gap-2 mb-4 overflow-x-auto pb-2">
                                <button onClick={() => setOrderFilter('ALL')} className={`px-4 py-1.5 rounded-lg text-xs font-bold ${orderFilter === 'ALL' ? 'bg-gaming-neon text-black' : 'bg-slate-800 text-gray-400'}`}>Hamısı</button>
                                <button onClick={() => setOrderFilter(OrderStatus.PENDING)} className={`px-4 py-1.5 rounded-lg text-xs font-bold ${orderFilter === OrderStatus.PENDING ? 'bg-yellow-500 text-black' : 'bg-slate-800 text-gray-400'}`}>Gözləmədə</button>
                                <button onClick={() => setOrderFilter(OrderStatus.PROCESSING)} className={`px-4 py-1.5 rounded-lg text-xs font-bold ${orderFilter === OrderStatus.PROCESSING ? 'bg-blue-500 text-white' : 'bg-slate-800 text-gray-400'}`}>Emalda</button>
                                <button onClick={() => setOrderFilter(OrderStatus.COMPLETED)} className={`px-4 py-1.5 rounded-lg text-xs font-bold ${orderFilter === OrderStatus.COMPLETED ? 'bg-green-500 text-white' : 'bg-slate-800 text-gray-400'}`}>Tamamlandı</button>
                            </div>

                            {filteredOrders.length === 0 ? (
                                <div className="text-center py-20 flex flex-col items-center">
                                    <Package className="w-16 h-16 text-gray-600 mb-4" />
                                    <p className="text-gray-400 text-lg">Bu statusda sifariş tapılmadı.</p>
                                    <button onClick={() => navigate('/')} className="mt-4 text-gaming-neon font-bold hover:underline">Alış-verişə Başla</button>
                                </div>
                            ) : (
                                filteredOrders.map(order => (
                                    <div key={order.id} className="bg-slate-800 rounded-2xl p-5 border border-gray-700 hover:border-gaming-neon/50 transition-colors group">
                                        <div className="flex flex-col md:flex-row gap-5 items-start md:items-center">
                                            {/* Image Thumbnail */}
                                            <div className="w-16 h-16 bg-black rounded-lg overflow-hidden shrink-0 border border-gray-600">
                                                {order.items && order.items[0]?.image ? (
                                                    <img src={order.items[0].image} alt="" className="w-full h-full object-cover" />
                                                ) : (
                                                    <div className="w-full h-full flex items-center justify-center text-gray-500"><Package className="w-6 h-6"/></div>
                                                )}
                                            </div>

                                            <div className="flex-1">
                                                <div className="flex flex-wrap justify-between items-start mb-1">
                                                    <h3 className="font-bold text-white text-lg">
                                                        {order.productTitle || (order.items && order.items[0]?.title)}
                                                        {order.items && order.items.length > 1 && <span className="text-gray-500 text-sm ml-2">+{order.items.length - 1} digər</span>}
                                                    </h3>
                                                    <span className="font-mono font-bold text-gaming-neon">{order.totalPrice ? order.totalPrice.toFixed(2) : order.price?.toFixed(2)} ₼</span>
                                                </div>
                                                <div className="flex flex-wrap items-center gap-3 text-sm text-gray-400">
                                                    <span>#{order.id.slice(-6).toUpperCase()}</span>
                                                    <span className="w-1 h-1 bg-gray-600 rounded-full"></span>
                                                    <span>{new Date(order.date).toLocaleDateString()}</span>
                                                    <span className="w-1 h-1 bg-gray-600 rounded-full"></span>
                                                    {getStatusBadge(order.status)}
                                                </div>
                                            </div>
                                        </div>

                                        {/* Delivered Content Box */}
                                        {order.status === OrderStatus.COMPLETED && order.deliveredContent && (
                                            <div className="mt-4 bg-black/40 rounded-xl p-3 border border-gray-700/50 flex items-center gap-3">
                                                <div className="p-2 bg-green-500/10 rounded-lg">
                                                    <CheckCircle className="w-5 h-5 text-green-500" />
                                                </div>
                                                <div className="flex-1 overflow-hidden">
                                                    <p className="text-xs text-gray-500 mb-0.5">Təslimat Məlumatı</p>
                                                    <code className="text-white font-mono text-sm block truncate">{order.deliveredContent}</code>
                                                </div>
                                                <button onClick={() => copyToClipboard(order.deliveredContent!)} className="p-2 hover:bg-gray-700 rounded text-gray-400 hover:text-white transition-colors">
                                                    <Copy className="w-4 h-4" />
                                                </button>
                                            </div>
                                        )}
                                    </div>
                                ))
                            )}
                        </div>
                    )}

                    {activeTab === 'subscriptions' && (
                        <div className="grid grid-cols-1 md:grid-cols-2 gap-4 animate-fade-in">
                            {mySubscriptions.length === 0 ? (
                                <div className="col-span-full text-center py-20 text-gray-500">Aktiv abunəlik tapılmadı.</div>
                            ) : (
                                mySubscriptions.map(sub => {
                                    const daysLeft = getDaysRemaining(sub.expiryDate);
                                    const totalDuration = sub.items[0]?.durationDays || 30; // Default to 30 if undefined
                                    const progressPercent = Math.max(0, Math.min(100, (daysLeft / totalDuration) * 100));

                                    return (
                                        <div key={sub.id} className="bg-gradient-to-br from-slate-800 to-slate-900 p-6 rounded-2xl border border-gray-700 relative overflow-hidden flex flex-col justify-between h-full">
                                            {/* Status Dot */}
                                            <div className={`absolute top-4 right-4 w-3 h-3 rounded-full ${daysLeft > 3 ? 'bg-green-500 shadow-[0_0_10px_rgba(34,197,94,0.5)]' : 'bg-red-500 shadow-[0_0_10px_rgba(239,68,68,0.5)] animate-pulse'}`}></div>

                                            <div>
                                                <div className="flex justify-between items-start mb-4">
                                                    <div className="bg-gaming-accent/20 p-2 rounded-lg text-gaming-accent">
                                                        <Calendar className="w-6 h-6" />
                                                    </div>
                                                </div>
                                                <h3 className="font-bold text-white text-lg mb-1 truncate">{sub.items[0].title}</h3>

                                                {/* Visual Progress Bar */}
                                                <div className="w-full bg-slate-700 h-2 rounded-full mt-4 mb-2 overflow-hidden">
                                                    <div 
                                                        className={`h-full rounded-full transition-all duration-1000 ${daysLeft < 5 ? 'bg-red-500' : 'bg-gaming-neon'}`} 
                                                        style={{ width: `${progressPercent}%` }}
                                                    ></div>
                                                </div>

                                                <div className="flex justify-between text-xs font-medium mb-4">
                                                    <span className="text-gray-400">Qalan vaxt:</span>
                                                    <span className={`${daysLeft < 3 ? 'text-red-400' : 'text-white'}`}>{daysLeft} GÜN</span>
                                                </div>

                                                <div className="flex items-center gap-2 text-xs text-gray-500 mb-4 bg-black/20 p-2 rounded border border-gray-700/50">
                                                    <Clock className="w-3 h-3" /> 
                                                    Bitmə Tarixi: {sub.expiryDate ? new Date(sub.expiryDate).toLocaleDateString('az-AZ', { day: 'numeric', month: 'long', year: 'numeric' }) : 'N/A'}
                                                </div>
                                            </div>

                                            <div className="bg-black/30 p-3 rounded-xl border border-gray-700 flex justify-between items-center mt-auto">
                                                <div>
                                                    <p className="text-[10px] text-gray-500 uppercase font-bold">Giriş Məlumatı</p>
                                                    <code className="text-xs text-white truncate max-w-[150px] block">{sub.deliveredContent}</code>
                                                </div>
                                                <button onClick={() => copyToClipboard(sub.deliveredContent!)} className="p-2 hover:bg-slate-700 rounded-lg transition-colors"><Copy className="w-4 h-4 text-gray-400 hover:text-white"/></button>
                                            </div>
                                        </div>
                                    )
                                })
                            )}
                        </div>
                    )}

                    {activeTab === 'settings' && (
                        <div className="max-w-lg mx-auto animate-fade-in space-y-6">
                            <div className="bg-slate-800 p-6 rounded-2xl border border-gray-700">
                                <h3 className="font-bold text-white mb-4 flex items-center gap-2">
                                    <Lock className="w-5 h-5 text-gaming-neon"/> Şifrəni Dəyiş
                                </h3>
                                <form onSubmit={handleChangePassword} className="space-y-4">
                                    <div>
                                        <label className="text-xs text-gray-400 block mb-1">Cari Şifrə</label>
                                        <input type="password" required className="w-full bg-slate-900 border border-gray-600 rounded-lg p-3 text-white focus:border-gaming-neon outline-none" value={currentPass} onChange={e => setCurrentPass(e.target.value)} />
                                    </div>
                                    <div>
                                        <label className="text-xs text-gray-400 block mb-1">Yeni Şifrə</label>
                                        <input type="password" required className="w-full bg-slate-900 border border-gray-600 rounded-lg p-3 text-white focus:border-gaming-neon outline-none" value={newPass} onChange={e => setNewPass(e.target.value)} />
                                    </div>
                                    {passMsg && <p className={`text-sm ${passMsg.includes('uğurla') ? 'text-green-500' : 'text-red-500'}`}>{passMsg}</p>}
                                    <button type="submit" className="w-full bg-blue-600 hover:bg-blue-700 text-white font-bold py-3 rounded-lg transition-colors">Yadda Saxla</button>
                                </form>
                            </div>
                        </div>
                    )}
                </div>
            </div>
        </div>
      </div>
    </div>
  );
};

export default Profile;

export enum ProductType {
  ID_LOAD = 'ID_LOAD',       
  LICENSE_KEY = 'LICENSE_KEY', 
  ACCOUNT = 'ACCOUNT',
  BALANCE = 'BALANCE' // New type for wallet top-up
}

export enum OrderStatus {
  PENDING = 'PENDING',
  PROCESSING = 'PROCESSING',
  COMPLETED = 'COMPLETED',
  CANCELLED = 'CANCELLED'
}

export interface Category {
  id: string;
  name: string;
  image?: string; // Added image for categories
  icon?: string;
  seoTitle?: string;
  seoKeywords?: string;
}

export interface Product {
  id: string;
  title: string;
  categoryId: string;
  type: ProductType;
  price: number;        
  costPrice: number;    
  discountPercent: number; 
  image: string;
  description: string;
  requiresInput?: boolean;
  inputLabel?: string;
  seoTitle?: string;
  seoKeywords?: string;
  durationDays?: number; // For subscriptions (e.g., 30 days)
}

export interface CartItem {
  productId: string;
  title: string;
  price: number;
  image: string;
  type: ProductType;
  userInput?: string; // e.g. Player ID
  quantity: number; // Added quantity
  durationDays?: number;
}

export interface Blog {
  id: string;
  title: string;
  content: string;
  date: string;
  image: string;
}

export interface Agreement {
  id: string;
  title: string; 
  content: string;
}

export interface Comment {
  id: string;
  author: string;
  content: string;
  type: 'product' | 'blog' | 'site';
  targetId?: string; 
  isApproved: boolean;
  date: string;
}

export interface PaymentMethod {
  id: string;
  name: string;
  details: string; 
