import React, { useState, useRef } from 'react';
import { useApp } from '../store';
import { OrderStatus, ProductType } from '../types';
import { Clock, CheckCircle, XCircle, Copy, Plus, CreditCard, Upload, Send, Loader2, Edit, Camera, Save, Lock, User as UserIcon, LogOut, Calendar, Package, TrendingUp, Shield, Trophy, Star, Crown, Zap, Gift, Swords, Gamepad2, Skull } from 'lucide-react';
import { useNavigate } from 'react-router-dom';

const Profile = () => {
  const { user, orders, updateUserProfile, changePassword, logout } = useApp();
  const navigate = useNavigate();
  const [activeTab, setActiveTab] = useState<'inventory' | 'quests' | 'settings'>('inventory');

  // Logical Addition: Order Filter State
  const [orderFilter, setOrderFilter] = useState<'ALL' | OrderStatus>('ALL');

  // Edit Profile State
  const [isEditing, setIsEditing] = useState(false);
  const [editName, setEditName] = useState(user?.name || '');
  const [editEmail, setEditEmail] = useState(user?.email || '');
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Change Password State
  const [currentPass, setCurrentPass] = useState('');
  const [newPass, setNewPass] = useState('');
  const [passMsg, setPassMsg] = useState('');

  const myOrders = orders.filter(o => o.userId === user?.id).sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());

  // Filtered orders logic
  const filteredOrders = myOrders.filter(o => orderFilter === 'ALL' || o.status === orderFilter);

  // Stats
  const totalSpent = myOrders.filter(o => o.status === OrderStatus.COMPLETED).reduce((acc, curr) => acc + (curr.totalPrice || 0), 0);

  // Filter subscriptions - STRICTLY ACCOUNT TYPE
  const mySubscriptions = myOrders.filter(o => 
     o.status === OrderStatus.COMPLETED && 
     o.items.some(i => i.type === ProductType.ACCOUNT) && 
     o.expiryDate
  );

  // GAMER LEVEL & RANK LOGIC
  const calculateLevel = (xp: number) => {
      return Math.floor(xp / 50) + 1;
  };

  const currentLevel = calculateLevel(totalSpent);
  const nextLevelXp = (currentLevel) * 50;
  const currentLevelXp = totalSpent - ((currentLevel - 1) * 50);
  const progressPercent = Math.min(100, (currentLevelXp / 50) * 100);

  const getRank = () => {
      if (currentLevel >= 20) return { name: 'ELITE', color: 'text-gaming-neon', bg: 'bg-gaming-neon/20', border: 'border-gaming-neon' };
      if (currentLevel >= 10) return { name: 'PRO', color: 'text-purple-400', bg: 'bg-purple-500/20', border: 'border-purple-500' };
      if (currentLevel >= 5) return { name: 'ADVANCED', color: 'text-yellow-400', bg: 'bg-yellow-500/20', border: 'border-yellow-500' };
      return { name: 'ROOKIE', color: 'text-gray-400', bg: 'bg-gray-700/50', border: 'border-gray-600' };
  };

  const rank = getRank();

  const handleLogout = () => {
    logout();
    navigate('/');
  };

  const copyToClipboard = (text: string) => {
    navigator.clipboard.writeText(text);
    alert("Kopyalandı!"); 
  };

  const handleAvatarUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
      const file = e.target.files?.[0];
      if (file) {
          const imageUrl = URL.createObjectURL(file);
          updateUserProfile({ avatar: imageUrl });
      }
  };

  const handleSaveProfile = () => {
      updateUserProfile({ name: editName, email: editEmail });
      setIsEditing(false);
  };

  const handleChangePassword = (e: React.FormEvent) => {
      e.preventDefault();
      if (changePassword(currentPass, newPass)) {
          setPassMsg("Şifrə uğurla dəyişdirildi!");
          setCurrentPass('');
          setNewPass('');
      } else {
          setPassMsg("Cari şifrə yanlışdır.");
      }
  };

  const getDaysRemaining = (expiryStr?: string) => {
     if(!expiryStr) return 0;
     const expiry = new Date(expiryStr);
     const now = new Date();
     const diffTime = expiry.getTime() - now.getTime();
     const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));
     return diffDays > 0 ? diffDays : 0;
  };

  if(!user) return null;

  return (
    <div className="min-h-screen bg-[#0b101b] bg-[url('https://transparenttextures.com/patterns/dark-matter.png')] py-10 px-4 font-gaming tracking-wide">
      <div className="max-w-7xl mx-auto">

        {/* CHARACTER HEADER */}
        <div className="bg-slate-900/80 backdrop-blur-xl border border-gray-700 rounded-3xl p-6 md:p-10 mb-8 relative overflow-hidden shadow-2xl">
            <div className="absolute top-0 right-0 w-96 h-96 bg-gaming-neon/10 rounded-full blur-[100px] pointer-events-none"></div>

            <div className="flex flex-col md:flex-row items-center gap-8 relative z-10">
                {/* Avatar Hexagon */}
                <div className="relative group">
                    <div className={`w-32 h-32 md:w-40 md:h-40 relative clip-hexagon ${rank.bg} p-1`}>
                         <div className="w-full h-full bg-slate-800 clip-hexagon overflow-hidden relative">
                             {user.avatar ? <img src={user.avatar} className="w-full h-full object-cover" /> : <div className="w-full h-full flex items-center justify-center text-4xl font-bold">{user.name.charAt(0)}</div>}
                         </div>
                    </div>
                    <button onClick={() => fileInputRef.current?.click()} className="absolute bottom-0 right-0 bg-white text-black p-2 rounded-full hover:scale-110 transition-transform shadow-lg z-20">
                        <Camera className="w-4 h-4" />
                    </button>
                    <input type="file" ref={fileInputRef} hidden accept="image/*" onChange={handleAvatarUpload} />

                    {/* Level Badge */}
                    <div className="absolute -top-2 -right-2 bg-gradient-to-r from-yellow-500 to-orange-500 w-10 h-10 rounded-lg rotate-45 flex items-center justify-center shadow-lg border-2 border-slate-900">
                         <span className="-rotate-45 font-black text-black text-lg">{currentLevel}</span>
                    </div>
                </div>

                {/* User Info & Stats */}
                <div className="flex-1 text-center md:text-left">
                    <div className="flex flex-col md:flex-row items-center gap-4 mb-2">
                         {isEditing ? (
                            <div className="flex gap-2">
                                <input className="bg-black/50 border border-gray-600 rounded px-2 py-1 text-white" value={editName} onChange={e => setEditName(e.target.value)} />
                                <button onClick={handleSaveProfile} className="text-green-500"><Save/></button>
                            </div>
                         ) : (
                            <h1 className="text-4xl md:text-5xl font-black text-white uppercase italic tracking-tighter flex items-center gap-2">
                                {user.name} 
                                <button onClick={() => setIsEditing(true)}><Edit className="w-5 h-5 text-gray-500 hover:text-white"/></button>
                            </h1>
                         )}
                         <span className={`px-3 py-1 rounded text-xs font-bold border ${rank.border} ${rank.color} bg-black/50`}>{rank.name}</span>
                    </div>
                    <p className="text-gray-400 font-mono mb-4">{user.email}</p>

                    {/* XP Bar */}
                    <div className="max-w-md">
                        <div className="flex justify-between text-xs font-bold text-gaming-neon mb-1 uppercase">
                            <span>Level {currentLevel}</span>
                            <span>{Math.floor(currentLevelXp)} / 50 XP</span>
                        </div>
                        <div className="h-4 bg-slate-800 rounded-full overflow-hidden border border-gray-700 relative">
                             <div className="absolute inset-0 bg-gaming-neon/20 animate-pulse"></div>
                             <div className="h-full bg-gradient-to-r from-gaming-neon to-purple-500 transition-all duration-1000" style={{width: `${progressPercent}%`}}></div>
                        </div>
                        <p className="text-[10px] text-gray-500 mt-1">Növbəti səviyyə üçün daha çox sifariş edin.</p>
                    </div>
                </div>

                {/* Balance & Actions */}
                <div className="bg-slate-950/50 p-6 rounded-2xl border border-gray-700 min-w-[250px]">
                    <p className="text-gray-400 text-xs font-bold uppercase tracking-widest mb-1">Cüzdan</p>
                    <div className="text-4xl font-mono font-bold text-white mb-4 flex items-center gap-2">
                        {user.balance.toFixed(2)} <span className="text-lg text-gaming-neon">₼</span>
                    </div>
                    <div className="grid grid-cols-2 gap-2">
                        <button onClick={() => navigate('/balance')} className="bg-gaming-neon hover:bg-cyan-400 text-black font-bold py-2 rounded flex items-center justify-center gap-1 transition-colors">
                            <Plus className="w-4 h-4"/> Artır
                        </button>
                        <button onClick={handleLogout} className="bg-red-500/10 hover:bg-red-500 text-red-500 hover:text-white font-bold py-2 rounded flex items-center justify-center gap-1 border border-red-500/20 transition-colors">
                            <LogOut className="w-4 h-4"/> Çıxış
                        </button>
                    </div>
                </div>
            </div>
        </div>

        {/* CONTENT TABS */}
        <div className="grid grid-cols-1 lg:grid-cols-4 gap-8">
            <div className="lg:col-span-1 space-y-4">
                 {[
                    { id: 'inventory', label: 'İnventar', icon: Package },
                    { id: 'quests', label: 'Abunəliklər', icon: Zap },
                    { id: 'settings', label: 'Tənzimləmələr', icon: Settings },
                 ].map(tab => (
                     <button
                        key={tab.id}
                        onClick={() => setActiveTab(tab.id as any)}
                        className={`w-full p-4 rounded-xl flex items-center justify-between group transition-all border
                            ${activeTab === tab.id 
                                ? 'bg-gradient-to-r from-gaming-neon/20 to-transparent border-gaming-neon text-white' 
                                : 'bg-slate-800 border-gray-700 text-gray-400 hover:bg-slate-700 hover:text-white'}`}
                     >
                         <div className="flex items-center gap-3">
                             <div className={`p-2 rounded-lg ${activeTab === tab.id ? 'bg-gaming-neon text-black' : 'bg-black text-gray-500 group-hover:text-white'}`}>
                                 <tab.icon className="w-5 h-5" />
                             </div>
                             <span className="font-bold uppercase tracking-wider">{tab.label}</span>
                         </div>
                         {activeTab === tab.id && <div className="w-2 h-2 rounded-full bg-gaming-neon shadow-[0_0_10px_#06b6d4]"></div>}
                     </button>
                 ))}
            </div>

            <div className="lg:col-span-3">
                 <div className="bg-slate-900/50 border border-gray-800 rounded-3xl p-6 min-h-[600px] relative">
                     {activeTab === 'inventory' && (
                         <div className="animate-fade-in">
                             <div className="flex justify-between items-center mb-6">
                                 <h2 className="text-2xl font-bold text-white flex items-center gap-2"><Swords className="text-gaming-neon"/> Sifariş İnventarı</h2>
                                 <div className="flex bg-slate-800 rounded p-1">
                                     {['ALL', 'PENDING', 'COMPLETED'].map(status => (
                                         <button 
                                            key={status} 
                                            onClick={() => setOrderFilter(status as any)}
                                            className={`px-3 py-1 rounded text-xs font-bold uppercase transition-colors ${orderFilter === status ? 'bg-gaming-neon text-black' : 'text-gray-400 hover:text-white'}`}
                                         >
                                             {status === 'ALL' ? 'Hamısı' : status}
                                         </button>
                                     ))}
                                 </div>
                             </div>

                             <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                                 {filteredOrders.length === 0 ? (
                                     <div className="col-span-full text-center py-20 opacity-50">
                                         <Skull className="w-16 h-16 mx-auto mb-2"/>
                                         <p>İnventar boşdur.</p>
