                                 ) : (
                                     filteredOrders.map(order => (
                                         <div key={order.id} className="bg-slate-800 p-4 rounded-xl border border-gray-700 hover:border-gaming-neon/50 transition-all group relative overflow-hidden">
                                             <div className="absolute top-0 right-0 p-2 opacity-50">
