                             <div className={`p-2 rounded-lg ${activeTab === tab.id ? 'bg-gaming-neon text-black' : 'bg-black text-gray-500 group-hover:text-white'}`}>
                                 <tab.icon className="w-5 h-5" />
                             </div>
                             <span className="font-bold uppercase tracking-wider">{tab.label}</span>
                         </div>
                         {activeTab === tab.id && <div className="w-2 h-2 rounded-full bg-gaming-neon shadow-[0_0_10px_#06b6d4]"></div>}
                     </button>
                 ))}
            </div>

            <div className="lg:col-span-3">
                 <div className="bg-slate-900/50 border border-gray-800 rounded-3xl p-6 min-h-[600px] relative">
                     {activeTab === 'inventory' && (
