export default Admin;

export enum ProductType {
  ID_LOAD = 'ID_LOAD',       
  LICENSE_KEY = 'LICENSE_KEY', 
  ACCOUNT = 'ACCOUNT',
  BALANCE = 'BALANCE'
}

export enum OrderStatus {
  PENDING = 'PENDING',
  PROCESSING = 'PROCESSING',
  COMPLETED = 'COMPLETED',
  CANCELLED = 'CANCELLED',
  FAILED = 'FAILED' // Added FAILED status
}

export interface StockCode {
  id: string;
