                                                 </div>
                                                 <div className="flex-1 overflow-hidden">
                                                     <h4 className="font-bold text-white truncate">{order.items.length > 1 ? `${order.items.length}x Items` : order.items[0]?.title}</h4>
                                                     <p className="text-xs text-gaming-neon font-mono mb-2">{order.totalPrice.toFixed(2)} ₼</p>
                                                     <p className="text-[10px] text-gray-500">Ordered: {new Date(order.date).toLocaleDateString()}</p>
                                                 </div>
                                             </div>

                                             {order.deliveredContent && (
                                                 <div className="mt-3 bg-black/40 p-3 rounded-lg border border-gray-700 flex flex-col gap-2">
                                                     <div className="flex justify-between items-center">
                                                         <span className="text-[10px] text-gray-500 uppercase font-bold">Aktivasiya Kodu / Məlumat</span>
                                                         <button onClick={() => toggleReveal(order.id)} className="text-gray-400 hover:text-white">
                                                             {revealedOrders[order.id] ? <EyeOff className="w-4 h-4" /> : <Eye className="w-4 h-4" />}
                                                         </button>
                                                     </div>
                                                     <div className="flex items-center justify-between bg-slate-900 p-2 rounded">
                                                         <code className="text-xs text-green-400 font-mono flex-1 mr-2 break-all">
                                                             {revealedOrders[order.id] ? order.deliveredContent : maskCode(order.deliveredContent)}
                                                         </code>
                                                         <button onClick={() => copyToClipboard(order.deliveredContent!)} className="text-gray-400 hover:text-white"><Copy className="w-4 h-4"/></button>
                                                     </div>
                                                 </div>
                                             )}
                                         </div>
                                     ))
                                 )}
                             </div>
                         </div>
                     )}

                     {activeTab === 'quests' && (
                         <div className="animate-fade-in">
