                                     <div className="text-center py-20 opacity-50">
                                         <Gamepad2 className="w-16 h-16 mx-auto mb-2"/>
                                         <p>Aktiv abunəlik (Account) yoxdur.</p>
                                     </div>
                                 ) : (
                                     mySubscriptions.map(sub => {
                                         const daysLeft = getDaysRemaining(sub.expiryDate);
                                         const totalDuration = sub.items[0]?.durationDays || 30;
                                         const progress = (daysLeft / totalDuration) * 100;

                                         return (
                                             <div key={sub.id} className="bg-gradient-to-r from-slate-800 to-slate-900 border border-gray-700 p-5 rounded-2xl relative overflow-hidden">
                                                 <div className="absolute left-0 top-0 bottom-0 w-1 bg-gaming-neon"></div>
                                                 <div className="flex justify-between items-center mb-2 relative z-10">
                                                     <h3 className="font-bold text-xl text-white">{sub.items[0].title}</h3>
                                                     <span className={`px-2 py-1 rounded text-xs font-bold ${daysLeft < 5 ? 'bg-red-500 text-white' : 'bg-green-500/20 text-green-400'}`}>
                                                         {daysLeft} GÜN QALIB
                                                     </span>
                                                 </div>

                                                 <div className="w-full bg-slate-700 h-3 rounded-full overflow-hidden mb-4 border border-slate-600">
                                                     <div className={`h-full ${daysLeft < 5 ? 'bg-red-500' : 'bg-gaming-neon'} shadow-[0_0_10px_currentColor]`} style={{width: `${progress}%`}}></div>
                                                 </div>

                                                 <div className="bg-black/50 p-3 rounded flex justify-between items-center border border-gray-700">
                                                     <div>
                                                         <p className="text-[10px] text-gray-500 uppercase">Login Data</p>
                                                         <code className="text-sm text-white">
                                                            {revealedOrders[sub.id] ? sub.deliveredContent : maskCode(sub.deliveredContent || "HIDDEN")}
                                                         </code>
                                                     </div>
                                                     <div className="flex gap-2">
                                                         <button onClick={() => toggleReveal(sub.id)} className="text-gray-400 hover:text-white">
                                                             {revealedOrders[sub.id] ? <EyeOff className="w-4 h-4" /> : <Eye className="w-4 h-4" />}
                                                         </button>
                                                         <button onClick={() => copyToClipboard(sub.deliveredContent!)}><Copy className="w-4 h-4 text-gray-400 hover:text-white"/></button>
                                                     </div>
                                                 </div>
                                             </div>
                                         )
                                     })
                                 )}
                             </div>
                         </div>
                     )}

                     {activeTab === 'settings' && (
                         <div className="animate-fade-in max-w-md mx-auto">
                             <h2 className="text-2xl font-bold text-white mb-6 text-center">Təhlükəsizlik</h2>
                             <div className="bg-slate-800 p-6 rounded-2xl border border-gray-700 shadow-xl">
                                 <form onSubmit={handleChangePassword} className="space-y-4">
                                    <div>
                                        <label className="text-xs text-gray-400 block mb-1 uppercase font-bold">Cari Şifrə</label>
                                        <input type="password" required className="w-full bg-slate-900 border border-gray-600 rounded-lg p-3 text-white focus:border-gaming-neon outline-none" value={currentPass} onChange={e => setCurrentPass(e.target.value)} />
                                    </div>
                                    <div>
                                        <label className="text-xs text-gray-400 block mb-1 uppercase font-bold">Yeni Şifrə</label>
                                        <input type="password" required className="w-full bg-slate-900 border border-gray-600 rounded-lg p-3 text-white focus:border-gaming-neon outline-none" value={newPass} onChange={e => setNewPass(e.target.value)} />
                                    </div>
                                    {passMsg && <p className={`text-sm ${passMsg.includes('uğurla') ? 'text-green-500' : 'text-red-500'}`}>{passMsg}</p>}
                                    <button type="submit" className="w-full bg-gaming-neon hover:bg-cyan-400 text-black font-bold py-3 rounded-lg transition-colors shadow-lg shadow-cyan-500/20">YENİLƏ</button>
                                </form>
                             </div>
                         </div>
                     )}
                 </div>
            </div>
        </div>
      </div>
    </div>
  );
};

