            completeOrder(order.id, "Balans Artırıldı");
        }
    } else {
        // Create a nice summary for the modal title
        const summary = order.items.map(i => `${i.quantity}x ${i.title}`).join(', ');

        // Auto-check for stock
        let autoContent = "";
        let hasStock = false;
        // Logic to check if we can auto-fill content from stock without assigning yet
