                  <div className="flex justify-between items-center mb-6 border-b border-gray-800 pb-4">
                      <h3 className="text-xl font-bold">Sifariş Detalları #{orderDetailsModal.id.slice(-6)}</h3>
                      <button onClick={() => setOrderDetailsModal(null)}><X className="text-gray-400 hover:text-white"/></button>
                  </div>

                  <div className="space-y-4 mb-6">
                      {orderDetailsModal.items.map((item, idx) => (
                          <div key={idx} className="flex gap-4 bg-slate-900 p-3 rounded-lg border border-gray-800 items-center">
                              <img src={item.image} className="w-12 h-12 rounded object-cover" alt="" />
                              <div className="flex-1">
                                  <p className="font-bold text-white">{item.title}</p>
                                  <p className="text-xs text-gray-400">{item.type}</p>
                                  {item.userInput && <p className="text-xs bg-black/40 px-2 py-1 rounded inline-block mt-1 text-gaming-neon">Input: {item.userInput}</p>}
                              </div>
                              <div className="text-right">
                                  <p className="text-sm text-gray-400">{item.quantity} x {item.price} ₼</p>
                                  <p className="font-bold text-white">{(item.quantity * item.price).toFixed(2)} ₼</p>
                              </div>
                          </div>
                      ))}
                  </div>

                  <div className="bg-slate-900 p-4 rounded-lg text-sm space-y-2">
                      <div className="flex justify-between">
                          <span className="text-gray-400">Ümumi Məbləğ:</span>
                          <span className="font-bold text-gaming-neon text-lg">{orderDetailsModal.totalPrice.toFixed(2)} ₼</span>
                      </div>
                      <div className="flex justify-between">
                          <span className="text-gray-400">İstifadəçi:</span>
                          <span className="text-white">{orderDetailsModal.userId}</span>
                      </div>
                      {orderDetailsModal.deliveredContent && (
                          <div className="pt-2 border-t border-gray-800 mt-2">
                              <span className="text-gray-400 block mb-1">Təslimat Məlumatı:</span>
                              <code className="block bg-black p-2 rounded text-green-400 whitespace-pre-wrap">{orderDetailsModal.deliveredContent}</code>
                          </div>
                      )}
                      {orderDetailsModal.receiptImage && (
                          <div className="pt-2">
                               <span className="text-gray-400 block mb-1">Qəbz:</span>
                               <img src={orderDetailsModal.receiptImage} className="max-h-40 rounded border border-gray-700" alt="Receipt" />
                          </div>
                      )}
                  </div>

                  <div className="mt-6 flex justify-end">
                      <button onClick={() => setOrderDetailsModal(null)} className="px-6 py-2 bg-slate-800 hover:bg-slate-700 text-white rounded-lg">Bağla</button>
                  </div>
              </div>
          </div>
      )}
    </div>
  );
};

export default Admin;

export enum ProductType {
  ID_LOAD = 'ID_LOAD',       
  LICENSE_KEY = 'LICENSE_KEY', 
  ACCOUNT = 'ACCOUNT',
  BALANCE = 'BALANCE'
}

