  const [isOpen, setIsOpen] = useState(false);
  const [notifOpen, setNotifOpen] = useState(false);
  const location = useLocation();
  const navigate = useNavigate();
  const notifRef = useRef<HTMLDivElement>(null);

  const isActive = (path: string) => location.pathname === path ? 'text-gaming-neon' : 'text-gray-300 hover:text-white';

  const navLinks = [
      { name: 'Ana səhifə', path: '/' },
      { name: 'Kateqoriyalar', path: '/' }, 
      { name: 'Xəbərlər', path: '/news' }, 
      { name: 'Qaydalar', path: '/rules' }, 
      { name: 'Balans artırma', path: isAuthenticated ? '/profile' : '/auth' },
      { name: 'Əlaqə', path: '/contact' }, 
