            </div>
          </div>

          {/* Right Section (Desktop) */}
          <div className="hidden lg:block">
            <div className="ml-4 flex items-center md:ml-6 space-x-4">
               {isAuthenticated ? (
                 <>
                  {/* Wishlist Icon */}
                  <Link to="/profile" className="p-2 rounded-full text-gray-400 hover:text-white hover:bg-slate-800 transition-colors relative">
                      <Heart className="w-5 h-5" />
                      {wishlistCount > 0 && (
                          <span className="absolute top-1 right-1 w-2.5 h-2.5 bg-red-500 rounded-full border border-slate-900 flex items-center justify-center text-[8px] font-bold text-white"></span>
