import React, { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { useApp } from '../store';
import { Product } from '../types';
import { ArrowLeft, CheckCircle, ShieldCheck, ShoppingCart, Heart } from 'lucide-react';

const ProductView = () => {
  const { id } = useParams<{ id: string }>();
  const navigate = useNavigate();
  const { products, addToCart, user, toggleWishlist, isAuthenticated } = useApp();

  const [product, setProduct] = useState<Product | undefined>(undefined);
  const [userInput, setUserInput] = useState('');
  const [added, setAdded] = useState(false);

  useEffect(() => {
    const found = products.find(p => p.id === id);
    if (found) setProduct(found);
    else navigate('/');
  }, [id, products, navigate]);

  if (!product) return null;

  const isLiked = user?.wishlist?.includes(product.id);

  const handleAddToCart = () => {
    if (product.requiresInput && !userInput) {
      alert("Zəhmət olmasa tələb olunan məlumatı daxil edin.");
      return;
    }
    addToCart(product, userInput);

    // Show feedback instead of redirecting
    setAdded(true);
    setTimeout(() => setAdded(false), 2000);
  };

  const handleWishlist = () => {
      if(!isAuthenticated) {
          navigate('/auth');
          return;
      }
      toggleWishlist(product.id);
  };

  const finalPrice = product.price - (product.price * (product.discountPercent / 100));

  return (
    <div className="min-h-screen bg-gaming-dark py-10 px-4">
      <div className="max-w-3xl mx-auto">
        <button onClick={() => navigate('/')} className="flex items-center text-gray-400 hover:text-white mb-6">
          <ArrowLeft className="w-4 h-4 mr-2" /> Mağazaya Qayıt
        </button>

        <div className="bg-gaming-card rounded-2xl border border-gray-800 overflow-hidden shadow-2xl animate-fade-in">
          <div className="p-6 md:p-8">
            <div className="flex flex-col md:flex-row gap-6 mb-8">
              <img src={product.image} alt={product.title} className="w-full md:w-1/3 rounded-lg object-cover aspect-video shadow-lg" />
              <div className="flex-1">
                <div className="flex justify-between items-start mb-2">
                    <h1 className="text-2xl font-bold text-white">{product.title}</h1>
                    <button 
                        onClick={handleWishlist}
                        className={`p-2 rounded-full border transition-all ${isLiked ? 'bg-red-500/10 border-red-500 text-red-500' : 'bg-slate-800 border-gray-700 text-gray-400 hover:text-white'}`}
                    >
                        <Heart className={`w-5 h-5 ${isLiked ? 'fill-current' : ''}`} />
                    </button>
                </div>

                <div className="flex items-center gap-2 mb-4">
                    <div className="text-gaming-accent font-bold text-2xl">{finalPrice.toFixed(2)} ₼</div>
                    {product.discountPercent > 0 && (
                        <span className="text-gray-500 line-through text-sm">{product.price.toFixed(2)} ₼</span>
                    )}
                </div>
                <p className="text-gray-400 text-sm leading-relaxed">{product.description}</p>
                <div className="mt-4 flex items-center gap-2 text-xs text-gray-500 bg-slate-900/50 p-2 rounded w-fit border border-gray-700">
                  <ShieldCheck className="w-4 h-4 text-green-500" />
                  <span>Manual Təsdiqləmə • Ani Təslimat</span>
                </div>
              </div>
            </div>

            {product.requiresInput && (
              <div className="mb-8 p-4 bg-slate-900/50 rounded-lg border border-gray-700">
                <label className="block text-sm font-medium text-gaming-neon mb-2">
                  {product.inputLabel || "Account ID / Link"} <span className="text-red-500">*</span>
                </label>
                <input
                  type="text"
                  value={userInput}
                  onChange={(e) => setUserInput(e.target.value)}
                  className="w-full bg-black border border-gray-600 rounded-lg p-3 text-white focus:ring-2 focus:ring-gaming-neon outline-none transition-all"
                  placeholder="Məlumatı bura daxil edin..."
                />
                <p className="text-xs text-gray-500 mt-2">Bu məlumat sifarişin yerinə yetirilməsi üçün vacibdir.</p>
              </div>
            )}

            <button
              onClick={handleAddToCart}
              className={`w-full font-bold py-4 rounded-lg transition-all flex items-center justify-center gap-2 shadow-lg transform hover:-translate-y-0.5
                  ${added ? 'bg-green-600 text-white' : 'bg-gaming-neon hover:bg-cyan-400 text-black'}`}
            >
              {added ? (
                  <>
                     <CheckCircle className="w-5 h-5" /> Səbətə Əlavə Edildi
                  </>
              ) : (
                  <>
                     <ShoppingCart className="w-5 h-5" /> Səbətə At
                  </>
              )}
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

export default ProductView;

import React, { useState, useRef } from 'react';
import { useApp } from '../store';
import { OrderStatus, ProductType } from '../types';
import { Clock, CheckCircle, XCircle, Copy, Plus, CreditCard, Upload, Send, Loader2, Edit, Camera, Save, Lock, User as UserIcon, LogOut, Calendar, Package, TrendingUp, Shield, Trophy, Star, Crown, Zap, Gift, Swords, Gamepad2, Skull, Settings, Eye, EyeOff, Heart } from 'lucide-react';
import { useNavigate } from 'react-router-dom';
import ProductCard from '../components/ProductCard';

const Profile = () => {
  const { user, orders, updateUserProfile, changePassword, logout, products } = useApp();
  const navigate = useNavigate();
  const [activeTab, setActiveTab] = useState<'inventory' | 'quests' | 'settings' | 'wishlist'>('inventory');

  // Logical Addition: Order Filter State
  const [orderFilter, setOrderFilter] = useState<'ALL' | OrderStatus>('ALL');

  // Security: Reveal Code State
  const [revealedOrders, setRevealedOrders] = useState<{[key: string]: boolean}>({});

  // Edit Profile State
  const [isEditing, setIsEditing] = useState(false);
  const [editName, setEditName] = useState(user?.name || '');
  const [editEmail, setEditEmail] = useState(user?.email || '');
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Change Password State
  const [currentPass, setCurrentPass] = useState('');
  const [newPass, setNewPass] = useState('');
  const [passMsg, setPassMsg] = useState('');

  const myOrders = orders.filter(o => o.userId === user?.id).sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());

  // Filtered orders logic
  const filteredOrders = myOrders.filter(o => orderFilter === 'ALL' || o.status === orderFilter);

  // Wishlist Products
  const wishlistProducts = products.filter(p => user?.wishlist?.includes(p.id));

  // Stats
  const totalSpent = myOrders.filter(o => o.status === OrderStatus.COMPLETED).reduce((acc, curr) => acc + (curr.totalPrice || 0), 0);

  // Filter subscriptions - STRICTLY ACCOUNT TYPE
  const mySubscriptions = myOrders.filter(o => 
     o.status === OrderStatus.COMPLETED && 
     o.items.some(i => i.type === ProductType.ACCOUNT) && 
     o.expiryDate
  );

  // GAMER LEVEL & RANK LOGIC
  const calculateLevel = (xp: number) => {
      return Math.floor(xp / 50) + 1;
  };

  const currentLevel = calculateLevel(totalSpent);
  const nextLevelXp = (currentLevel) * 50;
  const currentLevelXp = totalSpent - ((currentLevel - 1) * 50);
  const progressPercent = Math.min(100, (currentLevelXp / 50) * 100);

  const getRank = () => {
      if (currentLevel >= 20) return { name: 'ELITE', color: 'text-gaming-neon', bg: 'bg-gaming-neon/20', border: 'border-gaming-neon' };
      if (currentLevel >= 10) return { name: 'PRO', color: 'text-purple-400', bg: 'bg-purple-500/20', border: 'border-purple-500' };
      if (currentLevel >= 5) return { name: 'ADVANCED', color: 'text-yellow-400', bg: 'bg-yellow-500/20', border: 'border-yellow-500' };
      return { name: 'ROOKIE', color: 'text-gray-400', bg: 'bg-gray-700/50', border: 'border-gray-600' };
  };

  const rank = getRank();

  const handleLogout = () => {
    logout();
    navigate('/');
  };

  const copyToClipboard = (text: string) => {
    navigator.clipboard.writeText(text);
    alert("Kopyalandı!"); 
  };

  const toggleReveal = (orderId: string) => {
      setRevealedOrders(prev => ({
          ...prev,
          [orderId]: !prev[orderId]
      }));
  };

  const maskCode = (code: string) => {
      return "••••-••••-••••-" + code.slice(-4);
  };

  const handleAvatarUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
      const file = e.target.files?.[0];
      if (file) {
          const imageUrl = URL.createObjectURL(file);
          updateUserProfile({ avatar: imageUrl });
      }
  };

  const handleSaveProfile = () => {
      updateUserProfile({ name: editName, email: editEmail });
      setIsEditing(false);
  };

  const handleChangePassword = (e: React.FormEvent) => {
      e.preventDefault();
      if (changePassword(currentPass, newPass)) {
          setPassMsg("Şifrə uğurla dəyişdirildi!");
          setCurrentPass('');
          setNewPass('');
      } else {
          setPassMsg("Cari şifrə yanlışdır.");
      }
  };

  const getDaysRemaining = (expiryStr?: string) => {
     if(!expiryStr) return 0;
     const expiry = new Date(expiryStr);
     const now = new Date();
     const diffTime = expiry.getTime() - now.getTime();
     const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));
     return diffDays > 0 ? diffDays : 0;
  };

  if(!user) return null;

  return (
    <div className="min-h-screen bg-[#0b101b] bg-[url('https://transparenttextures.com/patterns/dark-matter.png')] py-10 px-4 font-gaming tracking-wide">
      <div className="max-w-7xl mx-auto">

        {/* CHARACTER HEADER */}
        <div className="bg-slate-900/80 backdrop-blur-xl border border-gray-700 rounded-3xl p-6 md:p-10 mb-8 relative overflow-hidden shadow-2xl">
            <div className="absolute top-0 right-0 w-96 h-96 bg-gaming-neon/10 rounded-full blur-[100px] pointer-events-none"></div>

            <div className="flex flex-col md:flex-row items-center gap-8 relative z-10">
                {/* Avatar Hexagon */}
                <div className="relative group">
                    <div className={`w-32 h-32 md:w-40 md:h-40 relative clip-hexagon ${rank.bg} p-1`}>
                         <div className="w-full h-full bg-slate-800 clip-hexagon overflow-hidden relative">
                             {user.avatar ? <img src={user.avatar} className="w-full h-full object-cover" /> : <div className="w-full h-full flex items-center justify-center text-4xl font-bold">{user.name.charAt(0)}</div>}
                         </div>
                    </div>
                    <button onClick={() => fileInputRef.current?.click()} className="absolute bottom-0 right-0 bg-white text-black p-2 rounded-full hover:scale-110 transition-transform shadow-lg z-20">
                        <Camera className="w-4 h-4" />
                    </button>
                    <input type="file" ref={fileInputRef} hidden accept="image/*" onChange={handleAvatarUpload} />

                    {/* Level Badge */}
                    <div className="absolute -top-2 -right-2 bg-gradient-to-r from-yellow-500 to-orange-500 w-10 h-10 rounded-lg rotate-45 flex items-center justify-center shadow-lg border-2 border-slate-900">
                         <span className="-rotate-45 font-black text-black text-lg">{currentLevel}</span>
                    </div>
                </div>

                {/* User Info & Stats */}
                <div className="flex-1 text-center md:text-left">
                    <div className="flex flex-col md:flex-row items-center gap-4 mb-2">
                         {isEditing ? (
                            <div className="flex gap-2">
                                <input className="bg-black/50 border border-gray-600 rounded px-2 py-1 text-white" value={editName} onChange={e => setEditName(e.target.value)} />
                                <button onClick={handleSaveProfile} className="text-green-500"><Save/></button>
                            </div>
                         ) : (
                            <h1 className="text-4xl md:text-5xl font-black text-white uppercase italic tracking-tighter flex items-center gap-2">
                                {user.name} 
                                <button onClick={() => setIsEditing(true)}><Edit className="w-5 h-5 text-gray-500 hover:text-white"/></button>
                            </h1>
                         )}
                         <span className={`px-3 py-1 rounded text-xs font-bold border ${rank.border} ${rank.color} bg-black/50`}>{rank.name}</span>
                    </div>
                    <p className="text-gray-400 font-mono mb-4">{user.email}</p>

                    {/* XP Bar */}
                    <div className="max-w-md">
                        <div className="flex justify-between text-xs font-bold text-gaming-neon mb-1 uppercase">
                            <span>Level {currentLevel}</span>
                            <span>{Math.floor(currentLevelXp)} / 50 XP</span>
                        </div>
                        <div className="h-4 bg-slate-800 rounded-full overflow-hidden border border-gray-700 relative">
                             <div className="absolute inset-0 bg-gaming-neon/20 animate-pulse"></div>
                             <div className="h-full bg-gradient-to-r from-gaming-neon to-purple-500 transition-all duration-1000" style={{width: `${progressPercent}%`}}></div>
                        </div>
                        <p className="text-[10px] text-gray-500 mt-1">Növbəti səviyyə üçün daha çox sifariş edin.</p>
                    </div>
                </div>

                {/* Balance & Actions */}
                <div className="bg-slate-950/50 p-6 rounded-2xl border border-gray-700 min-w-[250px]">
                    <p className="text-gray-400 text-xs font-bold uppercase tracking-widest mb-1">Cüzdan</p>
                    <div className="text-4xl font-mono font-bold text-white mb-4 flex items-center gap-2">
                        {user.balance.toFixed(2)} <span className="text-lg text-gaming-neon">₼</span>
                    </div>
                    <div className="grid grid-cols-2 gap-2">
                        <button onClick={() => navigate('/balance')} className="bg-gaming-neon hover:bg-cyan-400 text-black font-bold py-2 rounded flex items-center justify-center gap-1 transition-colors">
                            <Plus className="w-4 h-4"/> Artır
                        </button>
                        <button onClick={handleLogout} className="bg-red-500/10 hover:bg-red-500 text-red-500 hover:text-white font-bold py-2 rounded flex items-center justify-center gap-1 border border-red-500/20 transition-colors">
                            <LogOut className="w-4 h-4"/> Çıxış
                        </button>
                    </div>
                </div>
            </div>
        </div>

        {/* CONTENT TABS */}
        <div className="grid grid-cols-1 lg:grid-cols-4 gap-8">
            <div className="lg:col-span-1 space-y-4">
                 {[
                    { id: 'inventory', label: 'İnventar', icon: Package },
                    { id: 'quests', label: 'Abunəliklər', icon: Zap },
                    { id: 'wishlist', label: 'Sevimlilər', icon: Heart },
                    { id: 'settings', label: 'Tənzimləmələr', icon: Settings },
                 ].map(tab => (
                     <button
                        key={tab.id}
                        onClick={() => setActiveTab(tab.id as any)}
                        className={`w-full p-4 rounded-xl flex items-center justify-between group transition-all border
                            ${activeTab === tab.id 
                                ? 'bg-gradient-to-r from-gaming-neon/20 to-transparent border-gaming-neon text-white' 
                                : 'bg-slate-800 border-gray-700 text-gray-400 hover:bg-slate-700 hover:text-white'}`}
                     >
                         <div className="flex items-center gap-3">
                             <div className={`p-2 rounded-lg ${activeTab === tab.id ? 'bg-gaming-neon text-black' : 'bg-black text-gray-500 group-hover:text-white'}`}>
                                 <tab.icon className="w-5 h-5" />
                             </div>
                             <span className="font-bold uppercase tracking-wider">{tab.label}</span>
                         </div>
                         {activeTab === tab.id && <div className="w-2 h-2 rounded-full bg-gaming-neon shadow-[0_0_10px_#06b6d4]"></div>}
                     </button>
                 ))}
            </div>

            <div className="lg:col-span-3">
                 <div className="bg-slate-900/50 border border-gray-800 rounded-3xl p-6 min-h-[600px] relative">
                     {activeTab === 'inventory' && (
                         <div className="animate-fade-in">
                             <div className="flex justify-between items-center mb-6">
                                 <h2 className="text-2xl font-bold text-white flex items-center gap-2"><Swords className="text-gaming-neon"/> Sifariş İnventarı</h2>
                                 <div className="flex bg-slate-800 rounded p-1">
                                     {['ALL', 'PENDING', 'COMPLETED'].map(status => (
                                         <button 
                                            key={status} 
                                            onClick={() => setOrderFilter(status as any)}
                                            className={`px-3 py-1 rounded text-xs font-bold uppercase transition-colors ${orderFilter === status ? 'bg-gaming-neon text-black' : 'text-gray-400 hover:text-white'}`}
                                         >
                                             {status === 'ALL' ? 'Hamısı' : status}
                                         </button>
                                     ))}
                                 </div>
                             </div>

                             <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                                 {filteredOrders.length === 0 ? (
                                     <div className="col-span-full text-center py-20 opacity-50">
                                         <Skull className="w-16 h-16 mx-auto mb-2"/>
                                         <p>İnventar boşdur.</p>
                                     </div>
                                 ) : (
                                     filteredOrders.map(order => (
                                         <div key={order.id} className="bg-slate-800 p-4 rounded-xl border border-gray-700 hover:border-gaming-neon/50 transition-all group relative overflow-hidden">
                                             <div className="absolute top-0 right-0 p-2 opacity-50">
                                                 {order.status === 'COMPLETED' ? <CheckCircle className="text-green-500 w-5 h-5"/> : <Clock className="text-yellow-500 w-5 h-5"/>}
                                             </div>

                                             <div className="flex gap-4">
                                                 <div className="w-16 h-16 bg-black rounded border border-gray-600 flex items-center justify-center shrink-0">
                                                     {order.items[0]?.image ? <img src={order.items[0].image} className="w-full h-full object-cover rounded"/> : <Package className="text-gray-600"/>}
                                                 </div>
                                                 <div className="flex-1 overflow-hidden">
                                                     <h4 className="font-bold text-white truncate">{order.items.length > 1 ? `${order.items.length}x Items` : order.items[0]?.title}</h4>
                                                     <p className="text-xs text-gaming-neon font-mono mb-2">{order.totalPrice.toFixed(2)} ₼</p>
                                                     <p className="text-[10px] text-gray-500">Ordered: {new Date(order.date).toLocaleDateString()}</p>
                                                 </div>
                                             </div>

                                             {order.deliveredContent && (
                                                 <div className="mt-3 bg-black/40 p-3 rounded-lg border border-gray-700 flex flex-col gap-2">
                                                     <div className="flex justify-between items-center">
                                                         <span className="text-[10px] text-gray-500 uppercase font-bold">Aktivasiya Kodu / Məlumat</span>
                                                         <button onClick={() => toggleReveal(order.id)} className="text-gray-400 hover:text-white">
                                                             {revealedOrders[order.id] ? <EyeOff className="w-4 h-4" /> : <Eye className="w-4 h-4" />}
                                                         </button>
                                                     </div>
                                                     <div className="flex items-center justify-between bg-slate-900 p-2 rounded">
                                                         <code className="text-xs text-green-400 font-mono flex-1 mr-2 break-all">
                                                             {revealedOrders[order.id] ? order.deliveredContent : maskCode(order.deliveredContent)}
                                                         </code>
                                                         <button onClick={() => copyToClipboard(order.deliveredContent!)} className="text-gray-400 hover:text-white"><Copy className="w-4 h-4"/></button>
                                                     </div>
                                                 </div>
                                             )}
                                         </div>
                                     ))
                                 )}
                             </div>
                         </div>
                     )}

                     {activeTab === 'quests' && (
                         <div className="animate-fade-in">
                             <h2 className="text-2xl font-bold text-white mb-6 flex items-center gap-2"><Zap className="text-yellow-400"/> Aktiv Abunəliklər</h2>

                             <div className="space-y-4">
                                 {mySubscriptions.length === 0 ? (
                                     <div className="text-center py-20 opacity-50">
                                         <Gamepad2 className="w-16 h-16 mx-auto mb-2"/>
                                         <p>Aktiv abunəlik (Account) yoxdur.</p>
                                     </div>
                                 ) : (
                                     mySubscriptions.map(sub => {
                                         const daysLeft = getDaysRemaining(sub.expiryDate);
                                         const totalDuration = sub.items[0]?.durationDays || 30;
                                         const progress = (daysLeft / totalDuration) * 100;

                                         return (
                                             <div key={sub.id} className="bg-gradient-to-r from-slate-800 to-slate-900 border border-gray-700 p-5 rounded-2xl relative overflow-hidden">
                                                 <div className="absolute left-0 top-0 bottom-0 w-1 bg-gaming-neon"></div>
                                                 <div className="flex justify-between items-center mb-2 relative z-10">
                                                     <h3 className="font-bold text-xl text-white">{sub.items[0].title}</h3>
                                                     <span className={`px-2 py-1 rounded text-xs font-bold ${daysLeft < 5 ? 'bg-red-500 text-white' : 'bg-green-500/20 text-green-400'}`}>
                                                         {daysLeft} GÜN QALIB
                                                     </span>
                                                 </div>

                                                 <div className="w-full bg-slate-700 h-3 rounded-full overflow-hidden mb-4 border border-slate-600">
                                                     <div className={`h-full ${daysLeft < 5 ? 'bg-red-500' : 'bg-gaming-neon'} shadow-[0_0_10px_currentColor]`} style={{width: `${progress}%`}}></div>
                                                 </div>

                                                 <div className="bg-black/50 p-3 rounded flex justify-between items-center border border-gray-700">
                                                     <div>
                                                         <p className="text-[10px] text-gray-500 uppercase">Login Data</p>
                                                         <code className="text-sm text-white">
                                                            {revealedOrders[sub.id] ? sub.deliveredContent : maskCode(sub.deliveredContent || "HIDDEN")}
                                                         </code>
                                                     </div>
                                                     <div className="flex gap-2">
                                                         <button onClick={() => toggleReveal(sub.id)} className="text-gray-400 hover:text-white">
                                                             {revealedOrders[sub.id] ? <EyeOff className="w-4 h-4" /> : <Eye className="w-4 h-4" />}
                                                         </button>
                                                         <button onClick={() => copyToClipboard(sub.deliveredContent!)}><Copy className="w-4 h-4 text-gray-400 hover:text-white"/></button>
                                                     </div>
                                                 </div>
                                             </div>
                                         )
                                     })
                                 )}
                             </div>
                         </div>
                     )}

                     {activeTab === 'wishlist' && (
                         <div className="animate-fade-in">
                             <h2 className="text-2xl font-bold text-white mb-6 flex items-center gap-2"><Heart className="text-red-500 fill-current"/> Sevimlilər ({wishlistProducts.length})</h2>

                             {wishlistProducts.length === 0 ? (
                                 <div className="text-center py-20 opacity-50">
                                     <Heart className="w-16 h-16 mx-auto mb-2 text-gray-600"/>
                                     <p>Sevimlilər siyahısı boşdur.</p>
                                     <button onClick={() => navigate('/')} className="text-gaming-neon hover:underline mt-2">Mağazaya Keç</button>
                                 </div>
                             ) : (
                                 <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                                     {wishlistProducts.map(product => (
                                         <ProductCard key={product.id} product={product} />
                                     ))}
                                 </div>
                             )}
                         </div>
                     )}

                     {activeTab === 'settings' && (
                         <div className="animate-fade-in max-w-md mx-auto">
                             <h2 className="text-2xl font-bold text-white mb-6 text-center">Təhlükəsizlik</h2>
                             <div className="bg-slate-800 p-6 rounded-2xl border border-gray-700 shadow-xl">
                                 <form onSubmit={handleChangePassword} className="space-y-4">
                                    <div>
                                        <label className="text-xs text-gray-400 block mb-1 uppercase font-bold">Cari Şifrə</label>
                                        <input type="password" required className="w-full bg-slate-900 border border-gray-600 rounded-lg p-3 text-white focus:border-gaming-neon outline-none" value={currentPass} onChange={e => setCurrentPass(e.target.value)} />
                                    </div>
                                    <div>
                                        <label className="text-xs text-gray-400 block mb-1 uppercase font-bold">Yeni Şifrə</label>
                                        <input type="password" required className="w-full bg-slate-900 border border-gray-600 rounded-lg p-3 text-white focus:border-gaming-neon outline-none" value={newPass} onChange={e => setNewPass(e.target.value)} />
                                    </div>
                                    {passMsg && <p className={`text-sm ${passMsg.includes('uğurla') ? 'text-green-500' : 'text-red-500'}`}>{passMsg}</p>}
                                    <button type="submit" className="w-full bg-gaming-neon hover:bg-cyan-400 text-black font-bold py-3 rounded-lg transition-colors shadow-lg shadow-cyan-500/20">YENİLƏ</button>
                                </form>
                             </div>
                         </div>
                     )}
                 </div>
            </div>
        </div>
      </div>
    </div>
  );
};

export default Profile;

export enum ProductType {
  ID_LOAD = 'ID_LOAD',       
  LICENSE_KEY = 'LICENSE_KEY', 
  ACCOUNT = 'ACCOUNT',
  BALANCE = 'BALANCE'
}

export enum OrderStatus {
  PENDING = 'PENDING',
  PROCESSING = 'PROCESSING',
  COMPLETED = 'COMPLETED',
  CANCELLED = 'CANCELLED',
  FAILED = 'FAILED' // Added FAILED status
}

export interface StockCode {
  id: string;
  productId: string;
  code: string; // The actual key/account data
  isUsed: boolean;
  dateAdded: string;
}

export interface ActivityLog {
  id: string;
  adminName: string;
  action: string;
  details: string;
  date: string;
  type: 'info' | 'warning' | 'error' | 'success';
}

export interface Notification {
  id: string;
  userId: string;
  title: string;
  message: string;
  type: 'success' | 'info' | 'warning' | 'error';
  date: string;
  isRead: boolean;
}

export interface Category {
  id: string;
  name: string;
  image?: string;
  icon?: string;
  seoTitle?: string;
  seoKeywords?: string;
}

export interface Product {
  id: string;
  title: string;
  categoryId: string;
  type: ProductType;
  price: number;        
  costPrice: number;    
  discountPercent: number; 
  image: string;
  description: string;
  requiresInput?: boolean;
  inputLabel?: string;
  seoTitle?: string;
  seoKeywords?: string;
  durationDays?: number;
  stockCount?: number; // Calculated field
}

export interface CartItem {
  productId: string;
  title: string;
  price: number;
  image: string;
  type: ProductType;
  userInput?: string;
  quantity: number;
  durationDays?: number;
}

export interface Blog {
  id: string;
  title: string;
  content: string;
  date: string;
  image: string;
}

export interface Agreement {
  id: string;
  title: string; 
  content: string;
}

export interface Comment {
  id: string;
  author: string;
  content: string;
  type: 'product' | 'blog' | 'site';
  targetId?: string; 
  isApproved: boolean;
  date: string;
  rating?: number; // 1-5 Star Rating
}

export interface PaymentMethod {
  id: string;
  name: string;
  details: string; 
  instructions: string;
  isActive: boolean;
  icon: string;
}

export interface Order {
  id: string;
  userId: string;
  items: CartItem[];
  totalPrice: number;
  discountApplied?: number;
  status: OrderStatus;
  date: string;
  paymentMethodName: string;
  receiptImage?: string; 
  deliveredContent?: string; // Shows code/account info
  expiryDate?: string;

  // Legacy support
  productTitle?: string;
  productType?: ProductType;
  userInput?: string; 
  productId?: string;
  price?: number;
}

export interface User {
  id: string;
  name: string;
  email: string;
  phone: string;
  role: 'admin' | 'user';
  balance: number;
  password?: string;
  avatar?: string;
  resetRequested?: boolean;
  isBanned?: boolean;
  resetToken?: string;
  wishlist?: string[]; // New: List of product IDs
}

export interface SocialLinks {
  instagram: string;
  telegram: string;
  tiktok: string;
  whatsapp: string;
}

export interface SiteSettings {
  siteName: string;
  logoUrl: string;
  heroBannerUrl: string;
  heroTitle: string;
  heroSubtitle: string;
  whatsappNumber: string;
  footerText: string;
  discordWebhook: string;
  seoTitle: string;
  seoDesc: string;
  contactEmail?: string;
  contactAddress?: string;
  socials: SocialLinks;
}

export interface PromoCode {
  id: string;
  code: string;
  discountPercent: number;
  isActive: boolean;
}

import React, { createContext, useContext, useState, ReactNode, useEffect } from 'react';
import { Product, Order, PaymentMethod, User, OrderStatus, ProductType, Category, SiteSettings, Blog, Agreement, Comment, CartItem, PromoCode, Notification, StockCode, ActivityLog } from './types';
import { INITIAL_PRODUCTS, INITIAL_PAYMENT_METHODS, MOCK_USERS, INITIAL_CATEGORIES, INITIAL_SETTINGS, MOCK_PROMO_CODES } from './constants';

interface AppContextType {
  user: User | null; 
  usersList: User[];
  isAuthenticated: boolean;
  products: Product[];
  categories: Category[];
  orders: Order[];
  paymentMethods: PaymentMethod[];
  promoCodes: PromoCode[];
  siteSettings: SiteSettings;
  blogs: Blog[];
  agreements: Agreement[];
  comments: Comment[];
  cart: CartItem[];
  notifications: Notification[];
  stocks: StockCode[]; 
  activityLogs: ActivityLog[]; 

  // Auth
  login: (email: string, pass: string) => boolean;
  register: (name: string, email: string, phone: string, pass: string) => void;
  logout: () => void;
  updateUserProfile: (data: Partial<User>) => void;
  changePassword: (currentPass: string, newPass: string) => boolean;
  requestPasswordReset: (phone: string) => boolean;
  adminUpdateUserPassword: (userId: string, newPass: string) => void;
  toggleUserBan: (userId: string) => void;
  generateResetLink: (userId: string) => string;
  confirmPasswordReset: (token: string, newPass: string) => boolean;
  toggleWishlist: (productId: string) => void; // New Wishlist Toggle

  // Cart
  addToCart: (product: Product, userInput?: string) => void;
  updateCartQuantity: (index: number, delta: number) => void;
  removeFromCart: (index: number) => void;
  clearCart: () => void;

  // Order Actions
  placeOrder: (paymentMethodId: string | 'BALANCE', receiptFile?: File, promoDiscount?: number) => Promise<boolean>;
  placeBalanceOrder: (amount: number, paymentMethodId: string, receiptFile: File) => Promise<boolean>;
  processOrder: (orderId: string) => void;
  completeOrder: (orderId: string, manualContent?: string) => void; 
  cancelOrder: (orderId: string) => void;

  // Notification Actions
  markNotificationRead: (id: string) => void;
  clearNotifications: () => void;

  // Admin CMS & Stock
  addProduct: (product: Product) => void;
  addProducts: (newProducts: Product[]) => void;
  deleteProduct: (productId: string) => void;
  addCategory: (category: Category) => void;
  deleteCategory: (categoryId: string) => void;
  updateSiteSettings: (settings: Partial<SiteSettings>) => void;
  updateUserBalance: (amount: number) => void;
  addPaymentMethod: (method: PaymentMethod) => void;
  updatePaymentMethod: (id: string, details: Partial<PaymentMethod>) => void;
  deletePaymentMethod: (id: string) => void;
  addPromoCode: (promo: PromoCode) => void;
  deletePromoCode: (id: string) => void;
  togglePromoCode: (id: string) => void;

  // Stock Logic
  addStock: (productId: string, codes: string[]) => void;
  deleteStock: (stockId: string) => void;

  // CMS
  addBlog: (blog: Blog) => void;
  deleteBlog: (id: string) => void;
  addAgreement: (agreement: Agreement) => void;
  deleteAgreement: (id: string) => void;
  addComment: (comment: Omit<Comment, 'id' | 'date' | 'isApproved'>) => void;
  toggleCommentApproval: (id: string) => void;
  deleteComment: (id: string) => void;
}

const AppContext = createContext<AppContextType | undefined>(undefined);

export const AppProvider = ({ children }: { children?: React.ReactNode }) => {
  const [user, setUser] = useState<User | null>(null);
  const [usersList, setUsersList] = useState<User[]>(MOCK_USERS);
  const [products, setProducts] = useState<Product[]>(INITIAL_PRODUCTS);
  const [categories, setCategories] = useState<Category[]>(INITIAL_CATEGORIES);
  const [orders, setOrders] = useState<Order[]>([]);
  const [paymentMethods, setPaymentMethods] = useState<PaymentMethod[]>(INITIAL_PAYMENT_METHODS);
  const [promoCodes, setPromoCodes] = useState<PromoCode[]>(MOCK_PROMO_CODES);
  const [siteSettings, setSiteSettings] = useState<SiteSettings>(INITIAL_SETTINGS);
  const [cart, setCart] = useState<CartItem[]>([]);
  const [notifications, setNotifications] = useState<Notification[]>([]);

  // New States
  const [stocks, setStocks] = useState<StockCode[]>([]);
  const [activityLogs, setActivityLogs] = useState<ActivityLog[]>([]);

  // CMS State
  const [blogs, setBlogs] = useState<Blog[]>([
    { id: 'b1', title: 'PUBG Yeni Sezon Başladı!', content: 'Yeni sezonun gəlişi ilə birlikdə...', date: new Date().toISOString(), image: 'https://images.unsplash.com/photo-1542751371-adc38448a05e' }
  ]);
  const [agreements, setAgreements] = useState<Agreement[]>([
    { id: 'a1', title: 'İstifadəçi Razılaşması', content: 'Saytımızdan istifadə edərkən...' },
    { id: 'a2', title: 'Məxfilik Siyasəti', content: 'Məlumatlarınız qorunur...' }
  ]);
  const [comments, setComments] = useState<Comment[]>([
    { id: 'c1', author: 'Elvin M.', content: 'Çox sürətli gəldi, təşəkkürlər!', type: 'product', targetId: 'p1', isApproved: true, date: new Date().toISOString(), rating: 5 },
    { id: 'c2', author: 'Anonim', content: 'Gözləyirəm hələ...', type: 'site', isApproved: false, date: new Date().toISOString(), rating: 3 }
  ]);

  // Recalculate Product Stock Counts whenever 'stocks' changes
  useEffect(() => {
    setProducts(prev => prev.map(p => ({
        ...p,
        stockCount: stocks.filter(s => s.productId === p.id && !s.isUsed).length
    })));
  }, [stocks]);

  // --- Helper: Logger ---
  const logActivity = (action: string, details: string, type: ActivityLog['type'] = 'info') => {
      const newLog: ActivityLog = {
          id: `log-${Date.now()}`,
          adminName: user?.name || 'System',
          action,
          details,
          date: new Date().toISOString(),
          type
      };
      setActivityLogs(prev => [newLog, ...prev]);
  };

  // --- Notification Helper ---
  const sendNotification = (userId: string, title: string, message: string, type: 'success' | 'info' | 'warning' | 'error') => {
      const newNotif: Notification = {
          id: `notif-${Date.now()}-${Math.random()}`,
          userId,
          title,
          message,
          type,
          date: new Date().toISOString(),
          isRead: false
      };
      setNotifications(prev => [newNotif, ...prev]);
  };

  const markNotificationRead = (id: string) => {
      setNotifications(prev => prev.map(n => n.id === id ? { ...n, isRead: true } : n));
  };

  const clearNotifications = () => {
      if(user) {
          setNotifications(prev => prev.filter(n => n.userId !== user.id));
      }
  };

  const login = (email: string, pass: string) => {
    const foundUser = usersList.find(u => u.email === email && u.password === pass);
    if (foundUser) {
      if (foundUser.isBanned) {
        alert("Hesabınız bloklanıb. Zəhmət olmasa dəstək xidməti ilə əlaqə saxlayın.");
        return false;
      }
      setUser(foundUser);
      logActivity('User Login', `${foundUser.email} daxil oldu.`);
      return true;
    }
    return false;
  };

  const register = (name: string, email: string, phone: string, pass: string) => {
    const newUser: User = {
      id: `u-${Date.now()}`,
      name,
      email,
      phone,
      role: 'user',
      balance: 0,
      password: pass,
      isBanned: false,
      wishlist: []
    };
    setUsersList(prev => [...prev, newUser]);
    setUser(newUser);
    sendNotification(newUser.id, 'Xoş Gəldiniz!', 'GamePay ailəsinə xoş gəldiniz. Uğurlu alış-verişlər!', 'success');
    logActivity('New Register', `${email} qeydiyyatdan keçdi.`, 'success');
  };

  const updateUserProfile = (data: Partial<User>) => {
    if (!user) return;
    const updatedUser = { ...user, ...data };
    setUser(updatedUser);
    setUsersList(prev => prev.map(u => u.id === user.id ? updatedUser : u));
    logActivity('Profile Update', `${user.email} profilini yenilədi.`);
  };

  const changePassword = (currentPass: string, newPass: string) => {
      if(!user) return false;
      if(user.password !== currentPass) return false;

      const updatedUser = { ...user, password: newPass };
      setUser(updatedUser);
      setUsersList(prev => prev.map(u => u.id === user.id ? updatedUser : u));
      logActivity('Password Change', `${user.email} şifrəsini dəyişdi.`);
      return true;
  };

  const requestPasswordReset = (phone: string) => {
    const exists = usersList.find(u => u.phone === phone);
    if (exists) {
      setUsersList(prev => prev.map(u => u.phone === phone ? { ...u, resetRequested: true } : u));
      return true; 
    }
    return false;
  };

  const generateResetLink = (userId: string) => {
      const token = Math.random().toString(36).substring(2, 15) + Math.random().toString(36).substring(2, 15);
      setUsersList(prev => prev.map(u => u.id === userId ? { ...u, resetToken: token } : u));
      return `${window.location.origin}/#/auth?token=${token}`;
  };

  const confirmPasswordReset = (token: string, newPass: string) => {
      const userWithToken = usersList.find(u => u.resetToken === token);
      if(!userWithToken) return false;

      setUsersList(prev => prev.map(u => u.id === userWithToken.id ? { 
          ...u, 
          password: newPass, 
          resetToken: undefined, // Clear token
          resetRequested: false // Clear flag
      } : u));
      logActivity('Password Reset', `${userWithToken.email} şifrəsini token ilə yenilədi.`, 'warning');
      return true;
  };

  const adminUpdateUserPassword = (userId: string, newPass: string) => {
    const targetUser = usersList.find(u => u.id === userId);
    setUsersList(prev => prev.map(u => u.id === userId ? { ...u, password: newPass, resetRequested: false } : u));
    logActivity('Admin Password Change', `Admin ${targetUser?.email} istifadəçisinin şifrəsini dəyişdi.`, 'warning');
  };

  const toggleUserBan = (userId: string) => {
    const targetUser = usersList.find(u => u.id === userId);
    setUsersList(prev => prev.map(u => u.id === userId ? { ...u, isBanned: !u.isBanned } : u));
    logActivity('User Ban/Unban', `Admin ${targetUser?.email} statusunu dəyişdi.`, 'warning');
  };

  const logout = () => {
    setUser(null);
    setCart([]);
  };

  const updateUserBalance = (amount: number) => {
    if(user) {
        const newBalance = user.balance + amount;
        const updatedUser = { ...user, balance: newBalance };
        setUser(updatedUser);
        setUsersList(prev => prev.map(u => u.id === user.id ? updatedUser : u));
        logActivity('Balance Update', `${user.email} balansı ${amount > 0 ? '+' : ''}${amount} AZN dəyişdi.`);
    }
  };

  const toggleWishlist = (productId: string) => {
      if(!user) return;

      const currentWishlist = user.wishlist || [];
      let newWishlist;

      if(currentWishlist.includes(productId)) {
          newWishlist = currentWishlist.filter(id => id !== productId);
      } else {
          newWishlist = [...currentWishlist, productId];
      }

      const updatedUser = { ...user, wishlist: newWishlist };
      setUser(updatedUser);
      setUsersList(prev => prev.map(u => u.id === user.id ? updatedUser : u));
  };

  // --- STOCK LOGIC ---
  const addStock = (productId: string, codes: string[]) => {
      const newStocks = codes.map(code => ({
          id: `stock-${Date.now()}-${Math.random()}`,
          productId,
          code,
          isUsed: false,
          dateAdded: new Date().toISOString()
      }));
      setStocks(prev => [...prev, ...newStocks]);
      logActivity('Stock Added', `${codes.length} ədəd kod əlavə olundu.`);
  };

  const deleteStock = (stockId: string) => {
      setStocks(prev => prev.filter(s => s.id !== stockId));
      logActivity('Stock Deleted', `Stok ID ${stockId} silindi.`, 'warning');
  };

  // --- CART LOGIC ---
  const addToCart = (product: Product, userInput?: string) => {
    const finalPrice = product.price - (product.price * (product.discountPercent / 100));

    setCart(prev => {
        const existingIndex = prev.findIndex(item => item.productId === product.id && item.userInput === userInput);

        if (existingIndex > -1) {
            const newCart = [...prev];
            newCart[existingIndex].quantity += 1;
            return newCart;
        } else {
            return [...prev, {
                productId: product.id,
                title: product.title,
                price: finalPrice,
                image: product.image,
                type: product.type,
                userInput,
                quantity: 1,
                durationDays: product.durationDays
            }];
        }
    });
  };

  const updateCartQuantity = (index: number, delta: number) => {
      setCart(prev => {
          const newCart = [...prev];
          const item = newCart[index];
          const newQty = item.quantity + delta;

          if (newQty <= 0) return prev.filter((_, i) => i !== index);

          item.quantity = newQty;
          return newCart;
      });
  };

  const removeFromCart = (index: number) => {
    setCart(prev => prev.filter((_, i) => i !== index));
  };

  const clearCart = () => setCart([]);

  // --- ORDER LOGIC ---

  const placeOrder = async (paymentMethodId: string | 'BALANCE', receiptFile?: File, promoDiscount: number = 0): Promise<boolean> => {
    if (!user || cart.length === 0) return false;

    const subTotal = cart.reduce((sum, item) => sum + (item.price * item.quantity), 0);
    const totalPrice = subTotal - promoDiscount;

    if (paymentMethodId === 'BALANCE') {
        if (user.balance < totalPrice) {
            alert("Balansınızda kifayət qədər vəsait yoxdur.");
            return false;
        }

        // Deduct balance
        updateUserBalance(-totalPrice);

        // Create order initially
        const orderId = `ord-${Date.now()}`;

        // AUTO-DELIVERY LOGIC FOR BALANCE ORDERS
        let autoDeliveredContent = "";
        let isFullyDelivered = true;

        const updatedStocks = [...stocks];

        // Try to assign stocks
        cart.forEach(item => {
            if (item.type === ProductType.LICENSE_KEY || item.type === ProductType.ACCOUNT) {
                // Find unused stocks for this product
                const available = updatedStocks.filter(s => s.productId === item.productId && !s.isUsed);
                if (available.length >= item.quantity) {
                     // Assign codes
                     for(let i=0; i<item.quantity; i++) {
                         const stock = available[i];
                         stock.isUsed = true;
                         autoDeliveredContent += `${item.title}: ${stock.code}\n`;
                         // Update local ref to prevent double usage in loop
                         const sIndex = updatedStocks.findIndex(s => s.id === stock.id);
                         updatedStocks[sIndex].isUsed = true;
                     }
                } else {
                    isFullyDelivered = false;
                    autoDeliveredContent += `${item.title}: (Stok bitib, Admin göndərəcək)\n`;
                }
            } else {
                 // For ID_LOAD, it's manual
                 isFullyDelivered = false; 
                 autoDeliveredContent += `${item.title}: (Yükləmə Gözlənilir)\n`;
            }
        });

        // Update global stock state
        setStocks(updatedStocks);

        // Determine Final Status: If all items were keys/accounts and stock existed, it's COMPLETED. Else PROCESSING.
        const finalStatus = isFullyDelivered ? OrderStatus.COMPLETED : OrderStatus.PROCESSING;

        const newOrder: Order = {
            id: orderId,
            userId: user.id,
            items: [...cart],
            totalPrice: totalPrice,
            discountApplied: promoDiscount,
            status: finalStatus,
            date: new Date().toISOString(),
            paymentMethodName: 'Wallet Balance',
            expiryDate: undefined, // Calculated below if needed
            deliveredContent: autoDeliveredContent,
            productTitle: cart.length > 1 ? `${cart.length} Məhsul` : cart[0].title,
            productId: 'cart-checkout',
            price: totalPrice,
            productType: ProductType.LICENSE_KEY
        };

        setOrders(prev => [newOrder, ...prev]);
        clearCart();
        sendNotification(user.id, "Sifariş Qəbul Edildi", `Sifarişiniz (#${newOrder.id.slice(-6)}) ${isFullyDelivered ? 'tamamlandı' : 'emal olunur'}.`, 'success');
        logActivity('Order Placed', `Order #${orderId} (Balance) - ${totalPrice} AZN`);
        return true;
    }

    // Manual Payment
    const method = paymentMethods.find(p => p.id === paymentMethodId);
    if (!method || !receiptFile) return false;

    const receiptUrl = URL.createObjectURL(receiptFile);

    const newOrder: Order = {
      id: `ord-${Date.now()}`,
      userId: user.id,
      items: [...cart],
      totalPrice: totalPrice,
      discountApplied: promoDiscount,
      status: OrderStatus.PENDING,
      date: new Date().toISOString(),
      paymentMethodName: method.name,
      receiptImage: receiptUrl,
      productTitle: cart.length > 1 ? `${cart.length} Məhsul` : cart[0].title,
      productId: 'cart-checkout',
      price: totalPrice,
      productType: ProductType.LICENSE_KEY
    };

    setOrders(prev => [newOrder, ...prev]);
    clearCart();
    sendNotification(user.id, "Sifariş Gözləmədə", `Sifarişiniz (#${newOrder.id.slice(-6)}) yoxlanışa göndərildi.`, 'info');
    logActivity('Order Placed', `Order #${newOrder.id} (Manual) - ${totalPrice} AZN`);
    return true;
  };

  const placeBalanceOrder = async (amount: number, paymentMethodId: string, receiptFile: File): Promise<boolean> => {
    if (!user) return false;
    const method = paymentMethods.find(p => p.id === paymentMethodId);
    if (!method) return false;
    const receiptUrl = URL.createObjectURL(receiptFile);

    const newOrder: Order = {
      id: `bal-${Date.now()}`,
      userId: user.id,
      items: [{
        productId: 'balance-topup',
        title: 'Balans Artımı',
        price: amount,
        image: 'https://via.placeholder.com/150',
        type: ProductType.BALANCE,
        quantity: 1
      }],
      totalPrice: amount,
      status: OrderStatus.PENDING,
      date: new Date().toISOString(),
      paymentMethodName: method.name,
      receiptImage: receiptUrl,
      productTitle: 'Balans Artımı',
      productType: ProductType.BALANCE,
      price: amount
    };

    setOrders(prev => [newOrder, ...prev]);
    sendNotification(user.id, "Balans Sorğusu", `${amount} AZN dəyərində balans artım sorğunuz qeydə alındı.`, 'info');
    logActivity('Balance Request', `User ${user.email} ${amount} AZN artım istədi.`);
    return true;
  };

  const processOrder = (orderId: string) => {
    setOrders(prev => prev.map(order => order.id === orderId ? { ...order, status: OrderStatus.PROCESSING } : order));
    const order = orders.find(o => o.id === orderId);
    if(order) sendNotification(order.userId, "Sifariş Emalda", `Sifarişiniz (#${order.id.slice(-6)}) emal olunur.`, 'info');
    logActivity('Order Processing', `Order #${orderId} emala alındı.`);
  };

  const completeOrder = (orderId: string, manualContent?: string) => {
    setOrders(prev => prev.map(order => {
      if (order.id !== orderId) return order;

      let finalContent = manualContent || order.deliveredContent || "";

      // If manual content isn't provided, try to find stock NOW (for manual orders being approved)
      if (!manualContent && !order.items.some(i => i.type === ProductType.BALANCE)) {
           // This logic runs if Admin clicks "Complete" without typing anything, 
           // implying "Auto-assign from stock if available"
           let updatedStocks = [...stocks];
           let autoGenerated = "";

           order.items.forEach(item => {
               if(item.type === ProductType.LICENSE_KEY || item.type === ProductType.ACCOUNT) {
                   const available = updatedStocks.filter(s => s.productId === item.productId && !s.isUsed);
                   if (available.length >= item.quantity) {
                        for(let i=0; i<item.quantity; i++) {
                             const stock = available[i];
                             const sIdx = updatedStocks.findIndex(s=>s.id === stock.id);
                             updatedStocks[sIdx].isUsed = true;
                             autoGenerated += `${item.title}: ${stock.code}\n`;
                        }
                   }
               }
           });

           if (autoGenerated) {
               setStocks(updatedStocks);
               finalContent = autoGenerated;
           }
      }

      sendNotification(order.userId, "Sifariş Tamamlandı!", `Sifarişiniz (#${order.id.slice(-6)}) təsdiqləndi.`, 'success');

      if (order.items.some(i => i.type === ProductType.BALANCE)) {
         updateUserBalance(order.totalPrice);
         sendNotification(order.userId, "Balans Artırıldı", `${order.totalPrice} AZN balansınıza əlavə olundu.`, 'success');
      }

      let expiryDate = order.expiryDate;
      if (!expiryDate && order.items.length === 1 && order.items[0].type === ProductType.ACCOUNT && order.items[0].durationDays) {
         const d = new Date();
         d.setDate(d.getDate() + order.items[0].durationDays);
         expiryDate = d.toISOString();
      }

      logActivity('Order Completed', `Order #${orderId} tamamlandı.`, 'success');

      return { 
        ...order, 
        status: OrderStatus.COMPLETED,
        deliveredContent: finalContent,
        expiryDate: expiryDate
      };
    }));
  };

  const cancelOrder = (orderId: string) => {
    setOrders(prev => prev.map(order => order.id === orderId ? { ...order, status: OrderStatus.CANCELLED } : order));
    const order = orders.find(o => o.id === orderId);
    if(order) {
        sendNotification(order.userId, "Sifariş Ləğv Edildi", `Sifarişiniz (#${order.id.slice(-6)}) ləğv edildi.`, 'error');
        // If money was taken from balance, Refund it? 
        // For simplicity in this prompt, assume manual refund or logic here.
        // If it was Wallet Balance payment, we SHOULD refund.
        if (order.paymentMethodName === 'Wallet Balance') {
            updateUserBalance(order.totalPrice);
            sendNotification(order.userId, "Refund", `${order.totalPrice} AZN balansınıza qaytarıldı.`, 'success');
            logActivity('Order Refunded', `Order #${orderId} məbləği geri qaytarıldı.`);
        }
    }
    logActivity('Order Cancelled', `Order #${orderId} ləğv edildi.`, 'error');
  };

  // --- CMS Actions ---
  const addProduct = (product: Product) => { setProducts(prev => [...prev, product]); logActivity('Product Added', product.title); }
  const addProducts = (newProducts: Product[]) => setProducts(prev => [...prev, ...newProducts]);
  const deleteProduct = (productId: string) => { setProducts(prev => prev.filter(p => p.id !== productId)); logActivity('Product Deleted', productId); }
  const addCategory = (category: Category) => { setCategories(prev => [...prev, category]); logActivity('Category Added', category.name); }
  const deleteCategory = (categoryId: string) => setCategories(prev => prev.filter(c => c.id !== categoryId));
  const updateSiteSettings = (settings: Partial<SiteSettings>) => { setSiteSettings(prev => ({ ...prev, ...settings })); logActivity('Settings Updated', 'Sayt ayarları dəyişdirildi.'); }
  const addPaymentMethod = (method: PaymentMethod) => setPaymentMethods(prev => [...prev, method]);
  const updatePaymentMethod = (id: string, details: Partial<PaymentMethod>) => setPaymentMethods(prev => prev.map(pm => pm.id === id ? { ...pm, ...details } : pm));
  const deletePaymentMethod = (id: string) => setPaymentMethods(prev => prev.filter(pm => pm.id !== id));
  const addPromoCode = (promo: PromoCode) => setPromoCodes(prev => [...prev, promo]);
  const deletePromoCode = (id: string) => setPromoCodes(prev => prev.filter(p => p.id !== id));
  const togglePromoCode = (id: string) => setPromoCodes(prev => prev.map(p => p.id === id ? { ...p, isActive: !p.isActive } : p));
  const addBlog = (blog: Blog) => setBlogs(prev => [...prev, blog]);
  const deleteBlog = (id: string) => setBlogs(prev => prev.filter(b => b.id !== id));
  const addAgreement = (agreement: Agreement) => setAgreements(prev => [...prev, agreement]);
  const deleteAgreement = (id: string) => setAgreements(prev => prev.filter(a => a.id !== id));

  // New: Add Comment
  const addComment = (newCommentData: Omit<Comment, 'id' | 'date' | 'isApproved'>) => {
      const newComment: Comment = {
          id: `cmt-${Date.now()}`,
          ...newCommentData,
          isApproved: true, // Auto-approve for demo satisfaction, usually false in prod
          date: new Date().toISOString()
      };
      setComments(prev => [newComment, ...prev]);
      logActivity('New Comment', `${newCommentData.author} rəy yazdı: ${newComment.rating} ulduz.`);
  };

  const toggleCommentApproval = (id: string) => setComments(prev => prev.map(c => c.id === id ? {...c, isApproved: !c.isApproved} : c));
  const deleteComment = (id: string) => setComments(prev => prev.filter(c => c.id !== id));

  return (
    <AppContext.Provider value={{ 
      user, usersList, isAuthenticated: !!user,
      products, categories, orders, paymentMethods, promoCodes, siteSettings, cart, notifications,
      stocks, activityLogs,
      blogs, agreements, comments,
      login, register, logout, requestPasswordReset, updateUserProfile, adminUpdateUserPassword, toggleUserBan, generateResetLink, confirmPasswordReset, changePassword,
      addToCart, updateCartQuantity, removeFromCart, clearCart,
      placeOrder, placeBalanceOrder, processOrder, completeOrder, cancelOrder, updateUserBalance, markNotificationRead, clearNotifications,
      addPaymentMethod, updatePaymentMethod, deletePaymentMethod, addPromoCode, deletePromoCode, togglePromoCode,
      addProduct, addProducts, deleteProduct, addCategory, deleteCategory, updateSiteSettings,
      addBlog, deleteBlog, addAgreement, deleteAgreement, toggleCommentApproval, deleteComment, addComment,
      addStock, deleteStock, toggleWishlist
    }}>
      {children}
    </AppContext.Provider>
  );
};

export const useApp = () => {
  const context = useContext(AppContext);
  if (!context) throw new Error("useApp must be used within AppProvider");
  return context;
};

import React from 'react';
import { Product, ProductType } from '../types';
import { ShoppingCart, Zap, Key, UserCheck, Heart, Star } from 'lucide-react';
import { Link, useNavigate } from 'react-router-dom';
import { useApp } from '../store';

interface ProductCardProps {
  product: Product;
}

const ProductCard: React.FC<ProductCardProps> = ({ product }) => {
  const { user, toggleWishlist, isAuthenticated, comments } = useApp();
  const navigate = useNavigate();

  const isLiked = user?.wishlist?.includes(product.id);

  // Calculate Rating
  const productComments = comments.filter(c => c.targetId === product.id && c.isApproved && c.rating);
  const avgRating = productComments.length > 0 
      ? productComments.reduce((acc, c) => acc + (c.rating || 0), 0) / productComments.length 
      : 0;

  const getIcon = () => {
    switch (product.type) {
      case ProductType.ID_LOAD: return <Zap className="w-4 h-4 text-yellow-400" />;
      case ProductType.LICENSE_KEY: return <Key className="w-4 h-4 text-blue-400" />;
      case ProductType.ACCOUNT: return <UserCheck className="w-4 h-4 text-green-400" />;
      default: return <ShoppingCart className="w-4 h-4" />;
    }
  };

  const handleWishlist = (e: React.MouseEvent) => {
      e.preventDefault();
      e.stopPropagation();
      if(!isAuthenticated) {
          navigate('/auth');
          return;
      }
      toggleWishlist(product.id);
  };

  return (
    <div className="bg-gaming-card rounded-xl overflow-hidden border border-gray-800 shadow-lg hover:shadow-gaming-neon/20 hover:border-gaming-neon/50 transition-all duration-300 group relative flex flex-col h-full">
      <div className="relative h-48 overflow-hidden shrink-0">
        <img 
          src={product.image} 
          alt={product.title} 
          className="w-full h-full object-cover transform group-hover:scale-110 transition-transform duration-500"
        />
        <div className="absolute top-2 right-2 bg-black/60 backdrop-blur-sm px-2 py-1 rounded text-xs font-bold text-white border border-white/10 flex items-center gap-1">
          {getIcon()}
          {product.type === ProductType.ID_LOAD ? 'ID LOAD' : product.type === ProductType.LICENSE_KEY ? 'KEY' : 'ACCOUNT'}
        </div>

        {/* Wishlist Button */}
        <button 
            onClick={handleWishlist}
            className={`absolute top-2 left-2 p-2 rounded-full backdrop-blur-md transition-all ${isLiked ? 'bg-red-500/80 text-white' : 'bg-black/40 text-gray-300 hover:text-red-500 hover:bg-black/60'}`}
        >
            <Heart className={`w-4 h-4 ${isLiked ? 'fill-current' : ''}`} />
        </button>

        {/* Rating Badge */}
        {avgRating > 0 && (
             <div className="absolute bottom-2 right-2 bg-black/60 backdrop-blur-sm px-2 py-1 rounded text-xs font-bold text-yellow-400 border border-white/10 flex items-center gap-1">
                 <Star className="w-3 h-3 fill-current" />
                 {avgRating.toFixed(1)}
             </div>
        )}
      </div>

      <div className="p-5 flex flex-col flex-1">
        <h3 className="text-lg font-bold text-white mb-2 line-clamp-1 group-hover:text-gaming-neon transition-colors">{product.title}</h3>
        <p className="text-gray-400 text-sm mb-4 line-clamp-2 min-h-[40px]">{product.description}</p>

        <div className="flex items-center justify-between mt-auto pt-4 border-t border-gray-800">
          <span className="text-xl font-bold text-white">{product.price.toFixed(2)} ₼</span>
          <Link 
            to={`/product/${product.id}`}
            className="px-4 py-2 rounded-lg text-sm font-semibold transition-colors flex items-center gap-2 bg-gaming-accent hover:bg-gaming-accent/80 text-white shadow-lg shadow-purple-900/20"
          >
            Sifariş Et
          </Link>
        </div>
      </div>
    </div>
  );
};

export default ProductCard;

import React, { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
