                                 <div className="w-10 h-10 rounded-full bg-green-500/10 flex items-center justify-center text-green-500"><CheckCircle className="w-5 h-5"/></div>
                                 <div>
                                     <h4 className="font-bold text-white">Ani Təslimat</h4>
