            @keyframes glow-pulse {
                0% { box-shadow: 0 0 10px #06b6d4; }
                50% { box-shadow: 0 0 30px #06b6d4, 0 0 60px #8b5cf6; }
                100% { box-shadow: 0 0 10px #06b6d4; }
            }
            .glow-effect {
                animation: glow-pulse 2s infinite;
            }
        `}</style>

        <div className="max-w-7xl mx-auto">
