  const navigate = useNavigate();
  const location = useLocation();

  // Handle Hash Scroll
  useEffect(() => {
      if (location.hash === '#categories') {
          const el = document.getElementById('categories');
          if (el) el.scrollIntoView({ behavior: 'smooth' });
      }
