  // Auto-play Slideshow
  useEffect(() => {
      const timer = setInterval(() => {
          setCurrentSlide(prev => (prev + 1) % SLIDES.length);
      }, 5000);
      return () => clearInterval(timer);
  }, []);

  const nextSlide = () => setCurrentSlide(prev => (prev + 1) % SLIDES.length);
  const prevSlide = () => setCurrentSlide(prev => (prev - 1 + SLIDES.length) % SLIDES.length);

  // "Popular" filter logic for the home page list
  const filteredProducts = products.filter(p => {
    const matchesCategory = activeCat === 'All' || p.categoryId === activeCat;
    const matchesSearch = p.title.toLowerCase().includes(search.toLowerCase());
    return matchesCategory && matchesSearch;
  });

  const handleCategoryClick = (catId: string) => {
      navigate(`/category/${catId}`);
  };

  return (
    <div className="min-h-screen bg-gaming-dark pb-20">

      {/* 1. DYNAMIC SLIDESHOW (Hero) */}
      <div className="relative w-full h-[450px] md:h-[550px] overflow-hidden group">
         {SLIDES.map((slide, index) => (
             <div 
                key={slide.id}
                className={`absolute inset-0 transition-opacity duration-1000 ease-in-out ${index === currentSlide ? 'opacity-100' : 'opacity-0'}`}
             >
                 <img src={slide.image} className="w-full h-full object-cover" alt={slide.title} />
                 <div className="absolute inset-0 bg-gradient-to-t from-gaming-dark via-black/40 to-transparent" />

                 <div className={`absolute bottom-0 left-0 w-full p-8 md:p-16 flex flex-col items-center justify-center text-center transition-all duration-1000 transform ${index === currentSlide ? 'translate-y-0 opacity-100' : 'translate-y-10 opacity-0'}`}>
                     <h1 className="text-4xl md:text-7xl font-black text-white mb-4 drop-shadow-[0_5px_5px_rgba(0,0,0,0.8)] tracking-tighter uppercase italic">
                         {slide.title}
                     </h1>
                     <p className="text-gray-200 text-lg md:text-2xl max-w-2xl drop-shadow-md bg-black/30 backdrop-blur-sm px-4 py-2 rounded-full border border-white/10">
                         {slide.subtitle}
                     </p>
                 </div>
             </div>
         ))}

         {/* Slider Controls */}
         <button onClick={prevSlide} className="absolute left-4 top-1/2 -translate-y-1/2 bg-black/30 hover:bg-gaming-neon hover:text-black text-white p-2 rounded-full backdrop-blur-md border border-white/10 transition-all opacity-0 group-hover:opacity-100">
             <ChevronLeft className="w-8 h-8" />
         </button>
         <button onClick={nextSlide} className="absolute right-4 top-1/2 -translate-y-1/2 bg-black/30 hover:bg-gaming-neon hover:text-black text-white p-2 rounded-full backdrop-blur-md border border-white/10 transition-all opacity-0 group-hover:opacity-100">
             <ChevronRight className="w-8 h-8" />
         </button>

         {/* Indicators */}
         <div className="absolute bottom-6 left-1/2 -translate-x-1/2 flex gap-2">
             {SLIDES.map((_, idx) => (
                 <button 
                    key={idx} 
                    onClick={() => setCurrentSlide(idx)}
                    className={`h-1.5 rounded-full transition-all duration-300 ${idx === currentSlide ? 'w-8 bg-gaming-neon' : 'w-2 bg-gray-500'}`} 
                 />
             ))}
         </div>
      </div>

      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 -mt-8 relative z-20">

        {/* 2. SEARCH BAR (Integrated) */}
        <div className="bg-gaming-card/90 backdrop-blur-xl border border-gray-700/50 rounded-2xl p-2 shadow-2xl flex items-center max-w-2xl mx-auto mb-16 ring-1 ring-white/10">
            <Search className="ml-4 text-gaming-neon w-6 h-6" />
