              type="text" 
              placeholder="İstədiyiniz məhsulu axtarın..." 
              value={search}
              onChange={(e) => setSearch(e.target.value)}
              className="w-full bg-transparent border-none text-white px-4 py-3 focus:ring-0 outline-none text-lg placeholder-gray-500"
            />
            <button className="bg-gaming-neon text-black font-bold px-6 py-3 rounded-xl hover:bg-cyan-400 transition-colors shadow-lg shadow-cyan-500/20">
                Axtar
            </button>
        </div>

        {/* 3. CATEGORIES AS INTERACTIVE CARDS */}
        <div className="mb-16" id="categories">
            <div className="flex items-center justify-between mb-6">
                <h2 className="text-2xl font-bold text-white border-l-4 border-gaming-neon pl-4">Kateqoriyalar</h2>
            </div>

            <div className="grid grid-cols-2 md:grid-cols-4 gap-6">
                {categories.map(cat => (
                    <div 
                        key={cat.id} 
                        onClick={() => handleCategoryClick(cat.id)}
