                    >
                        {cat.image ? (
                            <img src={cat.image} className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-700" alt={cat.name} />
                        ) : (
                            <div className="w-full h-full bg-slate-800 flex items-center justify-center">
                                <Gamepad className="w-12 h-12 text-gray-500 group-hover:text-white transition-colors" />
                            </div>
                        )}

                        {/* Overlay Gradient */}
                        <div className="absolute inset-0 bg-gradient-to-t from-gaming-dark via-gaming-dark/50 to-transparent opacity-90 group-hover:opacity-70 transition-opacity duration-300"></div>

                        {/* Text Content */}
                        <div className="absolute bottom-0 left-0 w-full p-5">
                            <h3 className="text-xl font-black text-white uppercase tracking-wider italic mb-1 translate-y-2 group-hover:translate-y-0 transition-transform duration-300">
                                {cat.name}
                            </h3>
                            <div className="h-1 w-0 bg-gaming-neon rounded-full group-hover:w-16 transition-all duration-500"></div>
                        </div>

                        {/* Interactive Icon */}
                        <div className="absolute top-4 right-4 bg-gaming-card/50 backdrop-blur-md p-2 rounded-full border border-white/10 opacity-0 group-hover:opacity-100 transform translate-x-4 group-hover:translate-x-0 transition-all duration-300">
                            <ChevronRight className="w-5 h-5 text-gaming-neon" />
                        </div>
                    </div>
                ))}
            </div>
        </div>

        {/* 4. POPULAR PRODUCTS (Tabs) */}
        <div className="mb-16">
            <div className="flex flex-col md:flex-row md:items-center justify-between mb-8 gap-4">
                <h2 className="text-2xl font-bold text-white border-l-4 border-gaming-accent pl-4">Populyar Məhsullar</h2>

                {/* Category Tabs for Home Page Filter */}
                <div className="flex overflow-x-auto space-x-2 pb-2 scrollbar-hide">
                    <button
                        onClick={() => setActiveCat('All')}
                        className={`px-4 py-1.5 rounded-full text-sm font-bold transition-all whitespace-nowrap border border-transparent
                            ${activeCat === 'All' ? 'bg-white text-black shadow-[0_0_15px_rgba(255,255,255,0.3)]' : 'bg-slate-800 text-gray-400 hover:bg-slate-700 border-gray-700'}`}
                    >
                        Hamısı
                    </button>
                    {categories.map(cat => (
                        <button
                            key={cat.id}
                            onClick={() => setActiveCat(cat.id)}
                            className={`px-4 py-1.5 rounded-full text-sm font-bold transition-all whitespace-nowrap border border-transparent
                                ${activeCat === cat.id ? 'bg-white text-black shadow-[0_0_15px_rgba(255,255,255,0.3)]' : 'bg-slate-800 text-gray-400 hover:bg-slate-700 border-gray-700'}`}
                        >
                            {cat.name}
                        </button>
                    ))}
                </div>
            </div>

            {/* Product Grid */}
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6">
                {filteredProducts.map(product => (
                    <ProductCard key={product.id} product={product} />
