        {/* 5. INFO SECTION */}
        <div className="grid grid-cols-1 md:grid-cols-4 gap-6 mb-12">
            {[
                { icon: Zap, title: "Sürətli Çatdırılma", desc: "Sifarişləriniz dərhal emal olunur" },
                { icon: ShieldCheck, title: "100% Güvənli", desc: "Tam təhlükəsiz ödəniş sistemi" },
                { icon: Truck, title: "7/24 Dəstək", desc: "Hər zaman yanınızdayıq" },
                { icon: Percent, title: "Ən Ucuz Qiymət", desc: "Bazarın ən sərfəli qiymətləri" }
            ].map((item, idx) => (
                <div key={idx} className="bg-slate-800/50 p-6 rounded-xl border border-gray-700 text-center hover:border-gaming-neon transition-colors group">
                    <div className="w-12 h-12 bg-gaming-neon/10 rounded-full flex items-center justify-center mx-auto mb-4 group-hover:bg-gaming-neon group-hover:text-black transition-colors text-gaming-neon">
