                                                        'border-red-500 text-red-400'
                                                    }`}>
                                                        {order.status}
                                                    </span>
                                                </div>
                                            </div>
                                            <div className="text-right">
                                                <p className="text-gaming-neon font-bold text-lg">{order.totalPrice.toFixed(2)} ₼</p>
