                    <button onClick={handleLogout} className="flex items-center gap-3 p-3 rounded-xl transition-all font-bold text-red-500 hover:bg-red-500/10">
                        <LogOut className="w-5 h-5"/> Çıxış
                    </button>
                </nav>
            </div>
        </div>

        {/* RIGHT COLUMN: Content */}
